// Already Mine — full affirmation library (2180 entries).
// Loaded asynchronously (<script async>) so the app shell renders without
// parsing ~200KB of data. index.html reads window.AFFIRMATION_LIBRARY and/or
// the window.__affirmationsLoaded callback — the handshake works regardless
// of which script executes first. Do not rename either.
window.AFFIRMATION_LIBRARY = [
  // ABUNDANCE
  {id:"AB001",text:"Everything I need is already flowing gently toward me.",cat:"Abundance"},
  {id:"AB002",text:"I am a magnet for wealth and it comes to me with ease.",cat:"Abundance"},
  {id:"AB003",text:"The universe is abundant and I am open to receive all that is mine.",cat:"Abundance"},
  {id:"AB004",text:"Money flows to me. Opportunities find me. I am ready.",cat:"Abundance"},
  {id:"AB005",text:"Abundance is not something I chase — it is something I embody.",cat:"Abundance"},
  {id:"AB006",text:"I release every belief that money is hard to come by.",cat:"Abundance"},
  {id:"AB007",text:"Financial freedom is my birthright and I claim it today.",cat:"Abundance"},
  {id:"AB008",text:"Every day I am moving closer to the life I have always envisioned.",cat:"Abundance"},
  {id:"AB009",text:"I am worthy of wealth, comfort, and security in every form.",cat:"Abundance"},
  {id:"AB010",text:"Prosperity flows through me and out into every area of my life.",cat:"Abundance"},
  {id:"AB011",text:"I attract opportunities that align with my highest good.",cat:"Abundance"},
  {id:"AB012",text:"The more I give, the more freely abundance returns to me.",cat:"Abundance"},
  // LOVE
  {id:"LV001",text:"I am worthy of deep, gentle, lasting love and it is on its way.",cat:"Love"},
  {id:"LV002",text:"Love is drawn to me because I am whole, alive, and magnetic.",cat:"Love"},
  {id:"LV003",text:"My heart is open. Love recognizes me and finds its way home.",cat:"Love"},
  {id:"LV004",text:"I give and receive love freely. It is enough. I am enough.",cat:"Love"},
  {id:"LV005",text:"I attract relationships that are rooted in respect, depth, and truth.",cat:"Love"},
  {id:"LV006",text:"I release the need to earn love. I am loved simply for existing.",cat:"Love"},
  {id:"LV007",text:"My capacity for love grows deeper with every passing day.",cat:"Love"},
  {id:"LV008",text:"I am deserving of a love that feels like home.",cat:"Love"},
  {id:"LV009",text:"Love surrounds me in every form — in laughter, in kindness, in quiet moments.",cat:"Love"},
  {id:"LV010",text:"I am safe to love and to be loved fully.",cat:"Love"},
  {id:"LV011",text:"The right people are always drawn into my life at the right time.",cat:"Love"},
  // CONFIDENCE
  {id:"CO001",text:"I trust myself gently. My voice matters. My presence is enough.",cat:"Confidence"},
  {id:"CO002",text:"I walk into every room knowing exactly who I am and what I bring.",cat:"Confidence"},
  {id:"CO003",text:"My confidence is rooted in something deeper than approval.",cat:"Confidence"},
  {id:"CO004",text:"I believe in myself. That is where everything begins.",cat:"Confidence"},
  {id:"CO005",text:"I am capable of far more than I have yet allowed myself to believe.",cat:"Confidence"},
  {id:"CO006",text:"I release the need for permission. I give it to myself.",cat:"Confidence"},
  {id:"CO007",text:"My opinion of myself matters more than anyone else's.",cat:"Confidence"},
  {id:"CO008",text:"I speak my truth with clarity and without apology.",cat:"Confidence"},
  {id:"CO009",text:"Every challenge I have faced has made me more capable, not less.",cat:"Confidence"},
  {id:"CO010",text:"I am becoming more comfortable in my own skin every single day.",cat:"Confidence"},
  {id:"CO011",text:"I choose myself — again and again and again.",cat:"Confidence"},
  {id:"CO012",text:"I no longer shrink to make others comfortable.",cat:"Confidence"},
  // HEALTH
  {id:"HT001",text:"My body is healing and growing stronger with every breath I take.",cat:"Health"},
  {id:"HT002",text:"I am powerful, energized, and fully alive in this body.",cat:"Health"},
  {id:"HT003",text:"My body is sacred. I honor it and it honors me in return.",cat:"Health"},
  {id:"HT004",text:"I choose health today. One step, one breath, one choice at a time.",cat:"Health"},
  {id:"HT005",text:"My body knows how to heal. I trust it completely.",cat:"Health"},
  {id:"HT006",text:"I nourish my body with the care it deserves.",cat:"Health"},
  {id:"HT007",text:"Every cell in my body is vibrating with health and vitality.",cat:"Health"},
  {id:"HT008",text:"I listen to my body. It always knows what it needs.",cat:"Health"},
  {id:"HT009",text:"Rest is productive. Recovery is part of the plan.",cat:"Health"},
  {id:"HT010",text:"I am grateful for the strength my body carries me through each day.",cat:"Health"},
  {id:"HT011",text:"My energy is abundant. My body supports my greatest life.",cat:"Health"},
  // PEACE
  {id:"PC001",text:"I release what I cannot control and breathe into the present moment.",cat:"Peace"},
  {id:"PC002",text:"My peace is not dependent on circumstances. It lives inside me.",cat:"Peace"},
  {id:"PC003",text:"Stillness is my natural state. I return to it again and again.",cat:"Peace"},
  {id:"PC004",text:"I am calm. I am steady. This moment is enough.",cat:"Peace"},
  {id:"PC005",text:"I choose peace over perfection every single time.",cat:"Peace"},
  {id:"PC006",text:"The chaos around me does not define the calm within me.",cat:"Peace"},
  {id:"PC007",text:"I breathe in stillness. I breathe out everything that no longer serves me.",cat:"Peace"},
  {id:"PC008",text:"I am at peace with where I am and excited about where I am going.",cat:"Peace"},
  {id:"PC009",text:"My mind is quiet. My heart is open. I am present.",cat:"Peace"},
  {id:"PC010",text:"I do not need to rush. Everything arrives exactly when it should.",cat:"Peace"},
  {id:"PC011",text:"I release the past with love and step into this moment fully.",cat:"Peace"},
  // CAREER
  {id:"CR001",text:"My gifts are valuable. The right opportunities are finding me.",cat:"Career"},
  {id:"CR002",text:"I am built for this. My success is not a matter of if — only when.",cat:"Career"},
  {id:"CR003",text:"I am aligned with my purpose and my work carries that light.",cat:"Career"},
  {id:"CR004",text:"I show up. I do the work. The results take care of themselves.",cat:"Career"},
  {id:"CR005",text:"My career is expanding in ways I have not yet imagined.",cat:"Career"},
  {id:"CR006",text:"I bring something to the table that nobody else can.",cat:"Career"},
  {id:"CR007",text:"Success is not luck — it is the result of who I am becoming.",cat:"Career"},
  {id:"CR008",text:"I am open to being seen, recognized, and rewarded for my work.",cat:"Career"},
  {id:"CR009",text:"The right doors are opening for me right now.",cat:"Career"},
  {id:"CR010",text:"I trust the direction my career is heading even when the path is unclear.",cat:"Career"},
  {id:"CR011",text:"My work is meaningful and my impact is real.",cat:"Career"},
  // HEALING
  {id:"HL001",text:"I give myself permission to heal at my own pace.",cat:"Healing"},
  {id:"HL002",text:"Every day I am releasing what no longer belongs to me.",cat:"Healing"},
  {id:"HL003",text:"I am not my past. I am everything I am choosing to become.",cat:"Healing"},
  {id:"HL004",text:"Healing is not linear and I honor every step of my journey.",cat:"Healing"},
  {id:"HL005",text:"I am worthy of tenderness, especially from myself.",cat:"Healing"},
  {id:"HL006",text:"What hurt me does not define me. My resilience does.",cat:"Healing"},
  {id:"HL007",text:"I am safe now. I can let go of the armor I no longer need.",cat:"Healing"},
  {id:"HL008",text:"I forgive myself for all the times I did not know better.",cat:"Healing"},
  {id:"HL009",text:"My wounds are becoming wisdom. My pain is becoming power.",cat:"Healing"},
  {id:"HL010",text:"I choose to move forward — gently, and with great compassion for myself.",cat:"Healing"},
  // COURAGE
  {id:"CG001",text:"I move through fear because what is waiting on the other side matters more.",cat:"Courage"},
  {id:"CG002",text:"I am braver than I give myself credit for.",cat:"Courage"},
  {id:"CG003",text:"I do not need certainty to take the next step. I just need to begin.",cat:"Courage"},
  {id:"CG004",text:"Discomfort is not a sign to stop. It is a sign I am growing.",cat:"Courage"},
  {id:"CG005",text:"I choose courage over comfort — today and every day.",cat:"Courage"},
  {id:"CG006",text:"The boldest version of me is not far away. She is right here.",cat:"Courage"},
  {id:"CG007",text:"I trust myself enough to leap.",cat:"Courage"},
  {id:"CG008",text:"I have everything I need to face what is in front of me.",cat:"Courage"},
  // NEW BEGINNINGS
  {id:"NB001",text:"Every ending is a door I did not know I needed opened.",cat:"New Beginnings"},
  {id:"NB002",text:"I embrace this new chapter with an open heart and no attachment to the last.",cat:"New Beginnings"},
  {id:"NB003",text:"Starting over is not losing — it is arriving somewhere better.",cat:"New Beginnings"},
  {id:"NB004",text:"My fresh start is a gift I am giving to my future self.",cat:"New Beginnings"},
  {id:"NB005",text:"I do not need to carry the weight of what was into what will be.",cat:"New Beginnings"},
  {id:"NB006",text:"This is my season of becoming.",cat:"New Beginnings"},
  {id:"NB007",text:"I welcome change as the vehicle that carries me toward my greatest life.",cat:"New Beginnings"},
  // FAMILY
  {id:"FM001",text:"I am building a life that the people I love will be proud of.",cat:"Family"},
  {id:"FM002",text:"My family is my anchor and my inspiration.",cat:"Family"},
  {id:"FM003",text:"I show up for the people I love with my whole heart.",cat:"Family"},
  {id:"FM004",text:"The love in my home is a foundation nothing can shake.",cat:"Family"},
  {id:"FM005",text:"I create memories, moments, and a legacy worth leaving.",cat:"Family"},
  // GROWTH
  {id:"GR001",text:"I am exactly where I need to be, and I trust the journey completely.",cat:"Growth"},
  {id:"GR002",text:"The best version of me is not a destination — it is who I am right now, still becoming.",cat:"Growth"},
  // ABUNDANCE (continued)
  {id:"AB013",text:"I am open to receiving more than I have ever allowed myself to imagine.",cat:"Abundance"},
  {id:"AB014",text:"Wealth is a tool, and I am learning to use it with wisdom and grace.",cat:"Abundance"},
  {id:"AB015",text:"I do not compete. I create. My abundance does not diminish anyone else's.",cat:"Abundance"},
  {id:"AB016",text:"Opportunities are attracted to me because I show up with intention every day.",cat:"Abundance"},
  {id:"AB017",text:"I am becoming someone who attracts exactly what they need at exactly the right time.",cat:"Abundance"},
  {id:"AB018",text:"Money is energy and I welcome its flow into every area of my life.",cat:"Abundance"},
  {id:"AB019",text:"I release the story that I am not meant for financial ease.",cat:"Abundance"},
  {id:"AB020",text:"I am worthy of receiving without guilt and giving without depletion.",cat:"Abundance"},
  // LOVE (continued)
  {id:"LV012",text:"I do not chase love. I become the kind of person love cannot help but find.",cat:"Love"},
  {id:"LV013",text:"The love I give myself teaches the world how to love me.",cat:"Love"},
  {id:"LV014",text:"I attract people who reflect the best of who I am becoming.",cat:"Love"},
  {id:"LV015",text:"My relationships are built on honesty, depth, and mutual growth.",cat:"Love"},
  {id:"LV016",text:"I am learning to receive love without flinching.",cat:"Love"},
  {id:"LV017",text:"The people who are meant for me will stay.",cat:"Love"},
  {id:"LV018",text:"I release every relationship that was teaching me what I don't want — it did its job.",cat:"Love"},
  {id:"LV019",text:"Love is not something I earn. It is something I allow.",cat:"Love"},
  // CONFIDENCE (continued)
  {id:"CO013",text:"I am not too much. I am exactly enough for the right places and people.",cat:"Confidence"},
  {id:"CO014",text:"My past does not determine my potential. I decide that.",cat:"Confidence"},
  {id:"CO015",text:"I show up even when I am afraid — that is the whole point.",cat:"Confidence"},
  {id:"CO016",text:"I am becoming someone I would have looked up to.",cat:"Confidence"},
  {id:"CO017",text:"I no longer wait for confidence to arrive before I begin.",cat:"Confidence"},
  {id:"CO018",text:"Every time I do the hard thing, I become harder to stop.",cat:"Confidence"},
  {id:"CO019",text:"I trust my instincts. They have never truly led me wrong.",cat:"Confidence"},
  {id:"CO020",text:"I am allowed to take up space in every room I enter.",cat:"Confidence"},
  // HEALTH (continued)
  {id:"HT012",text:"I am not punishing my body. I am partnering with it.",cat:"Health"},
  {id:"HT013",text:"Every small act of care I give my body is an act of self-respect.",cat:"Health"},
  {id:"HT014",text:"My body carries me through every beautiful moment of this life. I am grateful.",cat:"Health"},
  {id:"HT015",text:"I release the need to look a certain way and embrace how good I feel.",cat:"Health"},
  {id:"HT016",text:"I am building foundations that will carry me into the life I am calling in.",cat:"Health"},
  {id:"HT017",text:"Sleep, water, movement, stillness — I give my body what it asks for.",cat:"Health"},
  {id:"HT018",text:"My health is the foundation everything else is built on. I protect it.",cat:"Health"},
  {id:"HT019",text:"I am not behind. I am beginning exactly when I was meant to.",cat:"Health"},
  // PEACE (continued)
  {id:"PC012",text:"I am not responsible for other people's storms. I tend to my own sky.",cat:"Peace"},
  {id:"PC013",text:"Silence is not emptiness. It is where I hear myself most clearly.",cat:"Peace"},
  {id:"PC014",text:"I give myself permission to slow down without calling it failure.",cat:"Peace"},
  {id:"PC015",text:"The present moment is the only place my life actually happens.",cat:"Peace"},
  {id:"PC016",text:"I am learning to sit with uncertainty without being swallowed by it.",cat:"Peace"},
  {id:"PC017",text:"My nervous system is allowed to rest. I am safe.",cat:"Peace"},
  {id:"PC018",text:"I release the need to have everything figured out before I can feel okay.",cat:"Peace"},
  {id:"PC019",text:"Peace is not the absence of problems. It is the presence of perspective.",cat:"Peace"},
  // CAREER (continued)
  {id:"CR012",text:"I am not waiting to be discovered. I am making myself undeniable.",cat:"Career"},
  {id:"CR013",text:"The work I do matters even when no one is watching.",cat:"Career"},
  {id:"CR014",text:"I am building something that will outlast my doubt.",cat:"Career"},
  {id:"CR015",text:"Every skill I develop is an investment that compounds over time.",cat:"Career"},
  {id:"CR016",text:"I release perfectionism and embrace progress. Done is better than perfect.",cat:"Career"},
  {id:"CR017",text:"I am exactly the person this moment has been preparing.",cat:"Career"},
  {id:"CR018",text:"My consistency is my competitive advantage.",cat:"Career"},
  {id:"CR019",text:"The path is being laid down as I walk it. I trust the direction.",cat:"Career"},
  // HEALING (continued)
  {id:"HL011",text:"I am not broken. I am in the process of becoming whole.",cat:"Healing"},
  {id:"HL012",text:"Crying is not weakness. It is the body releasing what the mind has been carrying.",cat:"Healing"},
  {id:"HL013",text:"I allow myself to grieve without attaching a timeline to it.",cat:"Healing"},
  {id:"HL014",text:"The version of me who needed that pain to grow is grateful. The new me is free.",cat:"Healing"},
  {id:"HL015",text:"I am no longer available for the same lessons dressed in different circumstances.",cat:"Healing"},
  {id:"HL016",text:"My healing does not have to be pretty to be real.",cat:"Healing"},
  {id:"HL017",text:"I chose to stay and I am proud of myself for that every single day.",cat:"Healing"},
  {id:"HL018",text:"Something in me always knew I would make it here.",cat:"Healing"},
  // COURAGE (continued)
  {id:"CG009",text:"The life I want is on the other side of the conversation I keep avoiding.",cat:"Courage"},
  {id:"CG010",text:"I am not waiting for the fear to go away. I am learning to walk with it.",cat:"Courage"},
  {id:"CG011",text:"Courage is a decision I make before I feel ready.",cat:"Courage"},
  {id:"CG012",text:"I have already survived things I thought would break me. I can do this too.",cat:"Courage"},
  {id:"CG013",text:"The risk of staying the same is greater than the risk of change.",cat:"Courage"},
  {id:"CG014",text:"I give myself permission to try and fail and try again.",cat:"Courage"},
  {id:"CG015",text:"Something extraordinary is waiting for me just beyond my comfort zone.",cat:"Courage"},
  {id:"CG016",text:"I am not too late. I am right on time for the life I am choosing now.",cat:"Courage"},
  // NEW BEGINNINGS (continued)
  {id:"NB008",text:"I release the old version of my life with love and step into the new with expectation.",cat:"New Beginnings"},
  {id:"NB009",text:"Not knowing what comes next is terrifying and also the most exciting thing imaginable.",cat:"New Beginnings"},
  {id:"NB010",text:"I am planting seeds today that my future self will harvest.",cat:"New Beginnings"},
  {id:"NB011",text:"The blank page is not intimidating. It is an invitation.",cat:"New Beginnings"},
  {id:"NB012",text:"Everything I release is making room for something more aligned.",cat:"New Beginnings"},
  {id:"NB013",text:"I do not need to have a plan. I need to have a direction.",cat:"New Beginnings"},
  {id:"NB014",text:"Every morning is a small new beginning. I take it one morning at a time.",cat:"New Beginnings"},
  {id:"NB015",text:"The hardest part of starting is starting. I have already done the hardest part.",cat:"New Beginnings"},
  // FAMILY (continued)
  {id:"FM006",text:"I am breaking cycles that were never meant to reach the next generation.",cat:"Family"},
  {id:"FM007",text:"The love I give my family comes back to me in ways I cannot always see.",cat:"Family"},
  {id:"FM008",text:"I am present for the ordinary moments because those become the extraordinary memories.",cat:"Family"},
  {id:"FM009",text:"My home is a sanctuary I am intentionally building.",cat:"Family"},
  {id:"FM010",text:"I parent myself with the patience I wish I had always been given.",cat:"Family"},
  // GROWTH (continued)
  {id:"GR003",text:"I am not the same person I was a year ago and that is everything.",cat:"Growth"},
  {id:"GR004",text:"Growth is uncomfortable and I welcome the discomfort as proof I am changing.",cat:"Growth"},
  {id:"GR005",text:"I celebrate small wins because they are the foundation of big ones.",cat:"Growth"},
  {id:"GR006",text:"I learn from every outcome — the good ones and especially the hard ones.",cat:"Growth"},
  {id:"GR007",text:"The person I am becoming is worth every uncomfortable step it takes to get there.",cat:"Growth"},
  {id:"GR008",text:"I am curious about my limitations because that is where my growth lives.",cat:"Growth"},
  {id:"GR009",text:"Every version of me has been doing their best. I honor all of them.",cat:"Growth"},
  {id:"GR010",text:"I am not competing with anyone but the person I was yesterday.",cat:"Growth"},
  {id:"GR011",text:"My story is not finished. The best chapters are still being written.",cat:"Growth"},
  {id:"GR012",text:"I invest in myself because I am the best investment there is.",cat:"Growth"},
  {id:"GR013",text:"Progress over perfection — always and in everything.",cat:"Growth"},
  {id:"GR014",text:"I give myself grace on the hard days because showing up imperfectly still counts.",cat:"Growth"},
  {id:"GR015",text:"I am worthy of the dreams that keep finding their way back to me.",cat:"Growth"},
  {id:"GR016",text:"Something in the universe is conspiring in my favor right now.",cat:"Growth"},
  {id:"GR017",text:"I am not who I was. I am who I am choosing to become.",cat:"Growth"},
  {id:"GR018",text:"My potential is not a fixed thing. It expands every time I choose to show up.",cat:"Growth"},
  {id:"GR019",text:"The life I am building is worth every moment of discomfort it requires.",cat:"Growth"},
  {id:"GR020",text:"I release comparison. My path was never meant to look like someone else's.",cat:"Growth"},
  {id:"GR021",text:"I am becoming more myself every single day.",cat:"Growth"},
  {id:"GR022",text:"The universe rewards consistency. I show up again.",cat:"Growth"},
  {id:"GR023",text:"I trust the process even when I cannot see the progress.",cat:"Growth"},
  {id:"GR024",text:"My dream is valid. My timing is perfect. My effort is enough.",cat:"Growth"},
  {id:"GR025",text:"I am already everything I need to be. I am also still becoming more.",cat:"Growth"},
  // FAMILY (continued)
  {id:"FM011",text:"I parent with intention, not with fear.",cat:"Family"},
  {id:"FM012",text:"The cycle stops with me — and that is one of the most powerful things I will ever do.",cat:"Family"},
  {id:"FM013",text:"I am building a home where love is louder than fear.",cat:"Family"},
  {id:"FM014",text:"I show up imperfectly and I show up anyway — that is enough.",cat:"Family"},
  {id:"FM015",text:"My presence is the gift my family needs most.",cat:"Family"},
  {id:"FM016",text:"I am healing so the people I love inherit wholeness instead of wounds.",cat:"Family"},
  {id:"FM017",text:"The safety I create in my home is a legacy in itself.",cat:"Family"},
  {id:"FM018",text:"I choose the people who choose me back — and I call that family.",cat:"Family"},
  {id:"FM019",text:"I am not my parents' patterns. I am my own conscious choices.",cat:"Family"},
  {id:"FM020",text:"Every small moment of connection is a thread in something that lasts.",cat:"Family"},
  {id:"FM021",text:"I give my children what I needed — and what I never had.",cat:"Family"},
  {id:"FM022",text:"My home reflects the peace I have worked to build inside myself.",cat:"Family"},
  {id:"FM023",text:"I repair when I get it wrong. That is what love in practice looks like.",cat:"Family"},
  {id:"FM024",text:"The love I offer my family is rooted in who I am, not what I am afraid of.",cat:"Family"},
  {id:"FM025",text:"I belong to people who see me — and I let myself be seen.",cat:"Family"},
  {id:"FM026",text:"I am learning to receive love as easily as I give it.",cat:"Family"},
  {id:"FM027",text:"My family feels safe because I have made safety something I carry.",cat:"Family"},
  {id:"FM028",text:"I do not have to be perfect to be a deeply good parent.",cat:"Family"},
  {id:"FM029",text:"The wounds I am healing today will not be passed to the next generation.",cat:"Family"},
  {id:"FM030",text:"I create rituals that hold my family together — small ones, repeated with love.",cat:"Family"},
  {id:"FM031",text:"Blood does not define my family. Commitment and love do.",cat:"Family"},
  {id:"FM032",text:"I speak to my children the way I wish someone had spoken to me.",cat:"Family"},
  {id:"FM033",text:"I am present in the ordinary Tuesday — because that is where family is actually built.",cat:"Family"},
  {id:"FM034",text:"I am allowed to grieve the family I did not have while building the one I deserve.",cat:"Family"},
  {id:"FM035",text:"My love is steady. My children know they can count on it.",cat:"Family"},
  {id:"FM036",text:"I set boundaries with family because I want relationship, not resentment.",cat:"Family"},
  {id:"FM037",text:"The legacy I leave is written in how I made people feel at home.",cat:"Family"},
  {id:"FM038",text:"I am breaking old patterns with patience, awareness, and a willingness to change.",cat:"Family"},
  {id:"FM039",text:"My home holds both joy and hard conversations — because that is what real love holds.",cat:"Family"},
  {id:"FM040",text:"I am the person in my family's story who chose differently.",cat:"Family"},
  // NEW BEGINNINGS (continued)
  {id:"NB016",text:"I am allowed to begin again. There is no limit on how many times I get to start.",cat:"New Beginnings"},
  {id:"NB017",text:"The life I am leaving behind taught me everything I needed to build this one.",cat:"New Beginnings"},
  {id:"NB018",text:"Courage is not the absence of fear about starting over. It is starting over anyway.",cat:"New Beginnings"},
  {id:"NB019",text:"I am not behind. I am exactly where my story requires me to be.",cat:"New Beginnings"},
  {id:"NB020",text:"The unknown is not my enemy. It is the only place where something new can happen.",cat:"New Beginnings"},
  {id:"NB021",text:"I let go of who I was in that chapter. This chapter needs a different version of me.",cat:"New Beginnings"},
  {id:"NB022",text:"It is not too late. It was never too late. That was always a story I could choose to stop telling.",cat:"New Beginnings"},
  {id:"NB023",text:"Starting over after loss is one of the bravest things a person can do. I am doing it.",cat:"New Beginnings"},
  {id:"NB024",text:"My past does not get a vote on what my future looks like.",cat:"New Beginnings"},
  {id:"NB025",text:"I do not need everything figured out before I begin. Beginning is how I figure it out.",cat:"New Beginnings"},
  {id:"NB026",text:"Change did not break me. It cleared the path.",cat:"New Beginnings"},
  {id:"NB027",text:"There is something being built in me right now that I cannot see yet. I trust it.",cat:"New Beginnings"},
  {id:"NB028",text:"I am stepping into unfamiliar territory and I am bringing myself with me. That is enough.",cat:"New Beginnings"},
  {id:"NB029",text:"What I am leaving behind no longer fits the person I am becoming. That is not loss. That is growth.",cat:"New Beginnings"},
  {id:"NB030",text:"Age is not a reason to stop beginning. It is proof I have survived enough to try again.",cat:"New Beginnings"},
  {id:"NB031",text:"I have rebuilt before. I know how this goes. I know I come out on the other side.",cat:"New Beginnings"},
  {id:"NB032",text:"This new chapter does not erase the old ones. It completes them.",cat:"New Beginnings"},
  {id:"NB033",text:"I give myself permission to be a beginner at this. Beginners are brave by definition.",cat:"New Beginnings"},
  {id:"NB034",text:"The door closed. I am not standing in front of it anymore. I am walking.",cat:"New Beginnings"},
  {id:"NB035",text:"Failure brought me here. I have no reason to be ashamed of where here is.",cat:"New Beginnings"},
  {id:"NB036",text:"I trust this new direction even before I can see where it leads.",cat:"New Beginnings"},
  {id:"NB037",text:"I am not running from my old life. I am walking deliberately toward a new one.",cat:"New Beginnings"},
  {id:"NB038",text:"Every fresh start I have ever taken has made me more myself, not less.",cat:"New Beginnings"},
  {id:"NB039",text:"This is the moment I will look back on as the one where everything changed.",cat:"New Beginnings"},
  {id:"NB040",text:"I release what no longer serves me without guilt. Letting go is an act of self-respect.",cat:"New Beginnings"},
  {id:"NB041",text:"I do not need permission from my past to move forward.",cat:"New Beginnings"},
  {id:"NB042",text:"Something in me knew this change was coming before my mind caught up. I trust that knowing.",cat:"New Beginnings"},
  {id:"NB043",text:"The person I was before this was not a failure. They were preparation.",cat:"New Beginnings"},
  {id:"NB044",text:"I am at the beginning and beginnings are full of possibility.",cat:"New Beginnings"},
  {id:"NB045",text:"I choose the new life. Not because the old one was bad, but because I am still growing.",cat:"New Beginnings"},
  // COURAGE (continued)
  {id:"CG017",text:"I do the scary thing anyway. That is what courage has always looked like for me.",cat:"Courage"},
  {id:"CG018",text:"I speak up even when my voice shakes. Especially when my voice shakes.",cat:"Courage"},
  {id:"CG019",text:"Fear does not get to make my decisions. I do.",cat:"Courage"},
  {id:"CG020",text:"I take the leap before I feel ready because ready is not a place I arrive at by waiting.",cat:"Courage"},
  {id:"CG021",text:"I am capable of hard conversations. I do not have to shrink to keep the peace.",cat:"Courage"},
  {id:"CG022",text:"Boldness is not the absence of doubt. It is moving forward in spite of it.",cat:"Courage"},
  {id:"CG023",text:"I trust myself in the moments when nothing is certain. Especially in those moments.",cat:"Courage"},
  {id:"CG024",text:"Courage is not a feeling I wait for. It is a choice I make before the feeling arrives.",cat:"Courage"},
  {id:"CG025",text:"I say the true thing even when the easier thing is available.",cat:"Courage"},
  {id:"CG026",text:"The version of me who plays it safe has kept me small for long enough.",cat:"Courage"},
  {id:"CG027",text:"I face what is hard because avoiding it costs more than confronting it.",cat:"Courage"},
  {id:"CG028",text:"I am not a person who backs down from the life I know I deserve.",cat:"Courage"},
  {id:"CG029",text:"The hard conversation is not the end of the relationship. It is the beginning of an honest one.",cat:"Courage"},
  {id:"CG030",text:"I have looked fear in the face before. I know how to do this.",cat:"Courage"},
  {id:"CG031",text:"Taking up space is not arrogance. It is courage. I take up my space.",cat:"Courage"},
  {id:"CG032",text:"I choose boldness today even if I choose comfort again tomorrow. Today is enough.",cat:"Courage"},
  {id:"CG033",text:"I do not need anyone's permission to act on what I know is right.",cat:"Courage"},
  {id:"CG034",text:"The moment I almost talked myself out of it is often the moment I most need to do it.",cat:"Courage"},
  {id:"CG035",text:"I am practicing courage the same way I practice anything — imperfectly and repeatedly.",cat:"Courage"},
  {id:"CG036",text:"I stop waiting for someone else to go first.",cat:"Courage"},
  {id:"CG037",text:"My instincts are trustworthy. I act on them.",cat:"Courage"},
  {id:"CG038",text:"I am willing to be misunderstood in the pursuit of something true.",cat:"Courage"},
  {id:"CG039",text:"The discomfort I feel right now is just evidence that I am doing something that matters.",cat:"Courage"},
  {id:"CG040",text:"I do not need to feel brave to be brave. The action is the bravery.",cat:"Courage"},
  {id:"CG041",text:"I have earned the right to ask for what I want.",cat:"Courage"},
  {id:"CG042",text:"I walk into uncertainty without needing a guarantee on the other side.",cat:"Courage"},
  {id:"CG043",text:"Choosing myself when it is costly is one of the most courageous things I can do.",cat:"Courage"},
  {id:"CG044",text:"I do not let the size of the risk convince me to abandon the size of the dream.",cat:"Courage"},
  {id:"CG045",text:"Every time I act with courage it becomes a little more natural. I am building this.",cat:"Courage"},
  {id:"CG046",text:"I am not too much. I am not too loud. I am exactly as bold as this moment requires.",cat:"Courage"},
  // HEALING (continued)
  {id:"HL019",text:"I am allowed to grieve what I lost even if no one else understands why it mattered.",cat:"Healing"},
  {id:"HL020",text:"Healing from betrayal does not mean pretending it did not happen. It means reclaiming myself anyway.",cat:"Healing"},
  {id:"HL021",text:"I release the shame that was never mine to carry.",cat:"Healing"},
  {id:"HL022",text:"My body is doing its best. I meet it with patience, not frustration.",cat:"Healing"},
  {id:"HL023",text:"I forgive myself for surviving in ways I am not proud of. I was doing what I knew how to do.",cat:"Healing"},
  {id:"HL024",text:"The exhaustion I feel is real. Rest is not a reward. It is part of my recovery.",cat:"Healing"},
  {id:"HL025",text:"I am rebuilding trust with myself one kept promise at a time.",cat:"Healing"},
  {id:"HL026",text:"Going backwards some days does not undo the healing. It is part of it.",cat:"Healing"},
  {id:"HL027",text:"I hold the younger version of me with kindness. She needed more than she got, and I know that now.",cat:"Healing"},
  {id:"HL028",text:"What happened to me was not a reflection of my worth. It never was.",cat:"Healing"},
  {id:"HL029",text:"I let the grief move through me without making it a permanent address.",cat:"Healing"},
  {id:"HL030",text:"Burnout taught me where I had abandoned myself. I am going back for those parts.",cat:"Healing"},
  {id:"HL031",text:"I do not have to forgive quickly. I have to heal honestly.",cat:"Healing"},
  {id:"HL032",text:"The pain had something to teach me. I have learned it. I am ready to put it down.",cat:"Healing"},
  {id:"HL033",text:"I am gentle with myself on the hard days. Especially on the hard days.",cat:"Healing"},
  {id:"HL034",text:"My nervous system is learning that it is safe to settle. I give it time.",cat:"Healing"},
  {id:"HL035",text:"I do not have to minimize what I went through to make other people comfortable.",cat:"Healing"},
  {id:"HL036",text:"The meaning I make from my pain is mine to choose. I choose meaning that frees me.",cat:"Healing"},
  {id:"HL037",text:"I stop apologizing for needing time. Healing is not something I can rush.",cat:"Healing"},
  {id:"HL038",text:"Something in me refused to stop. I honor that part of me today.",cat:"Healing"},
  {id:"HL039",text:"I am learning to trust myself again. It is slow and it is real.",cat:"Healing"},
  {id:"HL040",text:"My tears are not a setback. They are proof that I am finally letting myself feel.",cat:"Healing"},
  {id:"HL041",text:"I do not need to carry anger forever to prove that what happened mattered.",cat:"Healing"},
  {id:"HL042",text:"The shame I inherited was not created by me. I return it now. It was never mine.",cat:"Healing"},
  {id:"HL043",text:"Healing does not erase the scar. It makes me someone who survived something real.",cat:"Healing"},
  {id:"HL044",text:"I give myself the compassion I would give anyone I loved who was going through this.",cat:"Healing"},
  {id:"HL045",text:"My capacity to feel this deeply is the same capacity that will let me feel joy deeply.",cat:"Healing"},
  {id:"HL046",text:"I am not stuck. I am processing. There is a difference and I know it.",cat:"Healing"},
  {id:"HL047",text:"I no longer punish myself for the past. That chapter is closed. I am the author now.",cat:"Healing"},
  {id:"HL048",text:"I came through something hard and I am still here. That is not nothing. That is everything.",cat:"Healing"},
  // CAREER (continued)
  {id:"CR020",text:"I ask for the raise. I have earned it and I am done waiting for someone to notice.",cat:"Career"},
  {id:"CR021",text:"I am building something of my own and I refuse to apologize for the ambition it takes.",cat:"Career"},
  {id:"CR022",text:"My expertise is real. I stop downplaying what took me years to learn.",cat:"Career"},
  {id:"CR023",text:"Pivoting is not failing. It is having the intelligence to choose a better direction.",cat:"Career"},
  {id:"CR024",text:"I am allowed to take up space in professional rooms. I belong in every room I enter.",cat:"Career"},
  {id:"CR025",text:"The work I create has value. I charge accordingly.",cat:"Career"},
  {id:"CR026",text:"I do not shrink my ideas to make others comfortable with my potential.",cat:"Career"},
  {id:"CR027",text:"I am building something that does not exist yet. That is not reckless. That is vision.",cat:"Career"},
  {id:"CR028",text:"I trust the direction I am heading even when I cannot yet see the destination.",cat:"Career"},
  {id:"CR029",text:"My creative work is real work. It deserves real investment and real recognition.",cat:"Career"},
  {id:"CR030",text:"I stop waiting for permission to lead. I step forward.",cat:"Career"},
  {id:"CR031",text:"The uncertainty I feel is not a sign to stop. It is the feeling of growth in motion.",cat:"Career"},
  {id:"CR032",text:"I bring my full self to my work. That is not a liability. It is my edge.",cat:"Career"},
  {id:"CR033",text:"I am not starting over. I am taking everything I know into something new.",cat:"Career"},
  {id:"CR034",text:"My name and my work are becoming synonymous with quality.",cat:"Career"},
  {id:"CR035",text:"I have something to say and I say it clearly, in rooms large and small.",cat:"Career"},
  {id:"CR036",text:"The business I am building is a direct extension of what I believe is possible.",cat:"Career"},
  {id:"CR037",text:"I no longer work for approval. I work with purpose.",cat:"Career"},
  {id:"CR038",text:"I am good at this. I let myself know that without needing someone else to confirm it.",cat:"Career"},
  {id:"CR039",text:"The career I want is being built one decision at a time. I make the next one.",cat:"Career"},
  {id:"CR040",text:"I do work that matters to me and that mattering is what makes it excellent.",cat:"Career"},
  {id:"CR041",text:"Entrepreneurship is hard and I am exactly the kind of person who does hard things.",cat:"Career"},
  {id:"CR042",text:"I am visible. My contributions are seen, credited, and valued.",cat:"Career"},
  {id:"CR043",text:"I negotiate for what I am worth without apology and without backing down.",cat:"Career"},
  {id:"CR044",text:"The skills I have today are enough to take the next step. The rest I will learn on the way.",cat:"Career"},
  {id:"CR045",text:"I do not need to have it all figured out to move forward with confidence.",cat:"Career"},
  {id:"CR046",text:"My career does not have to look like anyone else's to be successful.",cat:"Career"},
  {id:"CR047",text:"I am creating a body of work I am proud of.",cat:"Career"},
  {id:"CR048",text:"Purpose-driven work is not a luxury. It is what I am here to do.",cat:"Career"},
  {id:"CR049",text:"I trust myself to figure it out. I always have and this time is no different.",cat:"Career"},
  // HEALTH (continued)
  {id:"HT020",text:"I love my body as it is today while I tend to where it is going.",cat:"Health"},
  {id:"HT021",text:"Movement is something I do for myself, not something I do to myself.",cat:"Health"},
  {id:"HT022",text:"I eat to nourish my body and I release the guilt that used to come with every meal.",cat:"Health"},
  {id:"HT023",text:"My mental health is health. I take care of it without apology.",cat:"Health"},
  {id:"HT024",text:"I listen when my body asks me to slow down. Slowing down is not giving up.",cat:"Health"},
  {id:"HT025",text:"I am breaking cycles that were never mine to inherit. My body deserves better.",cat:"Health"},
  {id:"HT026",text:"Small consistent choices are reshaping me in ways I can already feel.",cat:"Health"},
  {id:"HT027",text:"Sobriety is a gift I keep choosing for myself. I am clear, present, and free.",cat:"Health"},
  {id:"HT028",text:"I am aging with strength, intention, and deep gratitude for every year.",cat:"Health"},
  {id:"HT029",text:"Sleep is not laziness. It is the most important work my body does. I protect it.",cat:"Health"},
  {id:"HT030",text:"What I think about my body matters. I choose thoughts that support it.",cat:"Health"},
  {id:"HT031",text:"I do not need a perfect routine. I need a forgiving one I can keep coming back to.",cat:"Health"},
  {id:"HT032",text:"My body is not my enemy. It is the most faithful companion I have ever had.",cat:"Health"},
  {id:"HT033",text:"I release the old relationship I had with food and begin a new one built on kindness.",cat:"Health"},
  {id:"HT034",text:"Recovery is not weakness. It is the smartest thing I can do for the long game.",cat:"Health"},
  {id:"HT035",text:"My body responds to love. I give it love in the form of rest, water, and attention.",cat:"Health"},
  {id:"HT036",text:"I do not chase perfection in my health habits. I chase consistency.",cat:"Health"},
  {id:"HT037",text:"The way I feel in my body is more important than the way I look in it.",cat:"Health"},
  {id:"HT038",text:"I am building habits today that my older self will thank me for.",cat:"Health"},
  {id:"HT039",text:"My mind and body work together. When I care for one, I care for both.",cat:"Health"},
  {id:"HT040",text:"I no longer use my body as a place to store stress. I release it instead.",cat:"Health"},
  {id:"HT041",text:"Stillness is productive. My nervous system needs quiet and I give it that.",cat:"Health"},
  {id:"HT042",text:"I make choices that reflect how much I value being alive and well.",cat:"Health"},
  {id:"HT043",text:"My body has survived a lot. I meet that history with gentleness, not judgment.",cat:"Health"},
  {id:"HT044",text:"I am not starting a new chapter in my health to punish myself. I am starting one to free myself.",cat:"Health"},
  {id:"HT045",text:"I drink water. I breathe. I step outside. The smallest acts of care add up.",cat:"Health"},
  {id:"HT046",text:"I trust that showing up imperfectly is still showing up. That always counts.",cat:"Health"},
  {id:"HT047",text:"The strength I am building is not just physical. It runs all the way through me.",cat:"Health"},
  {id:"HT048",text:"I choose clarity. I choose presence. I choose the version of my life where I feel good.",cat:"Health"},
  {id:"HT049",text:"My body is on my side. I act like I believe that.",cat:"Health"},
  // LOVE (continued)
  {id:"LV020",text:"Self-love is not something I earn when I improve. It is where I begin.",cat:"Love"},
  {id:"LV021",text:"I have standards and I hold them even when holding them feels lonely.",cat:"Love"},
  {id:"LV022",text:"I am healing the parts of me that confused intensity for love. I know the difference now.",cat:"Love"},
  {id:"LV023",text:"I love fully and I remain fully myself. Those two things are not in conflict.",cat:"Love"},
  {id:"LV024",text:"I am attracting love by being exactly who I am, not a version of who I think I should be.",cat:"Love"},
  {id:"LV025",text:"I let love in. Even now. Even after everything.",cat:"Love"},
  {id:"LV026",text:"The friendships in my life are deep, chosen, and built to last.",cat:"Love"},
  {id:"LV027",text:"I love the people I love through difficulty without losing the thread back to myself.",cat:"Love"},
  {id:"LV028",text:"I know my worth in relationships. I do not negotiate it.",cat:"Love"},
  {id:"LV029",text:"Love and need are different things. I am learning to want from fullness, not from fear.",cat:"Love"},
  {id:"LV030",text:"My attachment wounds are healing. I am capable of secure and steady love.",cat:"Love"},
  {id:"LV031",text:"I bring my whole self into my relationships and I find that is exactly what the right people want.",cat:"Love"},
  {id:"LV032",text:"I do not shrink myself to fit into a love that was not built for who I actually am.",cat:"Love"},
  {id:"LV033",text:"The love I have been looking for has been practicing finding me too.",cat:"Love"},
  {id:"LV034",text:"I am a good friend. I show up, I remember, I stay.",cat:"Love"},
  {id:"LV035",text:"I release the fear that loving someone means eventually losing them.",cat:"Love"},
  {id:"LV036",text:"A healthy relationship does not require me to disappear into it. It asks me to arrive fully.",cat:"Love"},
  {id:"LV037",text:"I communicate what I need. That is not neediness. That is intimacy.",cat:"Love"},
  {id:"LV038",text:"I have been hurt before and I chose to stay open. That is one of the bravest things about me.",cat:"Love"},
  {id:"LV039",text:"The love I give without expectation comes back to me in ways I could not have planned.",cat:"Love"},
  {id:"LV040",text:"I do not beg for what should be freely given.",cat:"Love"},
  {id:"LV041",text:"I am building a relationship with myself that I am proud to bring another person into.",cat:"Love"},
  {id:"LV042",text:"Real connection requires me to be seen. I let myself be seen.",cat:"Love"},
  {id:"LV043",text:"I choose people who choose me back, clearly and consistently.",cat:"Love"},
  {id:"LV044",text:"My past relationships were not failures. They were data. I have learned from all of them.",cat:"Love"},
  {id:"LV045",text:"The love I have for the people in my life is one of my greatest strengths.",cat:"Love"},
  {id:"LV046",text:"I release anxious love and I practice trusting the people who have earned my trust.",cat:"Love"},
  {id:"LV047",text:"I am not too much for the right person. I am exactly enough.",cat:"Love"},
  {id:"LV048",text:"Love in my life looks like safety, laughter, honesty, and showing up. That is what I build toward.",cat:"Love"},
  {id:"LV049",text:"I love generously and I receive love with the same open hands.",cat:"Love"},
  // PEACE (continued)
  {id:"PC020",text:"I release the need to control what I was never meant to carry.",cat:"Peace"},
  {id:"PC021",text:"Worry is not preparation. I set it down and trust the process instead.",cat:"Peace"},
  {id:"PC022",text:"I find stillness not by escaping my life but by coming home to myself within it.",cat:"Peace"},
  {id:"PC023",text:"My peace is an inside job. No circumstance can take it unless I hand it over.",cat:"Peace"},
  {id:"PC024",text:"I let go of the past version of events I keep replaying. That moment is done.",cat:"Peace"},
  {id:"PC025",text:"I quiet my mind by choosing this breath, this moment, this small thing right in front of me.",cat:"Peace"},
  {id:"PC026",text:"I do not need to resolve everything tonight. I am allowed to rest inside the open question.",cat:"Peace"},
  {id:"PC027",text:"I choose peace over being right. The relationship matters more than the argument.",cat:"Peace"},
  {id:"PC028",text:"Boundaries are not walls. They are the edges of my peace and I maintain them with care.",cat:"Peace"},
  {id:"PC029",text:"Uncertainty is not a threat. It is the space where possibility lives.",cat:"Peace"},
  {id:"PC030",text:"I slow down on purpose. Speed is not the same as progress.",cat:"Peace"},
  {id:"PC031",text:"I release the anxiety that comes from living too far into the future.",cat:"Peace"},
  {id:"PC032",text:"The things I cannot change are not my assignment. I focus on what is.",cat:"Peace"},
  {id:"PC033",text:"I bring calm into the rooms I enter. That is one of my quiet strengths.",cat:"Peace"},
  {id:"PC034",text:"I do not have to earn rest. Stillness is not a reward. It is a right.",cat:"Peace"},
  {id:"PC035",text:"I stop rehearsing catastrophe. Most of what I fear will never arrive.",cat:"Peace"},
  {id:"PC036",text:"Peace in my relationships begins with peace inside myself. I start there.",cat:"Peace"},
  {id:"PC037",text:"I accept what is without adding the weight of what should have been.",cat:"Peace"},
  {id:"PC038",text:"The world moves fast. I do not have to move with it. I set my own pace.",cat:"Peace"},
  {id:"PC039",text:"I release the tension I have been holding in my body. I am safe right now.",cat:"Peace"},
  {id:"PC040",text:"I do not owe anyone my chaos. I protect my peace quietly and without guilt.",cat:"Peace"},
  {id:"PC041",text:"Letting go is not giving up. It is recognizing what was never mine to hold.",cat:"Peace"},
  {id:"PC042",text:"I trust that life is working out in ways I cannot yet see. I wait with openness.",cat:"Peace"},
  {id:"PC043",text:"I am not behind. I am not failing. I am living at a sustainable pace and that is enough.",cat:"Peace"},
  {id:"PC044",text:"I choose one calm thought when the spiral starts. That one thought is enough to redirect me.",cat:"Peace"},
  {id:"PC045",text:"I release the conversations in my head that no one else is having.",cat:"Peace"},
  {id:"PC046",text:"My worth is not measured by how much I produce. I am allowed to simply be.",cat:"Peace"},
  {id:"PC047",text:"I make peace with the parts of my story I cannot change and I build from here.",cat:"Peace"},
  {id:"PC048",text:"There is nothing to prove right now. I breathe. I am here. That is everything.",cat:"Peace"},
  {id:"PC049",text:"I choose peace not because everything is resolved but because I am done waiting for it to be.",cat:"Peace"},
  // CONFIDENCE (continued)
  {id:"CO021",text:"I know my worth and I do not need anyone to confirm it.",cat:"Confidence"},
  {id:"CO022",text:"I walk into every room as if I belong there — because I do.",cat:"Confidence"},
  {id:"CO023",text:"I speak without apologizing for taking up the space a sentence requires.",cat:"Confidence"},
  {id:"CO024",text:"I trust my own judgment. I have earned the right to.",cat:"Confidence"},
  {id:"CO025",text:"Failure did not break my confidence. It built the kind that cannot be faked.",cat:"Confidence"},
  {id:"CO026",text:"I let myself be seen. Fully. Without editing the parts that feel exposed.",cat:"Confidence"},
  {id:"CO027",text:"My story is mine. I own it without shame and without over-explaining.",cat:"Confidence"},
  {id:"CO028",text:"Confidence is something I practice, not something I wait to feel.",cat:"Confidence"},
  {id:"CO029",text:"The inner critic is not the truth. I know the difference now.",cat:"Confidence"},
  {id:"CO030",text:"I lead with conviction even when I cannot predict the outcome.",cat:"Confidence"},
  {id:"CO031",text:"I am unapologetically myself and the right people find that magnetic.",cat:"Confidence"},
  {id:"CO032",text:"I do not need to dim to make the room more comfortable. The room adjusts.",cat:"Confidence"},
  {id:"CO033",text:"My voice carries weight. I use it.",cat:"Confidence"},
  {id:"CO034",text:"I have rebuilt my confidence before and I know exactly what it takes.",cat:"Confidence"},
  {id:"CO035",text:"I stop second-guessing decisions I have already made with good intention.",cat:"Confidence"},
  {id:"CO036",text:"The version of me who doubts every move is not the most accurate version of me.",cat:"Confidence"},
  {id:"CO037",text:"I stand behind what I believe even when no one else in the room agrees.",cat:"Confidence"},
  {id:"CO038",text:"I do not need to justify my choices to anyone who did not ask for input.",cat:"Confidence"},
  {id:"CO039",text:"Every time I kept going when I wanted to quit, I proved something to myself.",cat:"Confidence"},
  {id:"CO040",text:"I am someone who figures things out. That has always been true.",cat:"Confidence"},
  {id:"CO041",text:"I present myself with the same respect I would give someone I admire.",cat:"Confidence"},
  {id:"CO042",text:"Opinions about me that I did not ask for do not get to live in my head rent-free.",cat:"Confidence"},
  {id:"CO043",text:"I walk through discomfort without letting it convince me I am in the wrong place.",cat:"Confidence"},
  {id:"CO044",text:"The confidence I have today was built in the hardest moments. I trust it completely.",cat:"Confidence"},
  {id:"CO045",text:"I stop performing and start simply being. That is confidence in its truest form.",cat:"Confidence"},
  {id:"CO046",text:"I am not waiting to feel ready. I am the person who goes first.",cat:"Confidence"},
  {id:"CO047",text:"My presence alone communicates something worth paying attention to.",cat:"Confidence"},
  {id:"CO048",text:"I no longer apologize for being good at what I do.",cat:"Confidence"},
  {id:"CO049",text:"The most confident thing I can do is be exactly who I am in every room I enter.",cat:"Confidence"},
  {id:"CO050",text:"I decide how I feel about myself and that decision is not up for debate.",cat:"Confidence"},
  // ABUNDANCE (continued)
  {id:"AB021",text:"I am shifting the way I think about money and that shift is changing everything.",cat:"Abundance"},
  {id:"AB022",text:"I receive with open hands and a grateful heart. Guilt has no place here.",cat:"Abundance"},
  {id:"AB023",text:"I believe I deserve more — more ease, more security, more freedom — and I act like it.",cat:"Abundance"},
  {id:"AB024",text:"Abundance is not only money. It is time, joy, health, love, and all the things that make a life full.",cat:"Abundance"},
  {id:"AB025",text:"Scarcity was a story I inherited. I am writing a different one.",cat:"Abundance"},
  {id:"AB026",text:"The more freely I give, the more effortlessly abundance finds its way back to me.",cat:"Abundance"},
  {id:"AB027",text:"I trust that what I need is always provided, sometimes in ways I did not expect.",cat:"Abundance"},
  {id:"AB028",text:"Opportunities are drawn to me because I am prepared, present, and open.",cat:"Abundance"},
  {id:"AB029",text:"Financial freedom is not a distant dream. It is the direction I am walking in right now.",cat:"Abundance"},
  {id:"AB030",text:"Abundance is my natural state. Lack is something I was taught, and I am unlearning it.",cat:"Abundance"},
  {id:"AB031",text:"I have more than enough to share and sharing does not diminish what I have.",cat:"Abundance"},
  {id:"AB032",text:"Money comes to me from expected and unexpected sources and I welcome it all.",cat:"Abundance"},
  {id:"AB033",text:"I release the belief that wanting more makes me greedy. Desire is not greed. It is direction.",cat:"Abundance"},
  {id:"AB034",text:"I am in an abundant universe and I claim my full share of it.",cat:"Abundance"},
  {id:"AB035",text:"Every dollar I spend returns to me multiplied. Money moves through me, not away from me.",cat:"Abundance"},
  {id:"AB036",text:"I am building a life where financial stress is not the background noise.",cat:"Abundance"},
  {id:"AB037",text:"Wealth and integrity live together in me. I hold both without apology.",cat:"Abundance"},
  {id:"AB038",text:"I notice abundance everywhere — in small moments, quiet blessings, and open doors.",cat:"Abundance"},
  {id:"AB039",text:"I stop treating prosperity like something that happens to other people.",cat:"Abundance"},
  {id:"AB040",text:"I am worthy of a life that feels spacious, resourced, and free.",cat:"Abundance"},
  {id:"AB041",text:"The universe is not withholding from me. I open myself to receive what is already mine.",cat:"Abundance"},
  {id:"AB042",text:"My relationship with money is healing. I approach it with clarity and calm.",cat:"Abundance"},
  {id:"AB043",text:"I do not hoard out of fear. I trust that more will come and I give from that trust.",cat:"Abundance"},
  {id:"AB044",text:"Every positive financial decision I make today builds the freedom I will feel tomorrow.",cat:"Abundance"},
  {id:"AB045",text:"Prosperity is not the reward for struggle. I allow it to arrive with ease.",cat:"Abundance"},
  {id:"AB046",text:"I overflow — with gratitude, with resources, with the ability to help others.",cat:"Abundance"},
  {id:"AB047",text:"I no longer dim my financial ambitions to avoid making others uncomfortable.",cat:"Abundance"},
  {id:"AB048",text:"The life I want is affordable. I am figuring out the how.",cat:"Abundance"},
  {id:"AB049",text:"I attract people, partnerships, and opportunities that expand what is possible for me.",cat:"Abundance"},
  {id:"AB050",text:"I am the kind of person for whom abundance is simply the natural order of things.",cat:"Abundance"},
  // GROWTH (continued)
  {id:"GR026",text:"Discomfort is not a detour. It is the actual road and I am on it.",cat:"Growth"},
  {id:"GR027",text:"I am becoming who I was always meant to be. The becoming is the point.",cat:"Growth"},
  {id:"GR028",text:"I am actively unlearning what was taught to me and choosing what I actually believe.",cat:"Growth"},
  {id:"GR029",text:"The small thing I do today that no one sees is building the life everyone will notice.",cat:"Growth"},
  {id:"GR030",text:"My relationships are teaching me about myself and I pay attention to the lessons.",cat:"Growth"},
  {id:"GR031",text:"I have outgrown things I once thought defined me. That is growth, not loss.",cat:"Growth"},
  {id:"GR032",text:"I am patient with my process. Transformation rarely announces itself ahead of time.",cat:"Growth"},
  {id:"GR033",text:"Failure is feedback. I take what it is teaching me and I keep going.",cat:"Growth"},
  {id:"GR034",text:"I am expanding who I understand myself to be. My identity is not a fixed thing.",cat:"Growth"},
  {id:"GR035",text:"Something is shifting in me right now even if I cannot see it yet. I trust that.",cat:"Growth"},
  {id:"GR036",text:"Every day I show up I am compounding. The returns are coming.",cat:"Growth"},
  {id:"GR037",text:"I release the old patterns not with judgment but with understanding. They served me once.",cat:"Growth"},
  {id:"GR038",text:"The version of me I am becoming would not recognize the fears that are slowing me down today.",cat:"Growth"},
  {id:"GR039",text:"I choose the harder path when I know it leads somewhere the easy path does not.",cat:"Growth"},
  {id:"GR040",text:"I have grown through things I never asked for and I carry that strength with me.",cat:"Growth"},
  {id:"GR041",text:"I give myself time to change. Rewiring takes repetition and I am patient with it.",cat:"Growth"},
  {id:"GR042",text:"The best investment I am making right now is in the person I am becoming.",cat:"Growth"},
  {id:"GR043",text:"I no longer need a crisis to prompt my growth. I choose it intentionally.",cat:"Growth"},
  {id:"GR044",text:"My edges are expanding. What felt impossible a year ago feels possible today.",cat:"Growth"},
  {id:"GR045",text:"I am not afraid of who I am becoming. I am becoming someone worth becoming.",cat:"Growth"},
  {id:"GR046",text:"I do the work even when results are invisible. Roots grow before branches.",cat:"Growth"},
  {id:"GR047",text:"The habits I build today are the character I inhabit tomorrow.",cat:"Growth"},
  {id:"GR048",text:"I grow through relationships by being honest about what I need and what I will no longer accept.",cat:"Growth"},
  {id:"GR049",text:"Outgrowing a version of myself is an act of loyalty to the one I am becoming.",cat:"Growth"},
  {id:"GR050",text:"I keep going not because it is easy but because I have seen what stopping costs.",cat:"Growth"},
  {id:"GR051",text:"Every hard lesson has made my foundation more solid. I build on it.",cat:"Growth"},
  {id:"GR052",text:"I am curious about who I will be five years from now if I keep choosing this.",cat:"Growth"},
  {id:"GR053",text:"Transformation is quiet, internal, and real. I trust what I cannot yet see.",cat:"Growth"},
  {id:"GR054",text:"I do not need to arrive. I need to keep moving. That is what growth asks of me.",cat:"Growth"},
  {id:"GR055",text:"I am proof that people change. I am living evidence of what is possible.",cat:"Growth"},
  // ABUNDANCE — expansion (AB051–AB150)
  {id:"AB051",text:"Wealth begins as a decision about what I believe I deserve. I have decided.",cat:"Abundance"},
  {id:"AB052",text:"I am allowed to want a comfortable life and to build one.",cat:"Abundance"},
  {id:"AB053",text:"Every door I knock on is one knock closer to the one that opens.",cat:"Abundance"},
  {id:"AB054",text:"My bank account is not a measure of my worth, and abundance still belongs to me.",cat:"Abundance"},
  {id:"AB055",text:"I make room for more by being grateful for what is already here.",cat:"Abundance"},
  {id:"AB056",text:"Receiving help is not weakness. It is one of the ways abundance arrives.",cat:"Abundance"},
  {id:"AB057",text:"I plant seeds in many fields and trust that some are already sprouting.",cat:"Abundance"},
  {id:"AB058",text:"There is enough. There has always been enough. I live like I believe it.",cat:"Abundance"},
  {id:"AB059",text:"I stop shrinking my dreams to fit my current budget.",cat:"Abundance"},
  {id:"AB060",text:"What I focus on expands, so I focus on what is working.",cat:"Abundance"},
  {id:"AB061",text:"My income grows as my willingness to be seen grows.",cat:"Abundance"},
  {id:"AB062",text:"I release my family's old stories about money. They end with me.",cat:"Abundance"},
  {id:"AB063",text:"Ease is not suspicious. Good things are allowed to come easily to me.",cat:"Abundance"},
  {id:"AB064",text:"I am a careful steward of what I have, and more is trusted to me because of it.",cat:"Abundance"},
  {id:"AB065",text:"Today I notice three forms of abundance that have nothing to do with money.",cat:"Abundance"},
  {id:"AB066",text:"I ask for what things cost without flinching.",cat:"Abundance"},
  {id:"AB067",text:"The universe does not run out. Neither does my access to it.",cat:"Abundance"},
  {id:"AB068",text:"I celebrate other people's wins because their abundance is proof of what is possible.",cat:"Abundance"},
  {id:"AB069",text:"I am building wealth quietly, one unglamorous decision at a time.",cat:"Abundance"},
  {id:"AB070",text:"My needs are not a burden. Providing for them is the universe's pleasure.",cat:"Abundance"},
  {id:"AB071",text:"Opportunity does not knock once. It circles back for the prepared.",cat:"Abundance"},
  {id:"AB072",text:"I let money rest in my hands without rushing to push it away.",cat:"Abundance"},
  {id:"AB073",text:"Generosity is my proof that I trust more is coming.",cat:"Abundance"},
  {id:"AB074",text:"I am done rehearsing poverty in my imagination.",cat:"Abundance"},
  {id:"AB075",text:"Every skill I sharpen raises the ceiling on what I can earn.",cat:"Abundance"},
  {id:"AB076",text:"Abundance flows toward clarity. I am getting clearer every day.",cat:"Abundance"},
  {id:"AB077",text:"I deserve to be paid fully and promptly for what I create.",cat:"Abundance"},
  {id:"AB078",text:"The gap between where I am and where I am going is already closing.",cat:"Abundance"},
  {id:"AB079",text:"I unsubscribe from urgency. Wealth built slowly is still wealth.",cat:"Abundance"},
  {id:"AB080",text:"My definition of rich includes mornings without dread. I am building that too.",cat:"Abundance"},
  {id:"AB081",text:"I treat small amounts of money with respect, and large amounts learn to trust me.",cat:"Abundance"},
  {id:"AB082",text:"There is a version of my life with more ease in it, and I am walking toward it.",cat:"Abundance"},
  {id:"AB083",text:"I do not guard scraps. I prepare for harvest.",cat:"Abundance"},
  {id:"AB084",text:"Saying no to the wrong opportunity makes room for the right one.",cat:"Abundance"},
  {id:"AB085",text:"My cup is not half empty or half full. It is refillable.",cat:"Abundance"},
  {id:"AB086",text:"Prosperity looks good on me, and I am done apologizing for wanting it.",cat:"Abundance"},
  {id:"AB087",text:"What is meant for me does not need to be chased. It needs to be met.",cat:"Abundance"},
  {id:"AB088",text:"I am open to wealth arriving in forms I did not think to ask for.",cat:"Abundance"},
  {id:"AB089",text:"Every bill I pay is proof that money moved through my life. More is moving now.",cat:"Abundance"},
  {id:"AB090",text:"I stop waiting for permission to live well.",cat:"Abundance"},
  {id:"AB091",text:"Enough is not the ceiling of my dreams. It is the floor.",cat:"Abundance"},
  {id:"AB092",text:"I attract abundance fastest when I am busy being useful.",cat:"Abundance"},
  {id:"AB093",text:"The richest thing I own is my attention, and I spend it deliberately.",cat:"Abundance"},
  {id:"AB094",text:"I trust myself with more, and life keeps agreeing with me.",cat:"Abundance"},
  {id:"AB095",text:"Lack leaves my vocabulary a little more every day.",cat:"Abundance"},
  {id:"AB096",text:"I am allowed to outgrow the income of every previous version of me.",cat:"Abundance"},
  {id:"AB097",text:"My gratitude list is the most accurate accounting of my wealth.",cat:"Abundance"},
  {id:"AB098",text:"I receive compliments, gifts, and good fortune with a simple thank you.",cat:"Abundance"},
  {id:"AB099",text:"Money solves money problems, and I am solving them with a steady hand.",cat:"Abundance"},
  {id:"AB100",text:"The harvest is already growing in fields I planted and forgot.",cat:"Abundance"},
  {id:"AB101",text:"I am not behind financially. I am at the beginning of my best decade.",cat:"Abundance"},
  {id:"AB102",text:"I keep my promises to my future self, one deposit at a time.",cat:"Abundance"},
  {id:"AB103",text:"Asking for more is not greed when I intend to do good with it.",cat:"Abundance"},
  {id:"AB104",text:"Abundance does not require my exhaustion. I refuse to burn out for it.",cat:"Abundance"},
  {id:"AB105",text:"I am the kind of person opportunities are told about.",cat:"Abundance"},
  {id:"AB106",text:"What I give attention to grows. I attend to my hopes, not my fears.",cat:"Abundance"},
  {id:"AB107",text:"I am wealthy in friends, in ideas, in mornings — and the money is following.",cat:"Abundance"},
  {id:"AB108",text:"Today I act like someone whose needs are already met, because they are being met.",cat:"Abundance"},
  {id:"AB109",text:"I am allowed to rest without losing momentum. Abundance keeps working while I sleep.",cat:"Abundance"},
  {id:"AB110",text:"My possibilities are not capped by my history.",cat:"Abundance"},
  {id:"AB111",text:"I count what I have before I count what I lack — and the list keeps growing.",cat:"Abundance"},
  {id:"AB112",text:"I am open, resourced, and ready for the next level of my life.",cat:"Abundance"},
  {id:"AB113",text:"Wealth is patient with the people who are patient with it.",cat:"Abundance"},
  {id:"AB114",text:"I move through the world expecting to be helped, and the world keeps obliging.",cat:"Abundance"},
  {id:"AB115",text:"Nothing meant for me passes me by. It waits, or it returns.",cat:"Abundance"},
  {id:"AB116",text:"I am no longer loyal to struggle. Comfort is allowed to be my normal.",cat:"Abundance"},
  {id:"AB117",text:"More money simply makes me more of who I already am — and who I am is good.",cat:"Abundance"},
  {id:"AB118",text:"Abundance hears me best when I speak in decisions, not wishes.",cat:"Abundance"},
  {id:"AB119",text:"I let my work compound quietly while I live my life.",cat:"Abundance"},
  {id:"AB120",text:"I am grateful in advance, and gratitude has never once let me down.",cat:"Abundance"},
  {id:"AB121",text:"Provision finds me on time even when it does not arrive early.",cat:"Abundance"},
  {id:"AB122",text:"I release the cringe around money talk. Clarity is kind.",cat:"Abundance"},
  {id:"AB123",text:"My environment is rich with possibilities I have only begun to notice.",cat:"Abundance"},
  {id:"AB124",text:"The next opportunity does not need me perfect. It needs me present.",cat:"Abundance"},
  {id:"AB125",text:"I forgive my past financial mistakes. They were tuition, and I learned.",cat:"Abundance"},
  {id:"AB126",text:"I keep showing up to the work, and the work keeps showing up for me.",cat:"Abundance"},
  {id:"AB127",text:"Some of what I want is already en route. My job today is readiness.",cat:"Abundance"},
  {id:"AB128",text:"I let go of the fear of being too expensive.",cat:"Abundance"},
  {id:"AB129",text:"Even my setbacks have paid me — in wisdom, in resilience, in direction.",cat:"Abundance"},
  {id:"AB130",text:"I have survived every lean season so far. This one is also passing.",cat:"Abundance"},
  {id:"AB131",text:"I am a calm and confident decision-maker with money.",cat:"Abundance"},
  {id:"AB132",text:"What I appreciate appreciates.",cat:"Abundance"},
  {id:"AB133",text:"I no longer wait for someday. I fund the dream in small amounts now.",cat:"Abundance"},
  {id:"AB134",text:"My value does not fluctuate with the market.",cat:"Abundance"},
  {id:"AB135",text:"Wealth that costs my health is not wealth. I build the kind that adds life.",cat:"Abundance"},
  {id:"AB136",text:"I am building proof, not just hope — and proof attracts.",cat:"Abundance"},
  {id:"AB137",text:"There are rooms I have not entered yet where my name is already known.",cat:"Abundance"},
  {id:"AB138",text:"My future is well funded by the choices I am making today.",cat:"Abundance"},
  {id:"AB139",text:"Abundance is quieter than I expected — steady bills paid, a fridge full, a plan working.",cat:"Abundance"},
  {id:"AB140",text:"I receive feedback, refunds, and windfalls with equal grace.",cat:"Abundance"},
  {id:"AB141",text:"The more honest I am about what I want, the faster it organizes around me.",cat:"Abundance"},
  {id:"AB142",text:"I am done negotiating against myself before anyone else has spoken.",cat:"Abundance"},
  {id:"AB143",text:"Today's small surplus is tomorrow's freedom. I treat it that way.",cat:"Abundance"},
  {id:"AB144",text:"I am allowed to have savings and dreams at the same time.",cat:"Abundance"},
  {id:"AB145",text:"My open hands receive more than my clenched fists ever protected.",cat:"Abundance"},
  {id:"AB146",text:"Where I am headed, scarcity stories are not invited.",cat:"Abundance"},
  {id:"AB147",text:"I am one good decision away from a different trajectory — and I make good decisions daily.",cat:"Abundance"},
  {id:"AB148",text:"Everything I have ever needed has found me. My needs are still finding me now.",cat:"Abundance"},
  {id:"AB149",text:"I live in the overlap of gratitude and ambition, and it is fertile ground.",cat:"Abundance"},
  {id:"AB150",text:"Already mine — I say it about the life I am building, and I mean it.",cat:"Abundance"},
  // LOVE — expansion (LV050–LV149)
  {id:"LV050",text:"I am lovable on my quiet days, my loud days, and my lost days alike.",cat:"Love"},
  {id:"LV051",text:"The love I want exists. I have seen it, and seeing it means it is findable.",cat:"Love"},
  {id:"LV052",text:"I do not perform for affection. I show up as myself and let that be the offer.",cat:"Love"},
  {id:"LV053",text:"My heart has good taste. I am learning to trust who it points toward.",cat:"Love"},
  {id:"LV054",text:"I am building the kind of love that makes both people more free.",cat:"Love"},
  {id:"LV055",text:"Being alone right now is not a verdict. It is a season with its own gifts.",cat:"Love"},
  {id:"LV056",text:"I speak kindly to myself because I am always listening.",cat:"Love"},
  {id:"LV057",text:"The right love will not require me to audition.",cat:"Love"},
  {id:"LV058",text:"I let people love me in their language while I teach them mine.",cat:"Love"},
  {id:"LV059",text:"My tenderness survived everything that tried to harden me. That is remarkable.",cat:"Love"},
  {id:"LV060",text:"I am done mistaking anxiety for chemistry.",cat:"Love"},
  {id:"LV061",text:"Love that is steady can still be exciting. I am open to learning that.",cat:"Love"},
  {id:"LV062",text:"I check on my friends, and the checking is the love.",cat:"Love"},
  {id:"LV063",text:"I am allowed to need people. Needing is not the same as being needy.",cat:"Love"},
  {id:"LV064",text:"The way I treat myself sets the opening bid for every relationship.",cat:"Love"},
  {id:"LV065",text:"I forgive my younger heart for the people it chose while it was still learning.",cat:"Love"},
  {id:"LV066",text:"Someone is hoping for a person exactly like me.",cat:"Love"},
  {id:"LV067",text:"I bring softness into rooms that have forgotten it.",cat:"Love"},
  {id:"LV068",text:"My standards are not too high. My patience for less is just gone.",cat:"Love"},
  {id:"LV069",text:"Real intimacy starts where my performance ends.",cat:"Love"},
  {id:"LV070",text:"I love people without holding my breath.",cat:"Love"},
  {id:"LV071",text:"The love in my life multiplies when I name it out loud.",cat:"Love"},
  {id:"LV072",text:"I am a safe place for the people I love — and for myself first.",cat:"Love"},
  {id:"LV073",text:"Affection given freely returns from directions I never expected.",cat:"Love"},
  {id:"LV074",text:"I no longer flinch when someone is consistent with me.",cat:"Love"},
  {id:"LV075",text:"My heart is not a problem to be fixed. It is a home being furnished.",cat:"Love"},
  {id:"LV076",text:"I am whole alone and better accompanied. Both are true.",cat:"Love"},
  {id:"LV077",text:"I trust slow love. Roots first, then branches.",cat:"Love"},
  {id:"LV078",text:"The people who get me do not need me translated.",cat:"Love"},
  {id:"LV079",text:"I release every almost. It was an almost for a reason.",cat:"Love"},
  {id:"LV080",text:"Love finds me easily because I have stopped hiding.",cat:"Love"},
  {id:"LV081",text:"I am learning the difference between peace and boredom, and choosing peace.",cat:"Love"},
  {id:"LV082",text:"Kindness is my type.",cat:"Love"},
  {id:"LV083",text:"I do not chase closure from people who could not even offer clarity.",cat:"Love"},
  {id:"LV084",text:"Every act of self-respect is a love letter to my future relationships.",cat:"Love"},
  {id:"LV085",text:"I belong to a small circle of people who would cross town for me. That is wealth.",cat:"Love"},
  {id:"LV086",text:"I let myself be delighted in. It used to feel like exposure. Now it feels like home.",cat:"Love"},
  {id:"LV087",text:"What I survived taught me what love is not. Now I get to learn what it is.",cat:"Love"},
  {id:"LV088",text:"I give my love generously and my trust accurately.",cat:"Love"},
  {id:"LV089",text:"There is no shortage of love in this world, and my share is not in question.",cat:"Love"},
  {id:"LV090",text:"I am someone people feel safe being honest with.",cat:"Love"},
  {id:"LV091",text:"My capacity to love after heartbreak is the strongest thing about me.",cat:"Love"},
  {id:"LV092",text:"I date with my eyes open and my heart available.",cat:"Love"},
  {id:"LV093",text:"The love I practice on myself is rehearsal for nothing — it is the real thing.",cat:"Love"},
  {id:"LV094",text:"I am allowed to ask for reassurance and to need the answer.",cat:"Love"},
  {id:"LV095",text:"Being chosen is lovely. Choosing myself is foundational.",cat:"Love"},
  {id:"LV096",text:"I keep my heart open without leaving the door unlocked to just anyone.",cat:"Love"},
  {id:"LV097",text:"My friendships are love stories too, and I tend them like it.",cat:"Love"},
  {id:"LV098",text:"I receive care without keeping score.",cat:"Love"},
  {id:"LV099",text:"The love that is coming will fit because I stopped shrinking.",cat:"Love"},
  {id:"LV100",text:"I am soft with the people I love and clear about what I need.",cat:"Love"},
  {id:"LV101",text:"Old wounds do not get a vote on new people.",cat:"Love"},
  {id:"LV102",text:"I show up to love as a whole person, not a half looking for completion.",cat:"Love"},
  {id:"LV103",text:"My presence is a gift I no longer give to people who unwrap it carelessly.",cat:"Love"},
  {id:"LV104",text:"I love without managing the other person's every feeling.",cat:"Love"},
  {id:"LV105",text:"Loneliness visits everyone. I let it visit without letting it decorate.",cat:"Love"},
  {id:"LV106",text:"I am exactly the kind of person I would want to be loved by.",cat:"Love"},
  {id:"LV107",text:"Healthy love felt boring once because chaos was familiar. Familiar is not the same as right.",cat:"Love"},
  {id:"LV108",text:"I tell people I love them while it can still make their day.",cat:"Love"},
  {id:"LV109",text:"My heart keeps no waiting room for people who are not coming.",cat:"Love"},
  {id:"LV110",text:"Vulnerability is not oversharing. It is letting the right people see me accurately.",cat:"Love"},
  {id:"LV111",text:"I am still romantic after everything. I count that as a victory.",cat:"Love"},
  {id:"LV112",text:"Love is patient with me while I learn to receive it.",cat:"Love"},
  {id:"LV113",text:"I choose partners who are kind to waiters, animals, and their own mothers.",cat:"Love"},
  {id:"LV114",text:"I am allowed to outgrow relationships without calling anyone a villain.",cat:"Love"},
  {id:"LV115",text:"The way someone treats me is information. I have stopped arguing with information.",cat:"Love"},
  {id:"LV116",text:"I bring laughter into love. It is one of my favorite things I do.",cat:"Love"},
  {id:"LV117",text:"My boundaries did not scare away the right people. They organized my life.",cat:"Love"},
  {id:"LV118",text:"I trust people who show me consistency over people who promise me intensity.",cat:"Love"},
  {id:"LV119",text:"Self-love is not a bubble bath. It is the standard I hold all day.",cat:"Love"},
  {id:"LV120",text:"I am open to being surprised by who turns out to matter.",cat:"Love"},
  {id:"LV121",text:"Every relationship in my life is allowed to be easy. Hard is not proof of depth.",cat:"Love"},
  {id:"LV122",text:"I let love change its shape across seasons without panicking.",cat:"Love"},
  {id:"LV123",text:"The love I give my people outlives every ordinary day I gave it on.",cat:"Love"},
  {id:"LV124",text:"I am done auditioning for emotionally unavailable audiences.",cat:"Love"},
  {id:"LV125",text:"My affection is a privilege, and I extend it to people who treat it that way.",cat:"Love"},
  {id:"LV126",text:"I can be deeply committed and still entirely myself.",cat:"Love"},
  {id:"LV127",text:"I love from overflow now, not from emptiness hoping to be filled.",cat:"Love"},
  {id:"LV128",text:"Someone's inability to love me well was never a measurement of me.",cat:"Love"},
  {id:"LV129",text:"I am gentle with my heart on anniversaries of old pain.",cat:"Love"},
  {id:"LV130",text:"I notice how I feel after I see someone. That feeling is the review.",cat:"Love"},
  {id:"LV131",text:"I keep falling in love with my life, and people keep wanting in.",cat:"Love"},
  {id:"LV132",text:"What I want in a partner, I practice being.",cat:"Love"},
  {id:"LV133",text:"I release the timeline. Love is not late. It is in transit.",cat:"Love"},
  {id:"LV134",text:"I am the love of my own life first, and that has made me better at sharing it.",cat:"Love"},
  {id:"LV135",text:"Conflict handled with care brings us closer. I do not fear the conversation.",cat:"Love"},
  {id:"LV136",text:"My people know where they stand with me. Clarity is how I love.",cat:"Love"},
  {id:"LV137",text:"I am allowed to want romance, partnership, and a witness to my life.",cat:"Love"},
  {id:"LV138",text:"Every time I choose honesty over harmony, my relationships get more real.",cat:"Love"},
  {id:"LV139",text:"I love hard and rest easy, because I hold nothing back that I will regret.",cat:"Love"},
  {id:"LV140",text:"Being deeply known no longer frightens me. It is the whole point.",cat:"Love"},
  {id:"LV141",text:"I trust the pace of what is real.",cat:"Love"},
  {id:"LV142",text:"My warmth is not naivety. I see clearly and love anyway.",cat:"Love"},
  {id:"LV143",text:"I let the people who love me catch me when I fall. They want to.",cat:"Love"},
  {id:"LV144",text:"The next chapter of my love story is written by who I am now, not who I was.",cat:"Love"},
  {id:"LV145",text:"I am building a love my younger self would not believe and my older self will thank me for.",cat:"Love"},
  {id:"LV146",text:"Affection, attention, honesty, repair — I give the love I intend to receive.",cat:"Love"},
  {id:"LV147",text:"I am not hard to love. I was just handing the manual to people who would not read it.",cat:"Love"},
  {id:"LV148",text:"I deserve a love I do not have to decode.",cat:"Love"},
  {id:"LV149",text:"Love is already mine — in friendship, in family, in the person learning my name right now.",cat:"Love"},
  // CONFIDENCE — expansion (CO051–CO150)
  {id:"CO051",text:"I keep my own opinion of myself in the front row.",cat:"Confidence"},
  {id:"CO052",text:"Doubt can ride along, but it does not get to drive.",cat:"Confidence"},
  {id:"CO053",text:"I have done hard things with shaking hands. The shaking never disqualified me.",cat:"Confidence"},
  {id:"CO054",text:"My presence does not require an apology or an explanation.",cat:"Confidence"},
  {id:"CO055",text:"I answer the question I was asked without shrinking the answer.",cat:"Confidence"},
  {id:"CO056",text:"Imposter feelings are a sign I am in new territory, not the wrong territory.",cat:"Confidence"},
  {id:"CO057",text:"I take compliments at face value. People mean them.",cat:"Confidence"},
  {id:"CO058",text:"I am the most qualified person alive to be me.",cat:"Confidence"},
  {id:"CO059",text:"Comparison flattens what is rich about my path. I keep the dimension.",cat:"Confidence"},
  {id:"CO060",text:"I act first and feel confident second. That is the actual order.",cat:"Confidence"},
  {id:"CO061",text:"My no is a complete sentence and my yes is fully meant.",cat:"Confidence"},
  {id:"CO062",text:"I trust the version of me who made that decision. They had good reasons.",cat:"Confidence"},
  {id:"CO063",text:"Being underestimated has quietly become my favorite advantage.",cat:"Confidence"},
  {id:"CO064",text:"I belong in rooms I was never supposed to reach.",cat:"Confidence"},
  {id:"CO065",text:"Confidence is not volume. Mine is quiet and it holds.",cat:"Confidence"},
  {id:"CO066",text:"I do not flinch at my own reflection. We are on the same team.",cat:"Confidence"},
  {id:"CO067",text:"Other people's certainty is not evidence. I check things for myself.",cat:"Confidence"},
  {id:"CO068",text:"I have stopped outsourcing my self-worth to the most critical person in the room.",cat:"Confidence"},
  {id:"CO069",text:"What I bring is specific. The right people are looking for exactly it.",cat:"Confidence"},
  {id:"CO070",text:"I make eye contact with my goals.",cat:"Confidence"},
  {id:"CO071",text:"I am allowed to be proud out loud.",cat:"Confidence"},
  {id:"CO072",text:"Awkward and brave beats polished and absent. I show up either way.",cat:"Confidence"},
  {id:"CO073",text:"My mistakes are footnotes, not the title of the book.",cat:"Confidence"},
  {id:"CO074",text:"I stand in my own corner first, loudly and on purpose.",cat:"Confidence"},
  {id:"CO075",text:"I am done auditioning for roles I already hold.",cat:"Confidence"},
  {id:"CO076",text:"The room does not decide my value. I arrive with it.",cat:"Confidence"},
  {id:"CO077",text:"My instincts have receipts. I trust them.",cat:"Confidence"},
  {id:"CO078",text:"I speak in drafts when I must, but I speak.",cat:"Confidence"},
  {id:"CO079",text:"I would rather be fully myself and filtered out than half myself and kept.",cat:"Confidence"},
  {id:"CO080",text:"I take my seat without checking everyone's face for permission.",cat:"Confidence"},
  {id:"CO081",text:"Confidence grew in me the way strength does — through reps I did not enjoy.",cat:"Confidence"},
  {id:"CO082",text:"I let my work speak, and I am no longer afraid to introduce it.",cat:"Confidence"},
  {id:"CO083",text:"I do not perform smallness as politeness anymore.",cat:"Confidence"},
  {id:"CO084",text:"When I do not know, I say so — and that honesty is its own authority.",cat:"Confidence"},
  {id:"CO085",text:"I have outlived every embarrassment so far. I will outlive the next one too.",cat:"Confidence"},
  {id:"CO086",text:"I move like someone who expects to be welcomed, and mostly I am.",cat:"Confidence"},
  {id:"CO087",text:"Self-doubt writes fiction. I read it less and less.",cat:"Confidence"},
  {id:"CO088",text:"I am sturdy in ways that took years and look like nothing.",cat:"Confidence"},
  {id:"CO089",text:"I let myself be a learner in public.",cat:"Confidence"},
  {id:"CO090",text:"My voice was given to me to be used, not to be managed.",cat:"Confidence"},
  {id:"CO091",text:"I make decisions from the version of me I am becoming, not the one I am leaving.",cat:"Confidence"},
  {id:"CO092",text:"I am hard to rattle — not because nothing shakes me, but because I know I reset.",cat:"Confidence"},
  {id:"CO093",text:"I respect myself too much to talk myself out of opportunities.",cat:"Confidence"},
  {id:"CO094",text:"Their opinion of me is a weather report from a city I do not live in.",cat:"Confidence"},
  {id:"CO095",text:"I show my work before it is perfect because momentum beats polish.",cat:"Confidence"},
  {id:"CO096",text:"I carry myself like the answer might be yes.",cat:"Confidence"},
  {id:"CO097",text:"I have been the new person, the only person, and the wrong-on-paper person — and delivered every time.",cat:"Confidence"},
  {id:"CO098",text:"My boundaries broadcast my worth so I do not have to argue it.",cat:"Confidence"},
  {id:"CO099",text:"I can be a masterpiece and a work in progress in the same afternoon.",cat:"Confidence"},
  {id:"CO100",text:"I do not need the whole staircase lit to take the first stair.",cat:"Confidence"},
  {id:"CO101",text:"Confidence, for me, is keeping promises to myself in private.",cat:"Confidence"},
  {id:"CO102",text:"I am allowed to change my mind in public and call it growth.",cat:"Confidence"},
  {id:"CO103",text:"I introduce myself with my real ambitions now.",cat:"Confidence"},
  {id:"CO104",text:"Rejection redirects me. It has never once erased me.",cat:"Confidence"},
  {id:"CO105",text:"I stopped whispering my ideas. Whispered ideas get credited to louder people.",cat:"Confidence"},
  {id:"CO106",text:"I look like my own role model a little more every year.",cat:"Confidence"},
  {id:"CO107",text:"I let silence sit in conversations without rushing to fill it with apology.",cat:"Confidence"},
  {id:"CO108",text:"I trust myself to handle the outcome either way. That is the whole trick.",cat:"Confidence"},
  {id:"CO109",text:"I am more durable than my most anxious thought claims.",cat:"Confidence"},
  {id:"CO110",text:"My standards announce me before I enter.",cat:"Confidence"},
  {id:"CO111",text:"I take feedback seriously and insults not at all. I can tell them apart.",cat:"Confidence"},
  {id:"CO112",text:"The bravest sentence I own is: this is what I think.",cat:"Confidence"},
  {id:"CO113",text:"I have stopped treating confidence like a prize. It is a practice, and I practice.",cat:"Confidence"},
  {id:"CO114",text:"I am the author of my reputation with myself.",cat:"Confidence"},
  {id:"CO115",text:"I do not dim on purpose. If a room needs me dimmer, I need a different room.",cat:"Confidence"},
  {id:"CO116",text:"I walk toward the version of me that used to feel impossible.",cat:"Confidence"},
  {id:"CO117",text:"What other people think of me is their craft project, not my instruction manual.",cat:"Confidence"},
  {id:"CO118",text:"I am persuasive because I believe what I am saying.",cat:"Confidence"},
  {id:"CO119",text:"I claim my wins in the first person. I did that.",cat:"Confidence"},
  {id:"CO120",text:"Hesitation is a tax I am no longer willing to pay daily.",cat:"Confidence"},
  {id:"CO121",text:"I am calibrated, not arrogant — I know exactly what I am good at.",cat:"Confidence"},
  {id:"CO122",text:"I trust me. After everything we have been through, how could I not.",cat:"Confidence"},
  {id:"CO123",text:"I show up as the senior version of myself, even on junior-feeling days.",cat:"Confidence"},
  {id:"CO124",text:"My posture changed when I stopped carrying other people's doubts.",cat:"Confidence"},
  {id:"CO125",text:"I ask the obvious question. Half the room was hoping someone would.",cat:"Confidence"},
  {id:"CO126",text:"I am not for everyone, and that is a feature with excellent reviews.",cat:"Confidence"},
  {id:"CO127",text:"Every scar I carry is load-bearing. I am built different because of them.",cat:"Confidence"},
  {id:"CO128",text:"I negotiate like someone with alternatives, because I am someone who creates them.",cat:"Confidence"},
  {id:"CO129",text:"Fear of looking foolish has cost me enough. I have closed that account.",cat:"Confidence"},
  {id:"CO130",text:"I am exactly as capable on the days I forget it.",cat:"Confidence"},
  {id:"CO131",text:"I let my track record talk back to my anxiety.",cat:"Confidence"},
  {id:"CO132",text:"I do not require an invitation to take myself seriously.",cat:"Confidence"},
  {id:"CO133",text:"I correct people gently when they undersell me, including myself.",cat:"Confidence"},
  {id:"CO134",text:"Confidence is remembering that I have a vote — and casting it.",cat:"Confidence"},
  {id:"CO135",text:"I am at home in my own skin, even in rooms that feel foreign.",cat:"Confidence"},
  {id:"CO136",text:"The next level of my life requires the next level of my self-respect. I am leveling.",cat:"Confidence"},
  {id:"CO137",text:"I treat my goals like appointments, not like lottery tickets.",cat:"Confidence"},
  {id:"CO138",text:"My quiet days are not weakness. Even the sun sets daily.",cat:"Confidence"},
  {id:"CO139",text:"I take up exactly the amount of space the truth requires.",cat:"Confidence"},
  {id:"CO140",text:"I have evidence now. The doubt is arguing with receipts.",cat:"Confidence"},
  {id:"CO141",text:"I am unbothered by being a beginner because I have watched myself learn before.",cat:"Confidence"},
  {id:"CO142",text:"My ambition is allowed to be visible.",cat:"Confidence"},
  {id:"CO143",text:"I root for myself audibly, in my own head, all day long.",cat:"Confidence"},
  {id:"CO144",text:"What I call confidence is mostly just refusing to abandon myself in public.",cat:"Confidence"},
  {id:"CO145",text:"I am someone whose word means something — first to me, then to everyone.",cat:"Confidence"},
  {id:"CO146",text:"I stopped waiting to feel impressive and started doing impressive things.",cat:"Confidence"},
  {id:"CO147",text:"I meet powerful people as a peer in training.",cat:"Confidence"},
  {id:"CO148",text:"There is no committee. I approve my own choices.",cat:"Confidence"},
  {id:"CO149",text:"I trust my future to the person who got me this far. That person is me.",cat:"Confidence"},
  {id:"CO150",text:"Belief in myself is already mine. I just keep choosing to pick it up.",cat:"Confidence"},
  // HEALTH — expansion (HT050–HT149)
  {id:"HT050",text:"I move my body today because it is mine and it likes to be used.",cat:"Health"},
  {id:"HT051",text:"Health is the quiet engine under every dream I have. I maintain the engine.",cat:"Health"},
  {id:"HT052",text:"I am building a body I can live in for a long time, not look at for a season.",cat:"Health"},
  {id:"HT053",text:"Water, sunlight, movement, rest — the prescription is simple and I take it.",cat:"Health"},
  {id:"HT054",text:"I eat like someone who plans to feel good in three hours.",cat:"Health"},
  {id:"HT055",text:"My energy is a budget, and I have stopped funding what drains me.",cat:"Health"},
  {id:"HT056",text:"Rest is not a pause in my progress. It is part of the program.",cat:"Health"},
  {id:"HT057",text:"I take the stairs, the walk, the stretch — the small yeses add up.",cat:"Health"},
  {id:"HT058",text:"My body whispers before it shouts. I am learning to hear the whispers.",cat:"Health"},
  {id:"HT059",text:"Healing takes the time it takes, and I am not in its way anymore.",cat:"Health"},
  {id:"HT060",text:"I treat sleep like the appointment everything else depends on, because it is.",cat:"Health"},
  {id:"HT061",text:"My worth was never a number on a scale, a plate, or a label.",cat:"Health"},
  {id:"HT062",text:"I am stronger this month than last month, in ways that show and ways that matter more.",cat:"Health"},
  {id:"HT063",text:"Food is not a moral test. I eat with attention and move on.",cat:"Health"},
  {id:"HT064",text:"My nervous system deserves an environment it does not have to brace against.",cat:"Health"},
  {id:"HT065",text:"I breathe lower and slower, and my whole body takes the hint.",cat:"Health"},
  {id:"HT066",text:"I no longer wait for a scare to take my health seriously.",cat:"Health"},
  {id:"HT067",text:"Gentle is not the same as lazy. Some seasons call for gentle.",cat:"Health"},
  {id:"HT068",text:"I am the keeper of one irreplaceable body, and I keep it well.",cat:"Health"},
  {id:"HT069",text:"Movement is my antidepressant, my coffee, and my reset button.",cat:"Health"},
  {id:"HT070",text:"I stretch the stiffness of old stress out of my body, one morning at a time.",cat:"Health"},
  {id:"HT071",text:"My health habits are boring, repeatable, and quietly changing my life.",cat:"Health"},
  {id:"HT072",text:"I fuel before I demand. My body is not a machine that runs on pressure.",cat:"Health"},
  {id:"HT073",text:"Strong looks different on every body. Mine is getting stronger in its own shape.",cat:"Health"},
  {id:"HT074",text:"I keep my promises to my body — the walk, the water, the bedtime.",cat:"Health"},
  {id:"HT075",text:"A doctor's appointment is self-respect with a calendar entry.",cat:"Health"},
  {id:"HT076",text:"I am allowed to enjoy food without an internal court case.",cat:"Health"},
  {id:"HT077",text:"My body has carried me through every single day of my life undefeated.",cat:"Health"},
  {id:"HT078",text:"I cool my mind down the way I warm my body up — deliberately.",cat:"Health"},
  {id:"HT079",text:"Today's choices are votes for the body I will live in at eighty.",cat:"Health"},
  {id:"HT080",text:"I no longer call it working out. I call it keeping the lights on.",cat:"Health"},
  {id:"HT081",text:"Pain is information, not identity. I listen without becoming it.",cat:"Health"},
  {id:"HT082",text:"I protect my mornings because my whole day is downstream of them.",cat:"Health"},
  {id:"HT083",text:"My phone has a bedtime so that I can have one.",cat:"Health"},
  {id:"HT084",text:"I am patient with plateaus. The body consolidates before it climbs.",cat:"Health"},
  {id:"HT085",text:"Healing is happening in me right now, on a schedule I do not supervise.",cat:"Health"},
  {id:"HT086",text:"I take my mental health as seriously as a broken bone.",cat:"Health"},
  {id:"HT087",text:"My breath is the remote control for my whole system, and it is always in reach.",cat:"Health"},
  {id:"HT088",text:"I have stopped numbing what needs tending.",cat:"Health"},
  {id:"HT089",text:"Sweat is just stress leaving with an escort.",cat:"Health"},
  {id:"HT090",text:"I eat enough. Under-fueling was never discipline. It was a detour.",cat:"Health"},
  {id:"HT091",text:"The strongest thing I do for my body some days is go to bed early.",cat:"Health"},
  {id:"HT092",text:"I move at the speed of recovery, and I still arrive.",cat:"Health"},
  {id:"HT093",text:"I thank my body in actions — vegetables, sunlight, stillness, play.",cat:"Health"},
  {id:"HT094",text:"My energy returns as I return to myself.",cat:"Health"},
  {id:"HT095",text:"I am not too old to get stronger. Muscles do not check birth certificates.",cat:"Health"},
  {id:"HT096",text:"I keep one healthy promise even on the worst days. The thread never fully breaks.",cat:"Health"},
  {id:"HT097",text:"My home supports my health — the water visible, the shoes by the door.",cat:"Health"},
  {id:"HT098",text:"I am rebuilding my relationship with my body, and we are on speaking terms.",cat:"Health"},
  {id:"HT099",text:"Hunger and tiredness are signals, not character flaws.",cat:"Health"},
  {id:"HT100",text:"I exercise to feel powerful, and the feeling shows up before the mirror does.",cat:"Health"},
  {id:"HT101",text:"A little stillness every day keeps the spiral away. I take my stillness.",cat:"Health"},
  {id:"HT102",text:"I respect the season my body is in — and seasons change.",cat:"Health"},
  {id:"HT103",text:"My health is a relationship, not a project with a deadline.",cat:"Health"},
  {id:"HT104",text:"I leave the table satisfied, not stuffed and not starved. Balance is learnable.",cat:"Health"},
  {id:"HT105",text:"Every walk I take untangles something.",cat:"Health"},
  {id:"HT106",text:"I trust my body's pace over my mind's panic.",cat:"Health"},
  {id:"HT107",text:"The body keeps the score, so I give it good things to record.",cat:"Health"},
  {id:"HT108",text:"My check-ins with myself are short, honest, and daily — how am I, actually.",cat:"Health"},
  {id:"HT109",text:"I treat fatigue as a message, not a weakness to push through forever.",cat:"Health"},
  {id:"HT110",text:"I am more flexible than last year, in body and in spirit.",cat:"Health"},
  {id:"HT111",text:"Health is the wealth I refuse to gamble.",cat:"Health"},
  {id:"HT112",text:"I put my own oxygen mask on first, without apology.",cat:"Health"},
  {id:"HT113",text:"Recovery days build the strength that training days request.",cat:"Health"},
  {id:"HT114",text:"I feed my gut like the second brain it is.",cat:"Health"},
  {id:"HT115",text:"I am done with all-or-nothing. Something, consistently, is the whole secret.",cat:"Health"},
  {id:"HT116",text:"My medicine cabinet includes sunlight, friendship, and eight hours of dark.",cat:"Health"},
  {id:"HT117",text:"I unclench my jaw, drop my shoulders, and come back to now.",cat:"Health"},
  {id:"HT118",text:"I move through the world in a body I am learning to thank.",cat:"Health"},
  {id:"HT119",text:"Aging is a privilege I intend to do with strength and humor.",cat:"Health"},
  {id:"HT120",text:"My habits hold me on the days motivation calls in sick.",cat:"Health"},
  {id:"HT121",text:"I drink the water before the coffee and the difference is real.",cat:"Health"},
  {id:"HT122",text:"I give my mind a daily off-ramp — a walk, a page, a long exhale.",cat:"Health"},
  {id:"HT123",text:"I am healthier than I was, and I am not done.",cat:"Health"},
  {id:"HT124",text:"My body responds to consistency like a friend responds to loyalty.",cat:"Health"},
  {id:"HT125",text:"I schedule rest with the same seriousness I schedule work.",cat:"Health"},
  {id:"HT126",text:"Nothing about my body is a problem to apologize for.",cat:"Health"},
  {id:"HT127",text:"I lift, I walk, I stretch — not as punishment, but as maintenance on a life I love.",cat:"Health"},
  {id:"HT128",text:"The kitchen is where half my health is decided, and I decide it kindly.",cat:"Health"},
  {id:"HT129",text:"I let my body set the deadline for healing, and I stop negotiating.",cat:"Health"},
  {id:"HT130",text:"My baseline is rising — calmer mornings, steadier energy, deeper sleep.",cat:"Health"},
  {id:"HT131",text:"I take five slow breaths before I take anything personally.",cat:"Health"},
  {id:"HT132",text:"I am a good steward of my energy in a world that bids for it constantly.",cat:"Health"},
  {id:"HT133",text:"Health is not a look. It is how far I can walk into my own life.",cat:"Health"},
  {id:"HT134",text:"I keep showing up for the unglamorous middle of the process.",cat:"Health"},
  {id:"HT135",text:"My screens dim early so my mind can too.",cat:"Health"},
  {id:"HT136",text:"I honor my limits today so they can expand tomorrow.",cat:"Health"},
  {id:"HT137",text:"Strong heart, calm mind, honest plate — I build all three daily.",cat:"Health"},
  {id:"HT138",text:"I am gentle with my body in front of the mirror and generous with it everywhere else.",cat:"Health"},
  {id:"HT139",text:"Movement first, mood follows. I have tested this a hundred times.",cat:"Health"},
  {id:"HT140",text:"I quit the war with my body and we have both flourished since.",cat:"Health"},
  {id:"HT141",text:"My vitality is renewable, and rest is how it renews.",cat:"Health"},
  {id:"HT142",text:"I prepare for my health like I prepare for people I love — in advance, with care.",cat:"Health"},
  {id:"HT143",text:"The body I have today is the one that gets me to the body I want. We work together.",cat:"Health"},
  {id:"HT144",text:"I check in before I check out — one honest minute with myself daily.",cat:"Health"},
  {id:"HT145",text:"My health goals are acts of hope, and I am hopeful daily.",cat:"Health"},
  {id:"HT146",text:"Each morning my body and I agree to try again, and we do.",cat:"Health"},
  {id:"HT147",text:"I am building stamina for the life I am building.",cat:"Health"},
  {id:"HT148",text:"Wellness is not a destination I arrive at. It is a direction I keep walking.",cat:"Health"},
  {id:"HT149",text:"A strong, rested, well-tended body — that future is already mine, one day at a time.",cat:"Health"},
  // PEACE — expansion (PC050–PC149)
  {id:"PC050",text:"I answer chaos with a slower breath.",cat:"Peace"},
  {id:"PC051",text:"Not everything that demands my attention deserves it.",cat:"Peace"},
  {id:"PC052",text:"I leave room in my day for nothing, and the nothing restores me.",cat:"Peace"},
  {id:"PC053",text:"Peace is a practice I get better at, not a place I have to find.",cat:"Peace"},
  {id:"PC054",text:"I am allowed to respond tomorrow.",cat:"Peace"},
  {id:"PC055",text:"My calm is contagious, starting with the parts of me that are scared.",cat:"Peace"},
  {id:"PC056",text:"I close tabs — in my browser and in my mind.",cat:"Peace"},
  {id:"PC057",text:"The news will still be the news after I have slept.",cat:"Peace"},
  {id:"PC058",text:"I do not attend every argument I am invited to.",cat:"Peace"},
  {id:"PC059",text:"Stillness does not have to be earned by exhaustion.",cat:"Peace"},
  {id:"PC060",text:"I lower the stakes. Most of this is not an emergency.",cat:"Peace"},
  {id:"PC061",text:"I have a quiet place inside me and I know the way there.",cat:"Peace"},
  {id:"PC062",text:"What other people think of me is none of my business tonight.",cat:"Peace"},
  {id:"PC063",text:"I trade rumination for one small action, and the spell breaks.",cat:"Peace"},
  {id:"PC064",text:"My home is becoming a place where my shoulders drop.",cat:"Peace"},
  {id:"PC065",text:"I am safe in this exact moment, and this exact moment is all there is.",cat:"Peace"},
  {id:"PC066",text:"I let the unanswered email be unanswered until morning.",cat:"Peace"},
  {id:"PC067",text:"Peace is what I am when I stop auditioning for everyone.",cat:"Peace"},
  {id:"PC068",text:"I forgive the day for not going to plan. Neither did I, and we are fine.",cat:"Peace"},
  {id:"PC069",text:"I keep some of my life unphotographed and unexplained.",cat:"Peace"},
  {id:"PC070",text:"The calmest sentence I know is: that is not mine to fix.",cat:"Peace"},
  {id:"PC071",text:"I unhook from outcomes I have already done my part for.",cat:"Peace"},
  {id:"PC072",text:"My pace is legal. Slow is allowed.",cat:"Peace"},
  {id:"PC073",text:"I stop stirring and let the water settle. Clarity comes on its own.",cat:"Peace"},
  {id:"PC074",text:"Quiet mornings are my cathedral.",cat:"Peace"},
  {id:"PC075",text:"I make peace with the version of events I cannot edit.",cat:"Peace"},
  {id:"PC076",text:"I am no longer the manager of everyone's moods.",cat:"Peace"},
  {id:"PC077",text:"Tension is a question my body asks. Softness is my answer.",cat:"Peace"},
  {id:"PC078",text:"I subtract before I add — fewer commitments, fewer alarms, fewer opinions.",cat:"Peace"},
  {id:"PC079",text:"The mountain does not chase the weather. I am learning from the mountain.",cat:"Peace"},
  {id:"PC080",text:"I keep my peace in small bills — a breath here, a boundary there.",cat:"Peace"},
  {id:"PC081",text:"Today I will not rehearse arguments with people who are not in the room.",cat:"Peace"},
  {id:"PC082",text:"I welcome boredom back. It is where my best thoughts were hiding.",cat:"Peace"},
  {id:"PC083",text:"What I cannot control, I bless and release.",cat:"Peace"},
  {id:"PC084",text:"I am done sprinting through a life I claim to love.",cat:"Peace"},
  {id:"PC085",text:"Silence is a room I keep furnished for myself.",cat:"Peace"},
  {id:"PC086",text:"I let the phone ring sometimes. I am allowed to be unreachable.",cat:"Peace"},
  {id:"PC087",text:"Peace over performance. Presence over perfection. Today over someday.",cat:"Peace"},
  {id:"PC088",text:"I let people be wrong about me without filing an appeal.",cat:"Peace"},
  {id:"PC089",text:"My nervous system gets a say in my schedule now.",cat:"Peace"},
  {id:"PC090",text:"Calm is not indifference. I care deeply, slowly, and on purpose.",cat:"Peace"},
  {id:"PC091",text:"I end the day by setting everything down — I can pick it up tomorrow if it matters.",cat:"Peace"},
  {id:"PC092",text:"Worry borrows pain and pays interest. I am closing the account.",cat:"Peace"},
  {id:"PC093",text:"I am the calm I keep looking for in other people.",cat:"Peace"},
  {id:"PC094",text:"One thing at a time is not slow. It is how things actually get done.",cat:"Peace"},
  {id:"PC095",text:"I notice five things around me right now, and the spiral loses my address.",cat:"Peace"},
  {id:"PC096",text:"Inner peace is an inside job with excellent benefits.",cat:"Peace"},
  {id:"PC097",text:"I keep a sabbath of my own making — one stretch of every week that is mine.",cat:"Peace"},
  {id:"PC098",text:"I exhale longer than I inhale, and my body believes me that we are safe.",cat:"Peace"},
  {id:"PC099",text:"The to-do list is a tool, not a verdict.",cat:"Peace"},
  {id:"PC100",text:"I no longer confuse being busy with being valuable.",cat:"Peace"},
  {id:"PC101",text:"Peace arrived when I stopped arguing with reality and started working with it.",cat:"Peace"},
  {id:"PC102",text:"I give my worries a bedtime.",cat:"Peace"},
  {id:"PC103",text:"I am off duty from saving everyone.",cat:"Peace"},
  {id:"PC104",text:"Some doors I close softly, and the quiet behind them is the whole point.",cat:"Peace"},
  {id:"PC105",text:"I sip instead of scroll, stretch instead of stew, breathe instead of brace.",cat:"Peace"},
  {id:"PC106",text:"My thoughts are weather. I am the sky.",cat:"Peace"},
  {id:"PC107",text:"I do less, better, and the peace is in the better.",cat:"Peace"},
  {id:"PC108",text:"Nothing is missing from this moment except my attention. I bring it back.",cat:"Peace"},
  {id:"PC109",text:"I trust that what I set down in faith will be handled.",cat:"Peace"},
  {id:"PC110",text:"I am quieter inside than I used to be, and I built that.",cat:"Peace"},
  {id:"PC111",text:"Rest is not what I do after the work. It is what makes the work possible.",cat:"Peace"},
  {id:"PC112",text:"Today I let things be easy if they want to be.",cat:"Peace"},
  {id:"PC113",text:"I hold my plans loosely and my peace tightly.",cat:"Peace"},
  {id:"PC114",text:"Even now — especially now — I can begin again calmly.",cat:"Peace"},
  {id:"PC115",text:"I keep one corner of my life simple on purpose.",cat:"Peace"},
  {id:"PC116",text:"Other people's urgency is not my emergency.",cat:"Peace"},
  {id:"PC117",text:"I have stopped narrating worst cases like they are forecasts.",cat:"Peace"},
  {id:"PC118",text:"Peace is my default setting, and I keep finding my way back to it.",cat:"Peace"},
  {id:"PC119",text:"I leave gaps between things — between tasks, between words, between reactions.",cat:"Peace"},
  {id:"PC120",text:"Acceptance is not approval. It is just where my power begins.",cat:"Peace"},
  {id:"PC121",text:"I tend my mind like a garden — pulling worry, planting attention.",cat:"Peace"},
  {id:"PC122",text:"My boundaries are how peace pays rent in my life.",cat:"Peace"},
  {id:"PC123",text:"I take the scenic route on purpose sometimes.",cat:"Peace"},
  {id:"PC124",text:"When I do not know what to do, I wait — and waiting works.",cat:"Peace"},
  {id:"PC125",text:"I let good enough be good enough in the places that do not matter.",cat:"Peace"},
  {id:"PC126",text:"My breath has been with me since minute one. I lean on the oldest friend I have.",cat:"Peace"},
  {id:"PC127",text:"I declutter a drawer and somehow my mind exhales too.",cat:"Peace"},
  {id:"PC128",text:"Slow mornings, single tasks, soft attention — this is the luxury I can already afford.",cat:"Peace"},
  {id:"PC129",text:"I cancel the meeting with my inner critic. It never has new material.",cat:"Peace"},
  {id:"PC130",text:"I am where my feet are.",cat:"Peace"},
  {id:"PC131",text:"Patience is just trust with a longer timeline.",cat:"Peace"},
  {id:"PC132",text:"I dim my life's noise until I can hear my own wisdom again.",cat:"Peace"},
  {id:"PC133",text:"Today's only quota is presence.",cat:"Peace"},
  {id:"PC134",text:"I receive this ordinary day as the gift it quietly is.",cat:"Peace"},
  {id:"PC135",text:"Equanimity looks passive from the outside and feels like power from the inside.",cat:"Peace"},
  {id:"PC136",text:"I am finished apologizing for resting.",cat:"Peace"},
  {id:"PC137",text:"Peace does not require everyone's cooperation. Just mine.",cat:"Peace"},
  {id:"PC138",text:"I sit with the discomfort until it finishes its sentence, and then it leaves.",cat:"Peace"},
  {id:"PC139",text:"The world is loud, and I am allowed to be quiet in it.",cat:"Peace"},
  {id:"PC140",text:"I close the day with three good things, and the day closes gently.",cat:"Peace"},
  {id:"PC141",text:"Stillness is where my scattered pieces reassemble.",cat:"Peace"},
  {id:"PC142",text:"I trust the pauses in my life as much as the progress.",cat:"Peace"},
  {id:"PC143",text:"My peace is not fragile. It has been stress-tested.",cat:"Peace"},
  {id:"PC144",text:"I respond from my values, not from my adrenaline.",cat:"Peace"},
  {id:"PC145",text:"There is no rush. There never was. The rushing was a habit, and habits change.",cat:"Peace"},
  {id:"PC146",text:"I am the thermostat of my home, not the thermometer.",cat:"Peace"},
  {id:"PC147",text:"I keep a pocket of calm that no schedule can confiscate.",cat:"Peace"},
  {id:"PC148",text:"I finish what the day asks and leave the rest to tomorrow without guilt.",cat:"Peace"},
  {id:"PC149",text:"Peace is already mine. I stop searching and start settling into it.",cat:"Peace"},
  // CAREER — expansion (CR050–CR149)
  {id:"CR050",text:"I do today's work at the level of tomorrow's role.",cat:"Career"},
  {id:"CR051",text:"My craft compounds. Every focused hour is interest earned.",cat:"Career"},
  {id:"CR052",text:"I am allowed to be ambitious without an apology attached.",cat:"Career"},
  {id:"CR053",text:"The market rewards clarity, and I am getting clearer about what I offer.",cat:"Career"},
  {id:"CR054",text:"I finish things. In a world of starters, that is a superpower.",cat:"Career"},
  {id:"CR055",text:"My career is a body of work, not a single make-or-break moment.",cat:"Career"},
  {id:"CR056",text:"I raise my hand for the assignment that scares me a little.",cat:"Career"},
  {id:"CR057",text:"I work with the door open to luck and the calendar closed to chaos.",cat:"Career"},
  {id:"CR058",text:"Rejection means I am in the arena, swinging.",cat:"Career"},
  {id:"CR059",text:"I document my wins because memory is modest and reviews are not.",cat:"Career"},
  {id:"CR060",text:"The job I want is being prepared for by the job I have.",cat:"Career"},
  {id:"CR061",text:"I send the pitch. The worst case is the silence I already live in.",cat:"Career"},
  {id:"CR062",text:"My reputation is built in the small moments nobody is grading.",cat:"Career"},
  {id:"CR063",text:"I solve problems out loud, and the right people keep noticing.",cat:"Career"},
  {id:"CR064",text:"I am paid for the years it took, not the minutes it takes.",cat:"Career"},
  {id:"CR065",text:"Meetings end, politics shift, but the work I shipped remains.",cat:"Career"},
  {id:"CR066",text:"I choose mentors who are where I am going, not where I am stuck.",cat:"Career"},
  {id:"CR067",text:"I am building a name that opens doors when I am not in the room.",cat:"Career"},
  {id:"CR068",text:"Done well and shipped beats perfect and pending.",cat:"Career"},
  {id:"CR069",text:"I treat Monday like an opportunity with my name on it.",cat:"Career"},
  {id:"CR070",text:"My side project is allowed to become my main story.",cat:"Career"},
  {id:"CR071",text:"I ask better questions, and better questions are most of the job.",cat:"Career"},
  {id:"CR072",text:"I out-care the competition. It is the most sustainable advantage I have.",cat:"Career"},
  {id:"CR073",text:"I am one good relationship away from the next chapter, and I invest in people honestly.",cat:"Career"},
  {id:"CR074",text:"I leave jobs, not bridges.",cat:"Career"},
  {id:"CR075",text:"My value walks in with me and leaves with me. Employers rent it. I own it.",cat:"Career"},
  {id:"CR076",text:"I speak in outcomes, not effort, and my work gets the credit it earns.",cat:"Career"},
  {id:"CR077",text:"I am the colleague I would want to work beside.",cat:"Career"},
  {id:"CR078",text:"Burnout is not a badge. I build a career that can hold a whole life.",cat:"Career"},
  {id:"CR079",text:"I learn in public and let the compounding work.",cat:"Career"},
  {id:"CR080",text:"I respect my own hours. Boundaries make my work better, not smaller.",cat:"Career"},
  {id:"CR081",text:"I take the meeting even when I feel unready. Ready is built in the room.",cat:"Career"},
  {id:"CR082",text:"My career path looks crooked on paper and perfect in hindsight.",cat:"Career"},
  {id:"CR083",text:"I price my work on the value delivered, not on my own nervousness.",cat:"Career"},
  {id:"CR084",text:"I will be glad I started today. So I start today.",cat:"Career"},
  {id:"CR085",text:"I am not too old, too early, too niche, or too late. I am available and skilled.",cat:"Career"},
  {id:"CR086",text:"I keep a folder of kind words about my work, and I believe it on hard days.",cat:"Career"},
  {id:"CR087",text:"I make my boss's job easier and my own future bigger.",cat:"Career"},
  {id:"CR088",text:"I choose problems worth years of my attention.",cat:"Career"},
  {id:"CR089",text:"The skill I am avoiding learning is the door I am avoiding opening.",cat:"Career"},
  {id:"CR090",text:"I am a finisher of courses, a shipper of projects, and a keeper of momentum.",cat:"Career"},
  {id:"CR091",text:"I network by being useful. It has never once felt false that way.",cat:"Career"},
  {id:"CR092",text:"My calendar reflects my ambitions, not just my obligations.",cat:"Career"},
  {id:"CR093",text:"I bring solutions and a spine to every difficult conversation.",cat:"Career"},
  {id:"CR094",text:"Recognition finds me faster now that I stopped hiding in over-preparation.",cat:"Career"},
  {id:"CR095",text:"I plant my flag in my niche and let depth do the marketing.",cat:"Career"},
  {id:"CR096",text:"The promotion is a lagging indicator. The growth already happened.",cat:"Career"},
  {id:"CR097",text:"I am durable in downturns. Skills compound in every economy.",cat:"Career"},
  {id:"CR098",text:"I write things down, follow through, and circle back — rare and remembered.",cat:"Career"},
  {id:"CR099",text:"My work funds my life. My life is not a donation to my work.",cat:"Career"},
  {id:"CR100",text:"I lead from where I am. Title is paperwork.",cat:"Career"},
  {id:"CR101",text:"I let my curiosity pick my next skill, and my curiosity has good taste.",cat:"Career"},
  {id:"CR102",text:"Feedback is free coaching. I take notes.",cat:"Career"},
  {id:"CR103",text:"I show my numbers in negotiations and let them argue for me.",cat:"Career"},
  {id:"CR104",text:"I quit projects that are going nowhere with the same courage I start ones that might.",cat:"Career"},
  {id:"CR105",text:"My ten-year vision survives bad quarters.",cat:"Career"},
  {id:"CR106",text:"I make fewer, bigger promises, and I keep them all.",cat:"Career"},
  {id:"CR107",text:"I am the person they call when it actually matters.",cat:"Career"},
  {id:"CR108",text:"Visibility is part of the job. I stopped treating it as bragging.",cat:"Career"},
  {id:"CR109",text:"I build assets — skills, relationships, work in public — that no layoff can repossess.",cat:"Career"},
  {id:"CR110",text:"I take the vacation. The work is better when I return, and so am I.",cat:"Career"},
  {id:"CR111",text:"I read the contract, ask the awkward question, and protect my own interests calmly.",cat:"Career"},
  {id:"CR112",text:"Every expert I admire was once exactly this confused. I keep going.",cat:"Career"},
  {id:"CR113",text:"I am building work I do not need to escape from.",cat:"Career"},
  {id:"CR114",text:"I let go of the career my twenties planned and claim the one my values choose.",cat:"Career"},
  {id:"CR115",text:"My standards do the negotiating before I say a word.",cat:"Career"},
  {id:"CR116",text:"I focus on the next right project, and the ladder assembles itself.",cat:"Career"},
  {id:"CR117",text:"I am paid in money, skills, and stories — and I make sure every job pays in at least two.",cat:"Career"},
  {id:"CR118",text:"The blank document is not a judgment. It is an offer.",cat:"Career"},
  {id:"CR119",text:"I follow up. Fortunes live in the follow-up.",cat:"Career"},
  {id:"CR120",text:"I have stopped waiting to feel like an expert before acting like a professional.",cat:"Career"},
  {id:"CR121",text:"I would hire me — and I keep building the case.",cat:"Career"},
  {id:"CR122",text:"My ambition has a long memory and a patient strategy.",cat:"Career"},
  {id:"CR123",text:"I choose the room where I am learning over the room where I am comfortable.",cat:"Career"},
  {id:"CR124",text:"I deliver early when it is easy and communicate early when it is not.",cat:"Career"},
  {id:"CR125",text:"I do not need everyone to understand my path. I need to walk it well.",cat:"Career"},
  {id:"CR126",text:"I keep my résumé honest and my skills ahead of it.",cat:"Career"},
  {id:"CR127",text:"Purpose is not found. It is built — project by project, deliberately.",cat:"Career"},
  {id:"CR128",text:"I let small wins count. Careers are made of Tuesdays.",cat:"Career"},
  {id:"CR129",text:"I am allowed to want both meaning and money. I am building both.",cat:"Career"},
  {id:"CR130",text:"I treat my energy as my most important professional asset.",cat:"Career"},
  {id:"CR131",text:"I make decisions my future self will brag about surviving.",cat:"Career"},
  {id:"CR132",text:"I retired my fear of the word no. It is just a routing instruction.",cat:"Career"},
  {id:"CR133",text:"Someone needs exactly what I make, made exactly the way I make it.",cat:"Career"},
  {id:"CR134",text:"I stay teachable at every level. Mastery has no graduation.",cat:"Career"},
  {id:"CR135",text:"The work I am proud of started as work I was scared of.",cat:"Career"},
  {id:"CR136",text:"I own my mistakes fast, fix them faster, and my credibility grows from it.",cat:"Career"},
  {id:"CR137",text:"I clock my progress in years, not weeks, and the chart only climbs.",cat:"Career"},
  {id:"CR138",text:"I am the constant in my career — every market, every team, every season.",cat:"Career"},
  {id:"CR139",text:"I draft the email, the deck, the plan — drafts become careers.",cat:"Career"},
  {id:"CR140",text:"I do deep work in a distracted world, and it shows.",cat:"Career"},
  {id:"CR141",text:"I treat junior colleagues the way I wished seniors had treated me.",cat:"Career"},
  {id:"CR142",text:"My ceiling is decided by my habits, not my doubts.",cat:"Career"},
  {id:"CR143",text:"I have stopped applying a discount to my own labor.",cat:"Career"},
  {id:"CR144",text:"The next opportunity will find me mid-motion, not waiting.",cat:"Career"},
  {id:"CR145",text:"I am more interested in being excellent than in being noticed — and excellence gets noticed.",cat:"Career"},
  {id:"CR146",text:"I navigate office storms with a long view and a short memory.",cat:"Career"},
  {id:"CR147",text:"I build the body of work first. The title catches up.",cat:"Career"},
  {id:"CR148",text:"Work that matters, pay that respects, hours that allow a life — I am building all three.",cat:"Career"},
  {id:"CR149",text:"The career I keep imagining is already mine in draft form. I am editing it into existence.",cat:"Career"},
  // HEALING — expansion (HL049–HL148)
  {id:"HL049",text:"I am healing in the same rooms where the wounding happened — quietly, daily, for real.",cat:"Healing"},
  {id:"HL050",text:"My softness coming back is the surest sign the worst is over.",cat:"Healing"},
  {id:"HL051",text:"I do not owe anyone a faster recovery.",cat:"Healing"},
  {id:"HL052",text:"Grief is love with nowhere to go, and I am building it somewhere to live.",cat:"Healing"},
  {id:"HL053",text:"I tell the truth about what happened, at least to myself, and the truth lightens.",cat:"Healing"},
  {id:"HL054",text:"Some days healing looks like dishes done and a shower taken. Those days count double.",cat:"Healing"},
  {id:"HL055",text:"I am allowed to remember it differently than the people who hurt me.",cat:"Healing"},
  {id:"HL056",text:"The flinch is fading. I notice it fading and I am proud.",cat:"Healing"},
  {id:"HL057",text:"I sit with my younger self often. We are getting along better than ever.",cat:"Healing"},
  {id:"HL058",text:"What I needed and did not get, I am learning to give myself without bitterness.",cat:"Healing"},
  {id:"HL059",text:"I let the anger speak until it tells me what it was protecting.",cat:"Healing"},
  {id:"HL060",text:"Healing rearranged my friendships, and the ones that remain are real.",cat:"Healing"},
  {id:"HL061",text:"I have stopped reopening old conversations to check if they still hurt.",cat:"Healing"},
  {id:"HL062",text:"My body is unlearning the brace, one safe day at a time.",cat:"Healing"},
  {id:"HL063",text:"Therapy is not a confession of weakness. It is training with a guide.",cat:"Healing"},
  {id:"HL064",text:"I am someone who stayed, who tried, who got back up. The record shows it.",cat:"Healing"},
  {id:"HL065",text:"Closure is something I give myself. I have stopped waiting for it in the mail.",cat:"Healing"},
  {id:"HL066",text:"I speak about my past in past tense now, and the grammar is the healing.",cat:"Healing"},
  {id:"HL067",text:"Triggers are flare-ups, not relapses. I tend them and continue.",cat:"Healing"},
  {id:"HL068",text:"I am not what was done to me. I am what I chose afterward.",cat:"Healing"},
  {id:"HL069",text:"Forgiveness, when I get there, will be for my own lightness — and I am allowed to take years.",cat:"Healing"},
  {id:"HL070",text:"I cried today and it watered something.",cat:"Healing"},
  {id:"HL071",text:"I no longer mistake numbness for strength.",cat:"Healing"},
  {id:"HL072",text:"My healing inconveniences people who benefited from my brokenness. I heal anyway.",cat:"Healing"},
  {id:"HL073",text:"I let joy back in without interrogating it at the door.",cat:"Healing"},
  {id:"HL074",text:"I keep small promises to myself, and trust regrows like grass.",cat:"Healing"},
  {id:"HL075",text:"The grip of old nightmares is loosening. Even my sleep is learning safety.",cat:"Healing"},
  {id:"HL076",text:"I tell my story without bleeding now. It has scarred over into wisdom.",cat:"Healing"},
  {id:"HL077",text:"I am gentle with the part of me that still waits for the other shoe.",cat:"Healing"},
  {id:"HL078",text:"What broke my heart is slowly becoming what built my depth.",cat:"Healing"},
  {id:"HL079",text:"I am allowed to outgrow my coping mechanisms with gratitude, not shame.",cat:"Healing"},
  {id:"HL080",text:"The body that survived deserves better than my criticism.",cat:"Healing"},
  {id:"HL081",text:"I unpack the heaviest box in my own time.",cat:"Healing"},
  {id:"HL082",text:"My laugh came back this year. I noticed, and I celebrated quietly.",cat:"Healing"},
  {id:"HL083",text:"I am living proof that the worst day was not the last day.",cat:"Healing"},
  {id:"HL084",text:"Recovery is not a straight line. It is a spiral that keeps rising.",cat:"Healing"},
  {id:"HL085",text:"I stopped asking why me and started asking what now — and everything shifted.",cat:"Healing"},
  {id:"HL086",text:"I am safe enough now to feel what I could not afford to feel then.",cat:"Healing"},
  {id:"HL087",text:"Peace with my past is a treaty I negotiate clause by clause.",cat:"Healing"},
  {id:"HL088",text:"I give my pain a pen sometimes, and the page holds what I cannot.",cat:"Healing"},
  {id:"HL089",text:"Being loved well now does not betray the person who survived being loved badly.",cat:"Healing"},
  {id:"HL090",text:"I am done carrying apologies that were never given to me.",cat:"Healing"},
  {id:"HL091",text:"My sensitivity survived. That means I won.",cat:"Healing"},
  {id:"HL092",text:"Healing made me quieter, kinder, and impossible to fool.",cat:"Healing"},
  {id:"HL093",text:"I rest without earning it, because exhaustion was part of the wound.",cat:"Healing"},
  {id:"HL094",text:"The child I was is finally getting a childhood through the life I live now.",cat:"Healing"},
  {id:"HL095",text:"I let the memories visit without letting them move back in.",cat:"Healing"},
  {id:"HL096",text:"My scars are mine — proof of repair, not evidence of damage.",cat:"Healing"},
  {id:"HL097",text:"I needed more time than expected, and I gave it to myself. That was love.",cat:"Healing"},
  {id:"HL098",text:"I am relearning trust at the pace trust actually grows.",cat:"Healing"},
  {id:"HL099",text:"I do not have to repeat the family pattern just because I was raised in it.",cat:"Healing"},
  {id:"HL100",text:"Today I choose repair — with myself first.",cat:"Healing"},
  {id:"HL101",text:"Grieving openly is the most honest thing I do.",cat:"Healing"},
  {id:"HL102",text:"I am allowed to feel two things at once. Healing is mostly that.",cat:"Healing"},
  {id:"HL103",text:"I lost a version of my life and grew another one. Both deserve acknowledgment.",cat:"Healing"},
  {id:"HL104",text:"The hypervigilance is retiring. It served, and now it can rest.",cat:"Healing"},
  {id:"HL105",text:"I answer my own 3 a.m. thoughts with the kindness of a good friend.",cat:"Healing"},
  {id:"HL106",text:"What I went through gave me a deep sight for other people's pain. I use it gently.",cat:"Healing"},
  {id:"HL107",text:"I am off the hook for how I survived.",cat:"Healing"},
  {id:"HL108",text:"I release the fantasy of the apology and keep the reality of my freedom.",cat:"Healing"},
  {id:"HL109",text:"Healing smells like clean sheets, sounds like my own music, feels like mornings without dread.",cat:"Healing"},
  {id:"HL110",text:"I am not difficult. I am healing in a world that wanted me convenient.",cat:"Healing"},
  {id:"HL111",text:"I check the locks once now, not five times. Progress is concrete.",cat:"Healing"},
  {id:"HL112",text:"I have stopped abandoning myself to keep the peace.",cat:"Healing"},
  {id:"HL113",text:"My heart was broken open, not just broken. More fits inside it now.",cat:"Healing"},
  {id:"HL114",text:"The story I tell about my pain is mine to edit, and I write a survivor, not a victim.",cat:"Healing"},
  {id:"HL115",text:"I let people earn their way back, or not. Both outcomes heal me.",cat:"Healing"},
  {id:"HL116",text:"I am the safe adult my younger self kept hoping would show up.",cat:"Healing"},
  {id:"HL117",text:"Feeling better scared me at first. I am letting it become familiar.",cat:"Healing"},
  {id:"HL118",text:"I do the grief work so it does not become my children's inheritance.",cat:"Healing"},
  {id:"HL119",text:"I am tender where I was torn, and tender is healing's texture.",cat:"Healing"},
  {id:"HL120",text:"One honest conversation at a time, I am taking my life back.",cat:"Healing"},
  {id:"HL121",text:"I no longer perform being okay. I am becoming okay, which is slower and real.",cat:"Healing"},
  {id:"HL122",text:"The past knocks less often now, and I am not obligated to answer.",cat:"Healing"},
  {id:"HL123",text:"I survived on instinct. I am living now on intention.",cat:"Healing"},
  {id:"HL124",text:"My healing has a witness — me. I see every invisible inch of it.",cat:"Healing"},
  {id:"HL125",text:"I put down the case I was building against myself.",cat:"Healing"},
  {id:"HL126",text:"Health returned to my body when honesty returned to my life.",cat:"Healing"},
  {id:"HL127",text:"I am allowed to be happy before everything is resolved.",cat:"Healing"},
  {id:"HL128",text:"The weight I carried was never mine. Setting it down is not quitting. It is justice.",cat:"Healing"},
  {id:"HL129",text:"I let love be slow and boring and safe, and it is healing me.",cat:"Healing"},
  {id:"HL130",text:"I parent my panic with patience now, and it settles faster every time.",cat:"Healing"},
  {id:"HL131",text:"What I numbed, I am now naming. Named things lose their teeth.",cat:"Healing"},
  {id:"HL132",text:"I came back for myself. That is the whole story, and it is a good one.",cat:"Healing"},
  {id:"HL133",text:"Even my setbacks happen inside a bigger recovery.",cat:"Healing"},
  {id:"HL134",text:"I am not fragile. I am newly mended and appropriately careful.",cat:"Healing"},
  {id:"HL135",text:"The mirror gets kinder as I do.",cat:"Healing"},
  {id:"HL136",text:"I make peace with the years I lost by fully living the ones I have.",cat:"Healing"},
  {id:"HL137",text:"My boundaries are scar tissue that learned to speak.",cat:"Healing"},
  {id:"HL138",text:"I trust my no now. It was expensive to learn and it protects everything.",cat:"Healing"},
  {id:"HL139",text:"Some endings deserved grief I never gave them. I am giving it now, and it frees me.",cat:"Healing"},
  {id:"HL140",text:"I am whole in progress.",cat:"Healing"},
  {id:"HL141",text:"My nervous system believes in safety again, one calm evening at a time.",cat:"Healing"},
  {id:"HL142",text:"I tell someone the hard thing, and the shame loses its lease.",cat:"Healing"},
  {id:"HL143",text:"Healing gave me back my future. I intend to use all of it.",cat:"Healing"},
  {id:"HL144",text:"I am gentle, I am honest, I am healing — all three at once, every day.",cat:"Healing"},
  {id:"HL145",text:"The pain was real. So is the repair. I hold both without contradiction.",cat:"Healing"},
  {id:"HL146",text:"I stopped waiting to feel ready to live and started living my way to ready.",cat:"Healing"},
  {id:"HL147",text:"Every soft morning I build is evidence the war is over.",cat:"Healing"},
  {id:"HL148",text:"Wholeness is already mine. I am just clearing the path back to it.",cat:"Healing"},
  // COURAGE — expansion (CG047–CG146)
  {id:"CG047",text:"I make the call I have been circling for a week.",cat:"Courage"},
  {id:"CG048",text:"Bravery, for me, is mostly done quietly and before breakfast.",cat:"Courage"},
  {id:"CG049",text:"I am willing to be bad at this until I am good at it.",cat:"Courage"},
  {id:"CG050",text:"The fear gets a seat, not a steering wheel.",cat:"Courage"},
  {id:"CG051",text:"I would rather hear no than wonder forever.",cat:"Courage"},
  {id:"CG052",text:"Courage is a muscle, and today is a rep.",cat:"Courage"},
  {id:"CG053",text:"I tell the truth one size sooner than feels comfortable.",cat:"Courage"},
  {id:"CG054",text:"Risk looks smaller from the other side. I cross.",cat:"Courage"},
  {id:"CG055",text:"I sign up before I talk myself out of it.",cat:"Courage"},
  {id:"CG056",text:"The dream is worth embarrassing myself a few times.",cat:"Courage"},
  {id:"CG057",text:"I am done waiting for fearless. Fearless is fiction. Willing is real.",cat:"Courage"},
  {id:"CG058",text:"I ask the question everyone is quietly carrying.",cat:"Courage"},
  {id:"CG059",text:"I leap with a plan and a backup, but I leap.",cat:"Courage"},
  {id:"CG060",text:"I disappoint people sometimes, and the sky stays up.",cat:"Courage"},
  {id:"CG061",text:"Standing alone on something true beats kneeling in agreement.",cat:"Courage"},
  {id:"CG062",text:"I knock on doors that look closed. Half of them were just unlocked.",cat:"Courage"},
  {id:"CG063",text:"Every brave act buys back territory from my anxiety.",cat:"Courage"},
  {id:"CG064",text:"I let myself be seen trying.",cat:"Courage"},
  {id:"CG065",text:"My voice shook and I said it anyway. That is the whole skill.",cat:"Courage"},
  {id:"CG066",text:"The first step costs the most courage. I pay it, and the rest is cheaper.",cat:"Courage"},
  {id:"CG067",text:"I keep promises that frighten me.",cat:"Courage"},
  {id:"CG068",text:"I have stopped rehearsing and started performing my own life.",cat:"Courage"},
  {id:"CG069",text:"Brave is a thing I do, not a thing I wait to feel.",cat:"Courage"},
  {id:"CG070",text:"I face the bill, the diagnosis, the inbox — facing things shrinks them.",cat:"Courage"},
  {id:"CG071",text:"I quit what everyone praised because it was quietly wrong for me.",cat:"Courage"},
  {id:"CG072",text:"Today I do one thing my comfort zone advises against.",cat:"Courage"},
  {id:"CG073",text:"I trust my legs to hold me in rooms that intimidate me.",cat:"Courage"},
  {id:"CG074",text:"The fear of starting is always bigger than the start.",cat:"Courage"},
  {id:"CG075",text:"I send the work out into the world unguarded.",cat:"Courage"},
  {id:"CG076",text:"I have been afraid and effective at the same time my whole life.",cat:"Courage"},
  {id:"CG077",text:"My courage does not roar today. It fills out the form. It books the appointment.",cat:"Courage"},
  {id:"CG078",text:"I tell people what I actually want. Mind reading was a bad system.",cat:"Courage"},
  {id:"CG079",text:"I walk toward the awkward conversation while it is still small.",cat:"Courage"},
  {id:"CG080",text:"Daring is contagious, and I infect my own life first.",cat:"Courage"},
  {id:"CG081",text:"I take the stage knowing the worst review cannot unmake me.",cat:"Courage"},
  {id:"CG082",text:"I retire the script of who I was supposed to be.",cat:"Courage"},
  {id:"CG083",text:"I hold my position under pressure when the position is true.",cat:"Courage"},
  {id:"CG084",text:"I open the letter. I read the results. I face real things in real time.",cat:"Courage"},
  {id:"CG085",text:"Courage compounds. Every small brave makes the next one cheaper.",cat:"Courage"},
  {id:"CG086",text:"I go first in giving the honest answer.",cat:"Courage"},
  {id:"CG087",text:"What I avoid grows teeth. What I face loses them.",cat:"Courage"},
  {id:"CG088",text:"I am braver than my folder of unsent drafts suggests. Today I send.",cat:"Courage"},
  {id:"CG089",text:"I choose discomfort on my terms before life assigns it on its own.",cat:"Courage"},
  {id:"CG090",text:"I un-quit the dream I shelved to seem realistic.",cat:"Courage"},
  {id:"CG091",text:"I let the silence after my honesty be the other person's work.",cat:"Courage"},
  {id:"CG092",text:"I show up to the audition, the interview, the open mic — presence is the prerequisite of luck.",cat:"Courage"},
  {id:"CG093",text:"I would rather build my own thing badly than polish someone else's forever.",cat:"Courage"},
  {id:"CG094",text:"Fear is excitement holding its breath. I exhale and begin.",cat:"Courage"},
  {id:"CG095",text:"I take the trip alone. I have always been good company.",cat:"Courage"},
  {id:"CG096",text:"I confront with care — the issue, not the person — and my relationships survive me.",cat:"Courage"},
  {id:"CG097",text:"My future self is watching today with hope. I act worthy of the audience.",cat:"Courage"},
  {id:"CG098",text:"I do it scared, do it imperfect, do it now — the doing is the point.",cat:"Courage"},
  {id:"CG099",text:"I unmute myself, in meetings and in life.",cat:"Courage"},
  {id:"CG100",text:"I bet on myself at decent odds. I have inside information.",cat:"Courage"},
  {id:"CG101",text:"I survived the thing I feared most, and now fear has lost its best argument.",cat:"Courage"},
  {id:"CG102",text:"I ask for the extension, the discount, the help — asking is free.",cat:"Courage"},
  {id:"CG103",text:"I leave safety that is actually stagnation wearing a costume.",cat:"Courage"},
  {id:"CG104",text:"My boldest choices have aged the best. I remember that when choosing.",cat:"Courage"},
  {id:"CG105",text:"I let go of the railing on purpose, briefly, daily.",cat:"Courage"},
  {id:"CG106",text:"I publish, post, and press send — visibility is the tax on impact, and I pay it.",cat:"Courage"},
  {id:"CG107",text:"The hard email takes four minutes. The dread took four days. I choose the minutes.",cat:"Courage"},
  {id:"CG108",text:"I tell my people what I am attempting so the attempt becomes real.",cat:"Courage"},
  {id:"CG109",text:"I am the descendant of people who crossed things. Crossing is in me.",cat:"Courage"},
  {id:"CG110",text:"I make eye contact with what scares me until it blinks.",cat:"Courage"},
  {id:"CG111",text:"I volunteer for the thing that stretches me in front of people.",cat:"Courage"},
  {id:"CG112",text:"I stand where my values stand, even when the room shuffles away.",cat:"Courage"},
  {id:"CG113",text:"Doubt knocks. Courage answers the door, takes the message, and gets back to work.",cat:"Courage"},
  {id:"CG114",text:"I spend my nerve on things that matter.",cat:"Courage"},
  {id:"CG115",text:"I begin in public. The accountability is the architecture.",cat:"Courage"},
  {id:"CG116",text:"I trade the comfort of maybe someday for the risk of an actual attempt.",cat:"Courage"},
  {id:"CG117",text:"I am qualified for this leap by every fall I have survived.",cat:"Courage"},
  {id:"CG118",text:"I say it plainly: I want this. Wanting out loud is brave.",cat:"Courage"},
  {id:"CG119",text:"I let rejection be the receipt for a real attempt.",cat:"Courage"},
  {id:"CG120",text:"I out-stubborn my fear on the days I cannot out-reason it.",cat:"Courage"},
  {id:"CG121",text:"I have a high tolerance for the discomfort of becoming.",cat:"Courage"},
  {id:"CG122",text:"Today I open the document, the savings account, the conversation — open is half of brave.",cat:"Courage"},
  {id:"CG123",text:"I face forward. Whatever chases me will have to deal with my momentum.",cat:"Courage"},
  {id:"CG124",text:"The brave thing and the kind thing are usually the same thing. I do that one.",cat:"Courage"},
  {id:"CG125",text:"I dare to be seen mid-process, unfinished and improving.",cat:"Courage"},
  {id:"CG126",text:"I cut the rope on the anchor dressed as a security blanket.",cat:"Courage"},
  {id:"CG127",text:"I stopped asking for the odds and started asking for the address.",cat:"Courage"},
  {id:"CG128",text:"Courage is loyalty to my future under pressure from my present.",cat:"Courage"},
  {id:"CG129",text:"I take the meeting with no script and trust the prepared version of me to show up.",cat:"Courage"},
  {id:"CG130",text:"I withstand being misjudged while I do the slow, right thing.",cat:"Courage"},
  {id:"CG131",text:"I name my actual rate, my actual needs, my actual ambitions.",cat:"Courage"},
  {id:"CG132",text:"I move first and explain later when the moment demands it.",cat:"Courage"},
  {id:"CG133",text:"I let the people I love see me attempt hard things and survive the misses.",cat:"Courage"},
  {id:"CG134",text:"The version of me who hesitated has been promoted to the version who decides.",cat:"Courage"},
  {id:"CG135",text:"I treat fear like weather — noted, dressed for, and walked through.",cat:"Courage"},
  {id:"CG136",text:"I keep one brave promise per day, and my life keeps enlarging.",cat:"Courage"},
  {id:"CG137",text:"I look back only to measure how far — never to retreat.",cat:"Courage"},
  {id:"CG138",text:"I deliver hard news with a soft voice and a straight spine.",cat:"Courage"},
  {id:"CG139",text:"I dare to take up the dream-sized space my plans require.",cat:"Courage"},
  {id:"CG140",text:"What I am building requires nerve, and I have located mine.",cat:"Courage"},
  {id:"CG141",text:"I run my own experiment instead of waiting for someone else's results.",cat:"Courage"},
  {id:"CG142",text:"I have rejected the quiet life of unopened doors.",cat:"Courage"},
  {id:"CG143",text:"Courage fits me better every time I wear it.",cat:"Courage"},
  {id:"CG144",text:"I step into the unknown like it owes me something — because it does.",cat:"Courage"},
  {id:"CG145",text:"I am afraid of less than last year, and next year the list shrinks again.",cat:"Courage"},
  {id:"CG146",text:"The bold life is already mine. I claim another inch of it today.",cat:"Courage"},
  // NEW BEGINNINGS — expansion (NB046–NB145)
  {id:"NB046",text:"Today is unwritten, and I am holding the pen.",cat:"New Beginnings"},
  {id:"NB047",text:"I begin before the fear finishes its argument.",cat:"New Beginnings"},
  {id:"NB048",text:"New city, new habit, new heart — I have started over before and bloomed every time.",cat:"New Beginnings"},
  {id:"NB049",text:"The first awkward week is the price of every great chapter.",cat:"New Beginnings"},
  {id:"NB050",text:"I bless what ended. It made room.",cat:"New Beginnings"},
  {id:"NB051",text:"I am new here, and new is allowed to ask questions.",cat:"New Beginnings"},
  {id:"NB052",text:"Every sunrise is the universe modeling how to begin again without apology.",cat:"New Beginnings"},
  {id:"NB053",text:"I leave the keys to the old life in the old life.",cat:"New Beginnings"},
  {id:"NB054",text:"Fresh starts do not require permission slips.",cat:"New Beginnings"},
  {id:"NB055",text:"I am early in something that will one day feel inevitable.",cat:"New Beginnings"},
  {id:"NB056",text:"The empty calendar is not a void. It is a canvas.",cat:"New Beginnings"},
  {id:"NB057",text:"I carry forward the lessons and leave behind the labels.",cat:"New Beginnings"},
  {id:"NB058",text:"Beginning again is not regression. It is iteration.",cat:"New Beginnings"},
  {id:"NB059",text:"I introduce myself as who I am becoming.",cat:"New Beginnings"},
  {id:"NB060",text:"The chapter ended mid-sentence, and I am allowed to write a better one.",cat:"New Beginnings"},
  {id:"NB061",text:"What I am starting today, my future self calls the turning point.",cat:"New Beginnings"},
  {id:"NB062",text:"I unpack hope first.",cat:"New Beginnings"},
  {id:"NB063",text:"New beginnings rarely announce themselves. This ordinary morning might be one.",cat:"New Beginnings"},
  {id:"NB064",text:"I make the first move toward the life that keeps appearing in my quiet moments.",cat:"New Beginnings"},
  {id:"NB065",text:"I am a stranger to my new life for a few weeks only. Then it becomes mine.",cat:"New Beginnings"},
  {id:"NB066",text:"I forgive the old chapter for taking so long to end.",cat:"New Beginnings"},
  {id:"NB067",text:"Day one looks small in every great story.",cat:"New Beginnings"},
  {id:"NB068",text:"I begin again with better information and the same brave heart.",cat:"New Beginnings"},
  {id:"NB069",text:"The door behind me locked for a reason. I face the hallway of open ones.",cat:"New Beginnings"},
  {id:"NB070",text:"I am rebuilding on cleared ground, and cleared ground is an advantage.",cat:"New Beginnings"},
  {id:"NB071",text:"Starting fresh at my age is not late. It is seasoned.",cat:"New Beginnings"},
  {id:"NB072",text:"I let the new thing be different instead of demanding it replace the old.",cat:"New Beginnings"},
  {id:"NB073",text:"The first draft of this new life is allowed to be rough.",cat:"New Beginnings"},
  {id:"NB074",text:"I begin quietly. Announcements can come after roots.",cat:"New Beginnings"},
  {id:"NB075",text:"What ended did not take my future with it. My future was never in its custody.",cat:"New Beginnings"},
  {id:"NB076",text:"I water the new thing daily and stop digging it up to check for roots.",cat:"New Beginnings"},
  {id:"NB077",text:"Reinvention is my birthright, renewable as often as I need it.",cat:"New Beginnings"},
  {id:"NB078",text:"I miss a place that no longer exists, and still I build the new home.",cat:"New Beginnings"},
  {id:"NB079",text:"The unknown ahead of me is at least half wonderful, and I keep forgetting that.",cat:"New Beginnings"},
  {id:"NB080",text:"I show up to my new beginning like a guest who intends to stay.",cat:"New Beginnings"},
  {id:"NB081",text:"Endings sorted my life into what matters and what was habit. I keep what matters.",cat:"New Beginnings"},
  {id:"NB082",text:"I am the architect of the after.",cat:"New Beginnings"},
  {id:"NB083",text:"New beginnings honor the old ones by using everything they taught.",cat:"New Beginnings"},
  {id:"NB084",text:"I start the smallest possible version today, and the smallest version starts everything.",cat:"New Beginnings"},
  {id:"NB085",text:"I am no longer who I was there. Here gets the upgraded version.",cat:"New Beginnings"},
  {id:"NB086",text:"First days are data, not verdicts.",cat:"New Beginnings"},
  {id:"NB087",text:"I give the new beginning a fair season, not a nervous week.",cat:"New Beginnings"},
  {id:"NB088",text:"Beginnings love me back when I commit to them.",cat:"New Beginnings"},
  {id:"NB089",text:"The blank slate is not empty. It is full of permission.",cat:"New Beginnings"},
  {id:"NB090",text:"I let myself be excited out loud about what is next.",cat:"New Beginnings"},
  {id:"NB091",text:"Every master was once a day-one disaster. I am in excellent company.",cat:"New Beginnings"},
  {id:"NB092",text:"I begin again — not from scratch, but from experience.",cat:"New Beginnings"},
  {id:"NB093",text:"The new path has no traffic from my old mistakes.",cat:"New Beginnings"},
  {id:"NB094",text:"I am building a life that fits the person I had to become.",cat:"New Beginnings"},
  {id:"NB095",text:"Some beginnings are disguised as losses for the first year. I trust the direction anyway.",cat:"New Beginnings"},
  {id:"NB096",text:"I take the orientation tour of my own new life with curiosity.",cat:"New Beginnings"},
  {id:"NB097",text:"What begins in honesty does not have to end in regret.",cat:"New Beginnings"},
  {id:"NB098",text:"I am brand new at this and ancient in resilience. Useful combination.",cat:"New Beginnings"},
  {id:"NB099",text:"The next version of my life requires this awkward in-between, and I honor it.",cat:"New Beginnings"},
  {id:"NB100",text:"I stop comparing chapter one of this to chapter twenty of that.",cat:"New Beginnings"},
  {id:"NB101",text:"Today I set down roots in fresh soil and trust the same old sun.",cat:"New Beginnings"},
  {id:"NB102",text:"Newness wears off. Rightness remains. I am building toward rightness.",cat:"New Beginnings"},
  {id:"NB103",text:"I begin where I am, with what I have, before I feel ready — and that is always enough.",cat:"New Beginnings"},
  {id:"NB104",text:"The move, the change, the leap — my whole body knew before my plans did.",cat:"New Beginnings"},
  {id:"NB105",text:"This is the part of the story where everything quietly turns. I can feel it.",cat:"New Beginnings"},
  {id:"NB106",text:"I clear out what expired — habits, grudges, drafts — and the space fills with possibility.",cat:"New Beginnings"},
  {id:"NB107",text:"I greet my new mornings by name.",cat:"New Beginnings"},
  {id:"NB108",text:"Beginnings deserve my best energy, so I stop spending it on autopsies of the past.",cat:"New Beginnings"},
  {id:"NB109",text:"I am allowed to love the new life without guilt toward the old one.",cat:"New Beginnings"},
  {id:"NB110",text:"The bridge burned, and the river taught me to swim.",cat:"New Beginnings"},
  {id:"NB111",text:"I keep beginner's eyes on purpose. They see doors that experts walk past.",cat:"New Beginnings"},
  {id:"NB112",text:"Starting over is my proof of life.",cat:"New Beginnings"},
  {id:"NB113",text:"What I begin in this season will shelter me in a future one.",cat:"New Beginnings"},
  {id:"NB114",text:"I am mid-transformation and on schedule, even when it feels like chaos.",cat:"New Beginnings"},
  {id:"NB115",text:"Every new beginning needed me to be exactly this uncomfortable first.",cat:"New Beginnings"},
  {id:"NB116",text:"I sign my name to the new chapter.",cat:"New Beginnings"},
  {id:"NB117",text:"Fresh starts are not erasers. They are sequels, and sequels know things.",cat:"New Beginnings"},
  {id:"NB118",text:"The seed does not mourn the packet.",cat:"New Beginnings"},
  {id:"NB119",text:"I begin again in the middle of my life, which is exactly where the best beginnings happen.",cat:"New Beginnings"},
  {id:"NB120",text:"I have closed the tab on the life that was not loading.",cat:"New Beginnings"},
  {id:"NB121",text:"My past self bought the lessons. My new self spends them.",cat:"New Beginnings"},
  {id:"NB122",text:"I welcome the version of me that only this new beginning could introduce.",cat:"New Beginnings"},
  {id:"NB123",text:"The terrain is unfamiliar, and my feet are experienced.",cat:"New Beginnings"},
  {id:"NB124",text:"I let this beginning be slow, real, and entirely mine.",cat:"New Beginnings"},
  {id:"NB125",text:"Restarting the same dream with new wisdom is not failure. It is mastery arriving.",cat:"New Beginnings"},
  {id:"NB126",text:"I begin today the habit my future biography mentions in chapter one.",cat:"New Beginnings"},
  {id:"NB127",text:"Even the calendar gets a fresh page every month. I am allowed the same.",cat:"New Beginnings"},
  {id:"NB128",text:"I make new memories in old places and reclaim the map.",cat:"New Beginnings"},
  {id:"NB129",text:"The first step does not need to know about the tenth.",cat:"New Beginnings"},
  {id:"NB130",text:"I am someone who begins. It is the bravest of my talents.",cat:"New Beginnings"},
  {id:"NB131",text:"New beginnings test my identity and find it portable.",cat:"New Beginnings"},
  {id:"NB132",text:"I outlasted the ending. The beginning is the easy part.",cat:"New Beginnings"},
  {id:"NB133",text:"Where I am headed, my history is a resource, not a residence.",cat:"New Beginnings"},
  {id:"NB134",text:"I open the new notebook and ruin the first page on purpose. Now we can work.",cat:"New Beginnings"},
  {id:"NB135",text:"Beginning again does not erase my progress. It relocates it.",cat:"New Beginnings"},
  {id:"NB136",text:"I trust beginnings that feel calm even more than ones that feel like fireworks.",cat:"New Beginnings"},
  {id:"NB137",text:"The land of what now is wide, and I am a willing explorer.",cat:"New Beginnings"},
  {id:"NB138",text:"I am building from the studs, and this time I know exactly what the house needs.",cat:"New Beginnings"},
  {id:"NB139",text:"My second acts have always been stronger. This one will keep the pattern.",cat:"New Beginnings"},
  {id:"NB140",text:"I leave room in the plan for the person I will be by spring.",cat:"New Beginnings"},
  {id:"NB141",text:"The old ceiling is the new floor.",cat:"New Beginnings"},
  {id:"NB142",text:"I start the conversation, the course, the chapter — starting is my renewable superpower.",cat:"New Beginnings"},
  {id:"NB143",text:"Everything I admire was once somebody's terrifying first step.",cat:"New Beginnings"},
  {id:"NB144",text:"I am at the trailhead with good shoes and an honest map.",cat:"New Beginnings"},
  {id:"NB145",text:"The fresh start I keep waiting for is already mine. It is called this morning.",cat:"New Beginnings"},
  // FAMILY — expansion (FM041–FM140)
  {id:"FM041",text:"I answer the bids for my attention — the look, the joke, the small hand on my sleeve.",cat:"Family"},
  {id:"FM042",text:"Our home runs on repair, not perfection.",cat:"Family"},
  {id:"FM043",text:"I am the calm my family gets to come home to.",cat:"Family"},
  {id:"FM044",text:"The dinner table is my favorite altar.",cat:"Family"},
  {id:"FM045",text:"I love my people specifically — their actual selves, not my projections.",cat:"Family"},
  {id:"FM046",text:"I tell the stories of where we came from so my children stand on something.",cat:"Family"},
  {id:"FM047",text:"Being patient at six in the evening is my most heroic act of the day.",cat:"Family"},
  {id:"FM048",text:"I apologize to my kids when I am wrong, and the apology teaches more than the lecture.",cat:"Family"},
  {id:"FM049",text:"My family does not need a perfect me. They need a present me.",cat:"Family"},
  {id:"FM050",text:"I build traditions small enough to keep — Friday pancakes, Sunday walks, the birthday plate.",cat:"Family"},
  {id:"FM051",text:"The phone goes down when my people walk in.",cat:"Family"},
  {id:"FM052",text:"I am raising adults I will genuinely like, by liking the children they are now.",cat:"Family"},
  {id:"FM053",text:"I married my teammate, and I play like it.",cat:"Family"},
  {id:"FM054",text:"I call my parents while calling is still possible.",cat:"Family"},
  {id:"FM055",text:"Our home has room for bad days without anyone being the bad guy.",cat:"Family"},
  {id:"FM056",text:"I keep my promises to children as if they were contracts, because to them they are.",cat:"Family"},
  {id:"FM057",text:"I am the generation where the yelling stops.",cat:"Family"},
  {id:"FM058",text:"Love is mostly logistics done warmly, and I do the logistics warmly.",cat:"Family"},
  {id:"FM059",text:"I let my family see me rest, so they learn rest is allowed.",cat:"Family"},
  {id:"FM060",text:"I protect my children's childhood from my own childhood.",cat:"Family"},
  {id:"FM061",text:"We are a family that says the love out loud.",cat:"Family"},
  {id:"FM062",text:"I give my partner the generosity of interpretation I hope to receive.",cat:"Family"},
  {id:"FM063",text:"Home is the one review that matters. I work for the home review.",cat:"Family"},
  {id:"FM064",text:"I sit on the floor and enter their world. The floor is where the bonding is.",cat:"Family"},
  {id:"FM065",text:"My boundaries with extended family are fences with gates, not walls.",cat:"Family"},
  {id:"FM066",text:"I let my children be different from me and watch who they actually are.",cat:"Family"},
  {id:"FM067",text:"I thank my partner for ordinary things, because ordinary things are the marriage.",cat:"Family"},
  {id:"FM068",text:"Our house holds laughter the way some houses hold tension. We built it that way.",cat:"Family"},
  {id:"FM069",text:"I am writing my family's emotional recipe book, and I include the sweetness.",cat:"Family"},
  {id:"FM070",text:"I show up to the recital, the game, the small Tuesday thing. Showing up is the love language.",cat:"Family"},
  {id:"FM071",text:"I forgive my parents at the pace that honesty allows, and I keep what was good.",cat:"Family"},
  {id:"FM072",text:"The family I am building is allowed to be softer than the one I came from.",cat:"Family"},
  {id:"FM073",text:"I am a student of my children. They update constantly.",cat:"Family"},
  {id:"FM074",text:"When I do not know what to say, I stay in the room. Staying is fluent.",cat:"Family"},
  {id:"FM075",text:"I make my home a place where the truth is safe to say slowly.",cat:"Family"},
  {id:"FM076",text:"I treat my siblings as the longest witnesses of my life. That history is worth tending.",cat:"Family"},
  {id:"FM077",text:"Bedtime is sacred, unhurried, and ours.",cat:"Family"},
  {id:"FM078",text:"I love my family at their most inconvenient, because that is when it counts.",cat:"Family"},
  {id:"FM079",text:"My children will remember the tone of this house. I set it daily.",cat:"Family"},
  {id:"FM080",text:"I am the soft landing after their hard days.",cat:"Family"},
  {id:"FM081",text:"I choose my family again on the days choosing is work.",cat:"Family"},
  {id:"FM082",text:"We repair the same day whenever we can. Resentment does not get to spend the night.",cat:"Family"},
  {id:"FM083",text:"I delegate, ask, and accept help — a family is not a solo performance.",cat:"Family"},
  {id:"FM084",text:"I keep romance in the family budget.",cat:"Family"},
  {id:"FM085",text:"My grandparents' sacrifices are still compounding, and the life I am building is the return.",cat:"Family"},
  {id:"FM086",text:"I narrate the good I see in my people, out loud, in front of others.",cat:"Family"},
  {id:"FM087",text:"The chores are shared, the credit is shared, the life is shared.",cat:"Family"},
  {id:"FM088",text:"I hold the people while they are here and let the grudges go first.",cat:"Family"},
  {id:"FM089",text:"I am building a family culture on purpose — words, rituals, jokes, values, all chosen.",cat:"Family"},
  {id:"FM090",text:"I let my children overhear me praising them.",cat:"Family"},
  {id:"FM091",text:"Family walks and one-on-ones — I schedule the love and the love shows up.",cat:"Family"},
  {id:"FM092",text:"I am the historian of small moments — the photos, the quotes, the first words.",cat:"Family"},
  {id:"FM093",text:"I give respect on credit in my family, and the terms are mine.",cat:"Family"},
  {id:"FM094",text:"I keep one tradition from my childhood and compost the rest. Curation is love.",cat:"Family"},
  {id:"FM095",text:"Our family handles money out loud, calmly, together.",cat:"Family"},
  {id:"FM096",text:"I welcome the awkward years like the weather — fully dressed and unoffended.",cat:"Family"},
  {id:"FM097",text:"I am someone my family does not have to brace around.",cat:"Family"},
  {id:"FM098",text:"Grandparents, neighbors, godparents — I let the village in.",cat:"Family"},
  {id:"FM099",text:"I make sure the quiet child gets the microphone sometimes.",cat:"Family"},
  {id:"FM100",text:"We celebrate effort in this house. Outcomes get cake, but effort gets the speech.",cat:"Family"},
  {id:"FM101",text:"I let my partner parent differently without supervision or scoring.",cat:"Family"},
  {id:"FM102",text:"I take care of myself loudly so my children learn it is not selfish.",cat:"Family"},
  {id:"FM103",text:"Our door is the one the cousins want to knock on.",cat:"Family"},
  {id:"FM104",text:"I tell my parents the things eulogies say, while they can still blush.",cat:"Family"},
  {id:"FM105",text:"I am converting generational pain into generational wisdom, one choice at a time.",cat:"Family"},
  {id:"FM106",text:"The family group chat gets my best jokes and my real updates.",cat:"Family"},
  {id:"FM107",text:"We eat together more nights than not, and it is quietly everything.",cat:"Family"},
  {id:"FM108",text:"I let my children be bored near me. Some of our best talks grew in that soil.",cat:"Family"},
  {id:"FM109",text:"I am a guardian of my family's rest — the schedule stays humane on my watch.",cat:"Family"},
  {id:"FM110",text:"I love the family I have while honestly grieving the one I needed. Both are sacred.",cat:"Family"},
  {id:"FM111",text:"I treat my home like a team and my team like a home.",cat:"Family"},
  {id:"FM112",text:"When my child tells me something small, I listen big — so the big things come to me too.",cat:"Family"},
  {id:"FM113",text:"I leave work at the door for the first ten minutes. The reunion sets the evening.",cat:"Family"},
  {id:"FM114",text:"Our family's wealth is measured in inside jokes and kept promises.",cat:"Family"},
  {id:"FM115",text:"I am the adult I needed, on duty, in this house.",cat:"Family"},
  {id:"FM116",text:"I say yes to the game of catch. The window for catch closes quietly.",cat:"Family"},
  {id:"FM117",text:"Discipline in our home means teaching, and the teacher stays calm.",cat:"Family"},
  {id:"FM118",text:"I check on the strong one, the quiet one, the one who says they are fine.",cat:"Family"},
  {id:"FM119",text:"My marriage gets date nights, hard conversations, and the benefit of the doubt.",cat:"Family"},
  {id:"FM120",text:"I keep the family stories alive and edit the shame out of them honestly.",cat:"Family"},
  {id:"FM121",text:"Holidays are ours to design. Obligation does not get a vote anymore.",cat:"Family"},
  {id:"FM122",text:"I am present at the table — fork down, eyes up, phone elsewhere.",cat:"Family"},
  {id:"FM123",text:"I give my children roots, wings, and a working example.",cat:"Family"},
  {id:"FM124",text:"Cycle-breaking is exhausting and historic. I am doing something historic.",cat:"Family"},
  {id:"FM125",text:"I praise my partner behind their back and it always finds its way home.",cat:"Family"},
  {id:"FM126",text:"I make space for my children's big feelings without making them my own.",cat:"Family"},
  {id:"FM127",text:"Chosen family counts in full. My table seats whoever loves well.",cat:"Family"},
  {id:"FM128",text:"I am tender with my parents' aging and honest about my limits. Both, with grace.",cat:"Family"},
  {id:"FM129",text:"We are a family that tries again after hard nights.",cat:"Family"},
  {id:"FM130",text:"I plant trees in this family whose shade I will never sit in, gladly.",cat:"Family"},
  {id:"FM131",text:"My children's trust is my most important account, and I deposit daily.",cat:"Family"},
  {id:"FM132",text:"I keep my word about the small things — the park, the five more minutes, the pickup time.",cat:"Family"},
  {id:"FM133",text:"A calm parent is the heirloom I am restoring.",cat:"Family"},
  {id:"FM134",text:"I love this family out loud, in writing, in casseroles, in showing up.",cat:"Family"},
  {id:"FM135",text:"Our home is the safest room in every storm season.",cat:"Family"},
  {id:"FM136",text:"I let myself be deeply known by the people who share my roof.",cat:"Family"},
  {id:"FM137",text:"The legacy I am leaving is people who know how to love and repair.",cat:"Family"},
  {id:"FM138",text:"I am the steady one not because I never shake, but because I always return.",cat:"Family"},
  {id:"FM139",text:"Every generation healed a little. I am healing a lot, and it shows at our table.",cat:"Family"},
  {id:"FM140",text:"The family I always wanted is already mine. I am building it from the inside.",cat:"Family"},
  // GROWTH — expansion (GR056–GR155)
  {id:"GR056",text:"I am under construction and open for business at the same time.",cat:"Growth"},
  {id:"GR057",text:"Tiny daily improvements are invisible weekly and unmistakable yearly.",cat:"Growth"},
  {id:"GR058",text:"I let the lesson cost what it costs and make sure I keep the receipt.",cat:"Growth"},
  {id:"GR059",text:"Growth tastes like humility first and freedom after.",cat:"Growth"},
  {id:"GR060",text:"I am outgrowing my excuses faster than I can replace them.",cat:"Growth"},
  {id:"GR061",text:"Every level of my life has required a slightly braver me. I keep becoming them.",cat:"Growth"},
  {id:"GR062",text:"I study my own patterns like a scientist with a beloved subject.",cat:"Growth"},
  {id:"GR063",text:"Becoming is not glamorous. It is Tuesdays, repeated with intention.",cat:"Growth"},
  {id:"GR064",text:"I ask for feedback and let it cost me nothing but ego.",cat:"Growth"},
  {id:"GR065",text:"The discomfort of growth is temporary. The discomfort of staying is on a subscription.",cat:"Growth"},
  {id:"GR066",text:"I am a better thinker than last year because I changed my mind twice.",cat:"Growth"},
  {id:"GR067",text:"My habits are the staff of my future. I hire carefully.",cat:"Growth"},
  {id:"GR068",text:"I grow in private so quietly that the public calls it sudden.",cat:"Growth"},
  {id:"GR069",text:"I keep the promise of the early alarm, and the day repays me.",cat:"Growth"},
  {id:"GR070",text:"What I tolerate, I teach myself. I am raising my standards for both.",cat:"Growth"},
  {id:"GR071",text:"I read, I attempt, I revise — the trilogy of becoming.",cat:"Growth"},
  {id:"GR072",text:"Plateaus are where the roots catch up to the branches.",cat:"Growth"},
  {id:"GR073",text:"I am patient with the process and impatient with my excuses. Correct order.",cat:"Growth"},
  {id:"GR074",text:"Five years ago, today's normal was my impossible. I remember that during the hard parts.",cat:"Growth"},
  {id:"GR075",text:"I trade who I have been for who I could be, and the exchange rate is always fair.",cat:"Growth"},
  {id:"GR076",text:"Growth asked for consistency, not intensity. I finally heard it.",cat:"Growth"},
  {id:"GR077",text:"I audit my circle, my inputs, and my self-talk. Everything feeds something.",cat:"Growth"},
  {id:"GR078",text:"The version of me that arrives next year is being assembled by this week's choices.",cat:"Growth"},
  {id:"GR079",text:"I welcome the cringe of my old work. It means my taste grew.",cat:"Growth"},
  {id:"GR080",text:"I am both the sculptor and the marble, and the chisel is daily practice.",cat:"Growth"},
  {id:"GR081",text:"What I practice in secret becomes my reputation in public.",cat:"Growth"},
  {id:"GR082",text:"I let hard seasons revise me without letting them define me.",cat:"Growth"},
  {id:"GR083",text:"Curiosity is my compass. It has never once pointed at stagnation.",cat:"Growth"},
  {id:"GR084",text:"I close the gap between what I know and what I do. That gap is the whole game.",cat:"Growth"},
  {id:"GR085",text:"My future self keeps sending back gratitude for the things I do grudgingly today.",cat:"Growth"},
  {id:"GR086",text:"I unlearn faster than I cling. It is my quiet edge.",cat:"Growth"},
  {id:"GR087",text:"Discipline is just remembering what I want most over what I want now.",cat:"Growth"},
  {id:"GR088",text:"I am wildly unfinished, and that is the most hopeful fact about me.",cat:"Growth"},
  {id:"GR089",text:"Growth redistributes my circle. I let it.",cat:"Growth"},
  {id:"GR090",text:"Every skill I have was once a clumsy attempt I refused to abandon.",cat:"Growth"},
  {id:"GR091",text:"I take notes on my own life and the patterns confess everything.",cat:"Growth"},
  {id:"GR092",text:"I am compounding quietly while looking entirely ordinary.",cat:"Growth"},
  {id:"GR093",text:"I keep one foot in gratitude and one foot in ambition, and I walk far that way.",cat:"Growth"},
  {id:"GR094",text:"The struggle is the curriculum, not a malfunction in it.",cat:"Growth"},
  {id:"GR095",text:"I check my trajectory more than my position.",cat:"Growth"},
  {id:"GR096",text:"Some doors only open for the next version of me. I am en route.",cat:"Growth"},
  {id:"GR097",text:"I ask better questions of myself and refuse to flinch at the answers.",cat:"Growth"},
  {id:"GR098",text:"What stretched me last year fits me comfortably now. That is all the evidence I need.",cat:"Growth"},
  {id:"GR099",text:"I let go of needing growth to feel good while it is happening.",cat:"Growth"},
  {id:"GR100",text:"I am the project I never abandon.",cat:"Growth"},
  {id:"GR101",text:"I treat every setback as tuition at a school I chose.",cat:"Growth"},
  {id:"GR102",text:"My evolution makes some people nostalgic for the old me. I keep evolving.",cat:"Growth"},
  {id:"GR103",text:"I show up on the boring days, which turn out to be the load-bearing days.",cat:"Growth"},
  {id:"GR104",text:"The mirror shows my face. My choices show my character. I tend both.",cat:"Growth"},
  {id:"GR105",text:"I am one honest self-assessment away from my next breakthrough, and I do not postpone it.",cat:"Growth"},
  {id:"GR106",text:"I replace resolutions with systems and watch myself finally change.",cat:"Growth"},
  {id:"GR107",text:"Growth is remembering I am allowed to begin badly.",cat:"Growth"},
  {id:"GR108",text:"I prune what I once was proud of when it no longer bears fruit.",cat:"Growth"},
  {id:"GR109",text:"My ceiling keeps becoming my floor, and I keep building stairs.",cat:"Growth"},
  {id:"GR110",text:"I am converting my potential into evidence at a steady rate.",cat:"Growth"},
  {id:"GR111",text:"Each season of my life gets a syllabus. I am a willing student of this one.",cat:"Growth"},
  {id:"GR112",text:"I respect who I was, consult who I am, and work for who I am becoming.",cat:"Growth"},
  {id:"GR113",text:"The pace is mine. The direction is what I guard.",cat:"Growth"},
  {id:"GR114",text:"I expand my comfort zone by visiting outside it regularly, like a neighbor.",cat:"Growth"},
  {id:"GR115",text:"I am living proof of revision.",cat:"Growth"},
  {id:"GR116",text:"I do the reps when no one claps. The clapping was never the fuel.",cat:"Growth"},
  {id:"GR117",text:"Hard conversations, early mornings, honest pages — my growth has fingerprints.",cat:"Growth"},
  {id:"GR118",text:"I stay coachable. The day I cannot be told anything is the day I stop growing.",cat:"Growth"},
  {id:"GR119",text:"My old self keeps trying to reapply for the job. The position is filled.",cat:"Growth"},
  {id:"GR120",text:"I grow where I am planted and also know when to repot.",cat:"Growth"},
  {id:"GR121",text:"Maturity is how gently I can hold what once destabilized me.",cat:"Growth"},
  {id:"GR122",text:"I am building range — softer where I was rigid, firmer where I was loose.",cat:"Growth"},
  {id:"GR123",text:"The detours taught me terrain the highway never would have.",cat:"Growth"},
  {id:"GR124",text:"I measure growth in recovered hours, kinder thoughts, and kept promises.",cat:"Growth"},
  {id:"GR125",text:"I keep showing my rough drafts to the world and improving in public.",cat:"Growth"},
  {id:"GR126",text:"Stagnation costs more than change. I have read the invoice.",cat:"Growth"},
  {id:"GR127",text:"I let admiration be instruction — what I love in others is dormant in me.",cat:"Growth"},
  {id:"GR128",text:"I am the compound interest of every small brave thing I have done.",cat:"Growth"},
  {id:"GR129",text:"Growth keeps no leaderboard. I race my own previous lap.",cat:"Growth"},
  {id:"GR130",text:"I retire one limiting belief per season, with honors.",cat:"Growth"},
  {id:"GR131",text:"The future does not need me perfect. It needs me improving on schedule.",cat:"Growth"},
  {id:"GR132",text:"I stay a beginner somewhere on purpose, always.",cat:"Growth"},
  {id:"GR133",text:"My becoming has outlasted every mood that tried to cancel it.",cat:"Growth"},
  {id:"GR134",text:"I water what I want to grow and stop fertilizing what I complain about.",cat:"Growth"},
  {id:"GR135",text:"Self-awareness was the hardest skill, and it has paid for all the others.",cat:"Growth"},
  {id:"GR136",text:"I evolve out loud so the people I love know it is possible.",cat:"Growth"},
  {id:"GR137",text:"The work works on me while I work on it.",cat:"Growth"},
  {id:"GR138",text:"I keep a long memory for lessons and a short memory for embarrassments.",cat:"Growth"},
  {id:"GR139",text:"Where my focus goes, my future grows.",cat:"Growth"},
  {id:"GR140",text:"I make peace with slow, because slow keeps arriving and quitting never does.",cat:"Growth"},
  {id:"GR141",text:"I am differently brave than last year — quieter, steadier, more often.",cat:"Growth"},
  {id:"GR142",text:"I upgrade my standards and my habits in the same transaction.",cat:"Growth"},
  {id:"GR143",text:"Each morning asks who I intend to be today. I answer with actions.",cat:"Growth"},
  {id:"GR144",text:"I am fluent in starting over and gaining fluency in following through.",cat:"Growth"},
  {id:"GR145",text:"My growth is rearranging the furniture of my identity, and I let it.",cat:"Growth"},
  {id:"GR146",text:"I host my own annual review and promote myself accordingly.",cat:"Growth"},
  {id:"GR147",text:"The chapters ahead require muscles I am building in this one.",cat:"Growth"},
  {id:"GR148",text:"I am more process than product, and the process is going well.",cat:"Growth"},
  {id:"GR149",text:"I earn my own respect daily, which makes everyone else's optional.",cat:"Growth"},
  {id:"GR150",text:"I keep planting seasons even after disappointing harvests. Farmers understand.",cat:"Growth"},
  {id:"GR151",text:"Becoming who I am meant to be is a daily vote, and I keep winning the election.",cat:"Growth"},
  {id:"GR152",text:"I love the climb on the days I remember to look at the view.",cat:"Growth"},
  {id:"GR153",text:"My transformation is not a phase. It is the plot.",cat:"Growth"},
  {id:"GR154",text:"I keep growing past the points where I once planned to stop.",cat:"Growth"},
  {id:"GR155",text:"The person I am becoming is already mine. Every day I claim a little more of them.",cat:"Growth"},
  // ABUNDANCE — expansion (AB151–AB200)
  {id:"AB151",text:"My calendar has white space in it, and that is a kind of rich.",cat:"Abundance"},
  {id:"AB152",text:"Ideas arrive for me daily. I am never out of raw material.",cat:"Abundance"},
  {id:"AB153",text:"I share my table often. A full table is my favorite proof of plenty.",cat:"Abundance"},
  {id:"AB154",text:"Luck keeps finding me because I keep showing up where it lands.",cat:"Abundance"},
  {id:"AB155",text:"I am paying off the past and funding the future in the same breath.",cat:"Abundance"},
  {id:"AB156",text:"Options are a form of wealth, and I am building mine deliberately.",cat:"Abundance"},
  {id:"AB157",text:"This is a planting season. I do not demand harvest from seeds.",cat:"Abundance"},
  {id:"AB158",text:"I teach the people I love that there is enough by living like there is.",cat:"Abundance"},
  {id:"AB159",text:"I keep space open on purpose. What is coming needs somewhere to land.",cat:"Abundance"},
  {id:"AB160",text:"Time is a currency I refuse to waste, and I am spending it on a life I want.",cat:"Abundance"},
  {id:"AB161",text:"Compliments, referrals, invitations — I notice how much keeps arriving unasked.",cat:"Abundance"},
  {id:"AB162",text:"Small generosities leave my hands all day, and my hands are never empty.",cat:"Abundance"},
  {id:"AB163",text:"There is no fixed pie. I am in the kitchen making more.",cat:"Abundance"},
  {id:"AB164",text:"I inherited my grandmother's resourcefulness and declined her fear.",cat:"Abundance"},
  {id:"AB165",text:"I negotiate kindly and firmly, and I leave the table with respect intact.",cat:"Abundance"},
  {id:"AB166",text:"Libraries, sunsets, long talks — half my wealth has always been free.",cat:"Abundance"},
  {id:"AB167",text:"My money has jobs now — some of it works, some of it rests, all of it has purpose.",cat:"Abundance"},
  {id:"AB168",text:"Debt is leaving my life the way it arrived — one decision at a time.",cat:"Abundance"},
  {id:"AB169",text:"Abundance likes my habits.",cat:"Abundance"},
  {id:"AB170",text:"I can make a feast from what is in the pantry. That skill is wealth too.",cat:"Abundance"},
  {id:"AB171",text:"My network is generous because I am the generous one in it.",cat:"Abundance"},
  {id:"AB172",text:"I am rich in second chances and I stopped wasting them.",cat:"Abundance"},
  {id:"AB173",text:"The raise, the client, the yes — I prepare like they are already scheduled.",cat:"Abundance"},
  {id:"AB174",text:"I release the fear of losing it all. I built it once, and builders are never empty-handed.",cat:"Abundance"},
  {id:"AB175",text:"Enough sleep, enough food, enough time — I refuse to run my life on deficits.",cat:"Abundance"},
  {id:"AB176",text:"I collect skills the way others collect worries, and mine pay dividends.",cat:"Abundance"},
  {id:"AB177",text:"The overflow is the plan. I build past my own needs so I can be someone's answer.",cat:"Abundance"},
  {id:"AB178",text:"I stopped calling my needs expensive and started calling them requirements.",cat:"Abundance"},
  {id:"AB179",text:"Wealth arrives faster in a house that is ready for it. I keep my house ready.",cat:"Abundance"},
  {id:"AB180",text:"I hold money without gripping it and release it without grieving.",cat:"Abundance"},
  {id:"AB181",text:"I let my rates grow up with me.",cat:"Abundance"},
  {id:"AB182",text:"There is more where that came from — more clients, more ideas, more mornings.",cat:"Abundance"},
  {id:"AB183",text:"I read the stories of people who built plenty from nothing, and I recognize myself.",cat:"Abundance"},
  {id:"AB184",text:"Scarcity made me clever. Abundance gets to enjoy the cleverness.",cat:"Abundance"},
  {id:"AB185",text:"I budget for joy on purpose. Delight is a line item, not a leak.",cat:"Abundance"},
  {id:"AB186",text:"My cupboards, my inbox, my heart — more is coming in than leaking out.",cat:"Abundance"},
  {id:"AB187",text:"I stopped lining up for crumbs when the bakery is mine to build.",cat:"Abundance"},
  {id:"AB188",text:"I ask bigger and flinch less every year.",cat:"Abundance"},
  {id:"AB189",text:"Abundance is not a jackpot. It is a rhythm, and I am keeping the beat.",cat:"Abundance"},
  {id:"AB190",text:"Wanting more for my family is not greed. It is love with a plan.",cat:"Abundance"},
  {id:"AB191",text:"I show up in lean months with the same posture I keep in generous ones.",cat:"Abundance"},
  {id:"AB192",text:"I answer opportunity on the first ring.",cat:"Abundance"},
  {id:"AB193",text:"Ideas, energy, and daylight return every morning. I work with renewable wealth.",cat:"Abundance"},
  {id:"AB194",text:"I keep an emergency fund and an opportunity fund. Fear and hope both get accounts.",cat:"Abundance"},
  {id:"AB195",text:"Counted in sunrises witnessed and promises kept, I am doing extremely well.",cat:"Abundance"},
  {id:"AB196",text:"The children in my life will learn plenty from watching me expect it.",cat:"Abundance"},
  {id:"AB197",text:"I release comparison with other people's harvests. Our fields were planted in different years.",cat:"Abundance"},
  {id:"AB198",text:"My abundance has witnesses now — the people I helped, hired, and fed.",cat:"Abundance"},
  {id:"AB199",text:"I keep a list of things I once prayed for that I now live in.",cat:"Abundance"},
  {id:"AB200",text:"Plenty is a language, and I am raising my fluency daily.",cat:"Abundance"},
  // LOVE — expansion (LV150–LV199)
  {id:"LV150",text:"I keep choosing my person after the choosing stopped being new.",cat:"Love"},
  {id:"LV151",text:"Love, in my house, looks like coffee made first and the last bite offered.",cat:"Love"},
  {id:"LV152",text:"I compliment the people I love in the present tense.",cat:"Love"},
  {id:"LV153",text:"Distance tests our love, and our love keeps passing.",cat:"Love"},
  {id:"LV154",text:"I want to grow old with the people who knew me young.",cat:"Love"},
  {id:"LV155",text:"I flirt with my own partner. The spark is a fire I keep feeding.",cat:"Love"},
  {id:"LV156",text:"After the argument, I reach first. Pride can sleep on the couch — we will not.",cat:"Love"},
  {id:"LV157",text:"I ask how their day was and stay for the whole answer.",cat:"Love"},
  {id:"LV158",text:"Hand-holding, long hugs, a squeeze of the shoulder — I keep love physical and present.",cat:"Love"},
  {id:"LV159",text:"Unpartnered is not unloved. My life is crowded with affection.",cat:"Love"},
  {id:"LV160",text:"Loving again after loss does not divide my heart. Hearts multiply.",cat:"Love"},
  {id:"LV161",text:"I let my partner have a bad day without making it a referendum on us.",cat:"Love"},
  {id:"LV162",text:"I stay curious about the person beside me. Familiar is not finished.",cat:"Love"},
  {id:"LV163",text:"I forgive quickly in small things and honestly in large ones.",cat:"Love"},
  {id:"LV164",text:"I would rather be known and complicated than adored and invisible.",cat:"Love"},
  {id:"LV165",text:"Long love is built from ordinary evenings, and I keep showing up to them.",cat:"Love"},
  {id:"LV166",text:"I text back. I remember birthdays. I love in verbs.",cat:"Love"},
  {id:"LV167",text:"My grandparents' kind of love — patient, steady, loyal — is a craft I am learning.",cat:"Love"},
  {id:"LV168",text:"Jealousy visits, and I greet it with honesty instead of accusations.",cat:"Love"},
  {id:"LV169",text:"I stopped issuing tests I never told anyone they were taking.",cat:"Love"},
  {id:"LV170",text:"First dates are not exams. They are conversations, and I am good at those.",cat:"Love"},
  {id:"LV171",text:"I let my friends love me at my most unimpressive.",cat:"Love"},
  {id:"LV172",text:"I do not wait for a crisis to tell people what they mean to me.",cat:"Love"},
  {id:"LV173",text:"The apology I owe, I deliver in person and in full.",cat:"Love"},
  {id:"LV174",text:"I ask to be held when I need holding. The people who love me are glad to know.",cat:"Love"},
  {id:"LV175",text:"The people I love and I share jokes that have been running for years. That is intimacy too.",cat:"Love"},
  {id:"LV176",text:"I love across generations — elders, children, old friends — and each one teaches me a different kind of care.",cat:"Love"},
  {id:"LV177",text:"When someone shows me their tender place, I guard it like my own.",cat:"Love"},
  {id:"LV178",text:"I remember the small preferences of the people I love. Memory is a love language.",cat:"Love"},
  {id:"LV179",text:"Romance did not retire when routine arrived. I keep proposing small adventures.",cat:"Love"},
  {id:"LV180",text:"I let love see my finances, my fears, and my bare face.",cat:"Love"},
  {id:"LV181",text:"I am the person who looks up when they walk in.",cat:"Love"},
  {id:"LV182",text:"Old couples holding hands are instructions, and I am taking notes.",cat:"Love"},
  {id:"LV183",text:"Love notes, voice memos, flowers on a weekday — I am the reason someone smiles at their phone.",cat:"Love"},
  {id:"LV184",text:"The love I accept now would have astonished the person I was five years ago.",cat:"Love"},
  {id:"LV185",text:"I make room in my week for the friendships that make room in their lives for me.",cat:"Love"},
  {id:"LV186",text:"Grand gestures are lovely. Groceries carried in are lovelier.",cat:"Love"},
  {id:"LV187",text:"I love people as they are today, not as I archived them years ago.",cat:"Love"},
  {id:"LV188",text:"My heart has been renovated, not replaced. The original beams still hold.",cat:"Love"},
  {id:"LV189",text:"The people I love are free, and they keep choosing to stay. That is the only staying worth having.",cat:"Love"},
  {id:"LV190",text:"I loved, I lost, and I would sign up again without reading the terms.",cat:"Love"},
  {id:"LV191",text:"Anniversaries matter in my house — of weddings, of friendships, of the day the dog arrived.",cat:"Love"},
  {id:"LV192",text:"I do not make people guess whether I love them.",cat:"Love"},
  {id:"LV193",text:"I love people in their becoming, not only in their finished forms.",cat:"Love"},
  {id:"LV194",text:"I hold space for hard feelings without rushing anyone to the bright side.",cat:"Love"},
  {id:"LV195",text:"The strongest thing in my house is the affection.",cat:"Love"},
  {id:"LV196",text:"I write the card by hand. Some loves deserve ink.",cat:"Love"},
  {id:"LV197",text:"I keep secrets, remember dreams, and defend the people I love in every room.",cat:"Love"},
  {id:"LV198",text:"Love keeps enlarging me, and I keep letting it.",cat:"Love"},
  {id:"LV199",text:"Somewhere between the first hello and the last goodnight, I keep choosing love — daily, gladly, on purpose.",cat:"Love"},
  // CONFIDENCE — expansion (CO151–CO200)
  {id:"CO151",text:"I raise my hand first and figure out my sentence on the way up.",cat:"Confidence"},
  {id:"CO152",text:"My body is allowed in swimsuits, photographs, and front rows.",cat:"Confidence"},
  {id:"CO153",text:"I speak to a crowd the way I speak to a friend — because that is all a crowd is.",cat:"Confidence"},
  {id:"CO154",text:"I share my art with my name attached.",cat:"Confidence"},
  {id:"CO155",text:"Small talk is a door, and I have stopped being afraid of doors.",cat:"Confidence"},
  {id:"CO156",text:"I decide in minutes what I used to agonize over for weeks. Most decisions are reversible, and the rest teach fast.",cat:"Confidence"},
  {id:"CO157",text:"Criticism of my work is not a biopsy of my worth.",cat:"Confidence"},
  {id:"CO158",text:"I walk slower through rooms now. Hurry was a way of apologizing.",cat:"Confidence"},
  {id:"CO159",text:"Gray hair, laugh lines, a body with mileage — I have never respected myself more.",cat:"Confidence"},
  {id:"CO160",text:"I ask for the explanation twice if I need it. Understanding outranks appearing smart.",cat:"Confidence"},
  {id:"CO161",text:"I wear what I love and let the lookers look.",cat:"Confidence"},
  {id:"CO162",text:"My quiet is not emptiness. Some of us carry our thunder indoors.",cat:"Confidence"},
  {id:"CO163",text:"I tell the story of my failure at parties now. It lost its power and kept its plot.",cat:"Confidence"},
  {id:"CO164",text:"I trust my hands to learn what my mind has decided.",cat:"Confidence"},
  {id:"CO165",text:"I run the meeting like someone who prepared, because I am someone who prepares.",cat:"Confidence"},
  {id:"CO166",text:"I ask my body what it can do, not how it compares, and we both stand taller for it.",cat:"Confidence"},
  {id:"CO167",text:"I take the photo. I stay in the frame. My people will want proof of me someday.",cat:"Confidence"},
  {id:"CO168",text:"I say my price and then I say nothing.",cat:"Confidence"},
  {id:"CO169",text:"When it is my turn to be celebrated, I stand still and let it happen.",cat:"Confidence"},
  {id:"CO170",text:"I disagree in the meeting, not in the parking lot.",cat:"Confidence"},
  {id:"CO171",text:"My accent, my laugh, my handwriting — the unpolished parts are the signature.",cat:"Confidence"},
  {id:"CO172",text:"I read the room and then, when it matters, I ignore it.",cat:"Confidence"},
  {id:"CO173",text:"Humility and smallness are different postures. I keep only the first.",cat:"Confidence"},
  {id:"CO174",text:"I show up to reunions and interviews as the current me, not a defense of the old one.",cat:"Confidence"},
  {id:"CO175",text:"I gave up bracing for the whole world. Mostly it is not looking, and I am free.",cat:"Confidence"},
  {id:"CO176",text:"I let my work be judged without standing next to it explaining.",cat:"Confidence"},
  {id:"CO177",text:"Confidence looks like ordering first without scanning the table.",cat:"Confidence"},
  {id:"CO178",text:"Talent got me started. Nerve keeps me in the room.",cat:"Confidence"},
  {id:"CO179",text:"My laugh keeps its full volume in mixed company.",cat:"Confidence"},
  {id:"CO180",text:"I state my needs at the doctor, the dealership, the dinner table — plainly, and twice if needed.",cat:"Confidence"},
  {id:"CO181",text:"I trust myself around new people. My own personality has never once abandoned me.",cat:"Confidence"},
  {id:"CO182",text:"The room got quiet when I spoke, and I kept speaking.",cat:"Confidence"},
  {id:"CO183",text:"I apply when I meet seven of the ten requirements. The other three are homework.",cat:"Confidence"},
  {id:"CO184",text:"I stopped auditing my face on the way out the door.",cat:"Confidence"},
  {id:"CO185",text:"My authority is homegrown. No costume required.",cat:"Confidence"},
  {id:"CO186",text:"I sit at the front on purpose.",cat:"Confidence"},
  {id:"CO187",text:"I sing in the car with the windows down. Small freedoms train big ones.",cat:"Confidence"},
  {id:"CO188",text:"Embarrassment has a half-life of a weekend. My goals have a half-life of never.",cat:"Confidence"},
  {id:"CO189",text:"I stopped crowd-sourcing decisions my gut had already made.",cat:"Confidence"},
  {id:"CO190",text:"The younger people are watching how I carry myself. I carry accordingly.",cat:"Confidence"},
  {id:"CO191",text:"I know my weak spots so well they have stopped being ambushes.",cat:"Confidence"},
  {id:"CO192",text:"I am not the loudest or the fastest in the room. I am the one still standing at the end.",cat:"Confidence"},
  {id:"CO193",text:"Some people will not like me. The math still works out heavily in my favor.",cat:"Confidence"},
  {id:"CO194",text:"I enter the gym, the class, the studio as a member, not an intruder.",cat:"Confidence"},
  {id:"CO195",text:"My ideas get pitched in first person while they are still warm.",cat:"Confidence"},
  {id:"CO196",text:"I stopped waiting for quiet hands and a steady heart. I work with the ones I have.",cat:"Confidence"},
  {id:"CO197",text:"I keep my shape in rooms built to bend people.",cat:"Confidence"},
  {id:"CO198",text:"Even on off days, the skills stay on.",cat:"Confidence"},
  {id:"CO199",text:"I compete relaxed. Tension never made anyone faster.",cat:"Confidence"},
  {id:"CO200",text:"I like who I am in an elevator, an emergency, and an empty house — the three honest places.",cat:"Confidence"},
  // HEALTH — expansion (HT150–HT199)
  {id:"HT150",text:"The dentist, the screening, the eye exam — I keep the boring appointments that keep me.",cat:"Health"},
  {id:"HT151",text:"My posture is a message I send myself all day. I straighten it kindly.",cat:"Health"},
  {id:"HT152",text:"I carry the groceries, climb the stairs, lift the suitcase — strong enough for my own life is the goal.",cat:"Health"},
  {id:"HT153",text:"Sunlight before screens. My mornings start analog.",cat:"Health"},
  {id:"HT154",text:"I cook more weeks than I don't, and my body can tell.",cat:"Health"},
  {id:"HT155",text:"Green things on my plate, green places on my weekend — I keep my life photosynthesizing.",cat:"Health"},
  {id:"HT156",text:"I stretch while the coffee brews. Health fits in the gaps I stopped wasting.",cat:"Health"},
  {id:"HT157",text:"My immune system works around the clock, and I staff it well — sleep, sunlight, real food.",cat:"Health"},
  {id:"HT158",text:"A chronic condition is part of my story, not the narrator.",cat:"Health"},
  {id:"HT159",text:"I take my medication without shame. Managed is a form of healthy.",cat:"Health"},
  {id:"HT160",text:"I walk after dinner, and my body files the day properly.",cat:"Health"},
  {id:"HT161",text:"Laughter is medicine with no copay, and I dose daily.",cat:"Health"},
  {id:"HT162",text:"My prescriptions are humble — water, walks, windows open — and they keep working.",cat:"Health"},
  {id:"HT163",text:"I train my balance now so I can trust my footing at ninety.",cat:"Health"},
  {id:"HT164",text:"Grip strength, good knees, a heart that climbs hills — I invest in the quiet portfolio.",cat:"Health"},
  {id:"HT165",text:"I eat protein like someone planning to keep their muscle.",cat:"Health"},
  {id:"HT166",text:"Rest days are written in pen.",cat:"Health"},
  {id:"HT167",text:"I leave the party while it is still fun and wake up grateful.",cat:"Health"},
  {id:"HT168",text:"I protect my hearing, my eyesight, my knees — the equipment of a long life.",cat:"Health"},
  {id:"HT169",text:"I sit on the floor and get up without using my hands, and I intend to keep that trick.",cat:"Health"},
  {id:"HT170",text:"I move the worry through my legs when it will not leave through my thoughts.",cat:"Health"},
  {id:"HT171",text:"I nap without a defense attorney.",cat:"Health"},
  {id:"HT172",text:"I sigh on purpose. The body reads it as a memo that the crisis is over.",cat:"Health"},
  {id:"HT173",text:"I know my numbers, and knowing them keeps them mine to change.",cat:"Health"},
  {id:"HT174",text:"I retired the clean-plate rule. My body, not my plate, says when.",cat:"Health"},
  {id:"HT175",text:"Fresh air fixes more moods than I ever want to admit.",cat:"Health"},
  {id:"HT176",text:"I keep a bedtime like a border. Very little worth having crosses midnight.",cat:"Health"},
  {id:"HT177",text:"Stretching is a conversation with tomorrow's body.",cat:"Health"},
  {id:"HT178",text:"I let myself be a slow runner, a wobbly yogi, a beginner swimmer — moving badly beats sitting perfectly.",cat:"Health"},
  {id:"HT179",text:"Half my ailments are hunger, thirst, or a bad night wearing costumes. I check the basics first.",cat:"Health"},
  {id:"HT180",text:"My body is the address where my whole life happens. I keep the place kind.",cat:"Health"},
  {id:"HT181",text:"I lift heavy things and set them down gently. Life keeps asking for both skills.",cat:"Health"},
  {id:"HT182",text:"The couch earns its keep after the walk.",cat:"Health"},
  {id:"HT183",text:"I unfollow what makes me dread mirrors and follow what makes me use my legs.",cat:"Health"},
  {id:"HT184",text:"Vegetables at most meals, movement on most days, sleep on most nights — I built my health on the word most.",cat:"Health"},
  {id:"HT185",text:"I treat the small ache now so it never earns a promotion.",cat:"Health"},
  {id:"HT186",text:"I sit less than I used to and stand corrected.",cat:"Health"},
  {id:"HT187",text:"My lungs are for deep breaths and loud laughs, and I keep them clear for both.",cat:"Health"},
  {id:"HT188",text:"I measure my health in flights of stairs that no longer require negotiation.",cat:"Health"},
  {id:"HT189",text:"The strongest muscle I train is the one that says no thanks, not tonight.",cat:"Health"},
  {id:"HT190",text:"I eat breakfast like someone with plans.",cat:"Health"},
  {id:"HT191",text:"I warm up. Bodies forgive preparation and remember recklessness.",cat:"Health"},
  {id:"HT192",text:"Health is a team sport in my house — we walk, we cook, we sleep on time, together.",cat:"Health"},
  {id:"HT193",text:"I sweat somewhere weekly that is not from stress.",cat:"Health"},
  {id:"HT194",text:"I ask for the second opinion. My body deserves due diligence.",cat:"Health"},
  {id:"HT195",text:"Screens off, lights low, book open — I land the day like a good pilot.",cat:"Health"},
  {id:"HT196",text:"I count colors on my plate more often than calories.",cat:"Health"},
  {id:"HT197",text:"Being strong makes everything else in my life lighter to carry.",cat:"Health"},
  {id:"HT198",text:"I thank my feet. They have logged every mile of every good day I have ever had.",cat:"Health"},
  {id:"HT199",text:"Decades from now I will still be dancing at weddings. Today's choices are the RSVP.",cat:"Health"},
  // PEACE — expansion (PC150–PC199)
  {id:"PC150",text:"Forgiveness is a room I keep unlocking from the inside.",cat:"Peace"},
  {id:"PC151",text:"The to-do list will outlive everyone. I stopped racing it.",cat:"Peace"},
  {id:"PC152",text:"Red lights, waiting lines, slow elevators — I practice peace in the small delays life provides for free.",cat:"Peace"},
  {id:"PC153",text:"I keep my phone in grayscale and my evenings in color.",cat:"Peace"},
  {id:"PC154",text:"Difficult people no longer get to redecorate my inner rooms.",cat:"Peace"},
  {id:"PC155",text:"I checked: the world kept spinning during my nap.",cat:"Peace"},
  {id:"PC156",text:"Money gets a scheduled meeting with me, not open access to my nights.",cat:"Peace"},
  {id:"PC157",text:"I am allowed to leave the group chat.",cat:"Peace"},
  {id:"PC158",text:"I read the message twice, breathe once, and reply as the calmest person in the thread.",cat:"Peace"},
  {id:"PC159",text:"Autumn does not apologize for slowing down. Neither do I in my own seasons.",cat:"Peace"},
  {id:"PC160",text:"My ambition and my peace share custody of my day — mornings for the dream, evenings for the life.",cat:"Peace"},
  {id:"PC161",text:"The phone charges in the kitchen. I charge in my sleep.",cat:"Peace"},
  {id:"PC162",text:"I hum while I do the dishes. Peace often disguises itself as chores done slowly.",cat:"Peace"},
  {id:"PC163",text:"I let the argument stay ended, even when I remember a winning point at midnight.",cat:"Peace"},
  {id:"PC164",text:"I made peace with my parents' limits, and the peace is mostly mine to keep.",cat:"Peace"},
  {id:"PC165",text:"One evening a week belongs to no one — no plans, no screens, no explanations.",cat:"Peace"},
  {id:"PC166",text:"I keep plants. They grow at the only pace there is, and watching them recalibrates me.",cat:"Peace"},
  {id:"PC167",text:"Rain on the roof still works. I still stop to listen.",cat:"Peace"},
  {id:"PC168",text:"Contentment is the quietest feeling. Nobody claps. It is wonderful.",cat:"Peace"},
  {id:"PC169",text:"I release my opinions on matters that never asked for one.",cat:"Peace"},
  {id:"PC170",text:"I step outside when my thoughts get crowded. The sky redistributes them.",cat:"Peace"},
  {id:"PC171",text:"The kettle, the window, the first quiet ten minutes — I defend them like territory.",cat:"Peace"},
  {id:"PC172",text:"My help comes with hours of operation now.",cat:"Peace"},
  {id:"PC173",text:"Most of my best days would make terrible content. That is how I know they are working.",cat:"Peace"},
  {id:"PC174",text:"Grudges are heavy, and I am traveling light from here on.",cat:"Peace"},
  {id:"PC175",text:"I aired out the room where the resentment lived. It is a guest room now.",cat:"Peace"},
  {id:"PC176",text:"Not every silence needs filling. Some of it is furniture.",cat:"Peace"},
  {id:"PC177",text:"Ceiling fans, crickets, distant trains — I fall asleep to a world that runs fine without my supervision.",cat:"Peace"},
  {id:"PC178",text:"I lowered my voice and my blood pressure agreed.",cat:"Peace"},
  {id:"PC179",text:"I keep the weekend at the weekend's pace.",cat:"Peace"},
  {id:"PC180",text:"Nothing about this afternoon requires my anxiety's consultation.",cat:"Peace"},
  {id:"PC181",text:"I take yes for an answer now.",cat:"Peace"},
  {id:"PC182",text:"The candle, the bath, the early night — small ceremonies keep my week from blurring.",cat:"Peace"},
  {id:"PC183",text:"I end my weekends with a wind-down, not a countdown.",cat:"Peace"},
  {id:"PC184",text:"Half my stress was other people's expectations I had signed without reading. I am unsigning.",cat:"Peace"},
  {id:"PC185",text:"Tides come in without my help. So does tomorrow. I loosen my grip.",cat:"Peace"},
  {id:"PC186",text:"My mind offers me a hundred emergencies a day. I accept two, maybe.",cat:"Peace"},
  {id:"PC187",text:"I schedule less than fits, and the day breathes.",cat:"Peace"},
  {id:"PC188",text:"Peace is my rebellion against a world that profits from my hurry.",cat:"Peace"},
  {id:"PC189",text:"I watch the birds for no reason and cannot report a single downside.",cat:"Peace"},
  {id:"PC190",text:"When I am late, I am late calmly. Arriving frazzled helps no one, including the clock.",cat:"Peace"},
  {id:"PC191",text:"Refreshing the feed never once refreshed me. I log off to actually reload.",cat:"Peace"},
  {id:"PC192",text:"An unmade decision gets one page in my journal, not free run of my week.",cat:"Peace"},
  {id:"PC193",text:"I hold my opinions like water and my values like stone, and I know which is which.",cat:"Peace"},
  {id:"PC194",text:"The dishwasher hums, the house settles, and I let the day be over.",cat:"Peace"},
  {id:"PC195",text:"I befriended the in-between — the lobby, the layover, the loading screen.",cat:"Peace"},
  {id:"PC196",text:"Peace stacked up in me slowly, like snow that finally holds.",cat:"Peace"},
  {id:"PC197",text:"I read the whole poem, drink the tea while it is hot, and let that be an accomplishment.",cat:"Peace"},
  {id:"PC198",text:"Peace does not mean I stopped caring. It means I stopped drowning in the caring.",cat:"Peace"},
  {id:"PC199",text:"Somewhere in today a quiet hour is waiting for me, and I intend to keep the appointment.",cat:"Peace"},
  // CAREER — expansion (CR150–CR199)
  {id:"CR150",text:"I teach what I know, and my knowledge doubles on the way out.",cat:"Career"},
  {id:"CR151",text:"The gap on my résumé was a life being lived. I explain it once, without shame.",cat:"Career"},
  {id:"CR152",text:"I come back from breaks sharper. Rested people see the whole board.",cat:"Career"},
  {id:"CR153",text:"Work friendships turn long weeks into shared ones. I make time for the coffee.",cat:"Career"},
  {id:"CR154",text:"I present to the room, not to my slides.",cat:"Career"},
  {id:"CR155",text:"My desk may be at home, but my standards commute everywhere with me.",cat:"Career"},
  {id:"CR156",text:"My meetings end early and decide things. Calendars are where respect shows.",cat:"Career"},
  {id:"CR157",text:"Feast months fund famine months. Freelancing taught me seasons, and I built a barn.",cat:"Career"},
  {id:"CR158",text:"I charge for the drafts nobody sees.",cat:"Career"},
  {id:"CR159",text:"I talk salary with my peers. Silence was only ever a discount for someone else.",cat:"Career"},
  {id:"CR160",text:"I switched industries, and my skills translated better than my fear predicted.",cat:"Career"},
  {id:"CR161",text:"I do the right thing when the shortcut is cheaper. Reputation sells at full price.",cat:"Career"},
  {id:"CR162",text:"I credit ideas loudly and accurately, and the credit keeps coming back with interest.",cat:"Career"},
  {id:"CR163",text:"The craft deserves my patience. Mastery keeps different hours than ambition.",cat:"Career"},
  {id:"CR164",text:"My portfolio career looks scattered from the outside and woven from the inside.",cat:"Career"},
  {id:"CR165",text:"Every yes costs a different yes. I spend mine deliberately.",cat:"Career"},
  {id:"CR166",text:"A bad boss taught me management by counterexample. Expensive course, full marks.",cat:"Career"},
  {id:"CR167",text:"A sabbatical is maintenance, not mutiny.",cat:"Career"},
  {id:"CR168",text:"I document, I hand off cleanly, I train my replacement — my legacy is that things work after me.",cat:"Career"},
  {id:"CR169",text:"When a peer wins, I take notes and send congratulations, both sincerely.",cat:"Career"},
  {id:"CR170",text:"I automate the boring parts and keep the thinking for myself.",cat:"Career"},
  {id:"CR171",text:"My out-of-office reply is firm and my rest is real.",cat:"Career"},
  {id:"CR172",text:"Layoffs happen to markets, not to my worth. I grieve for a week and update the plan.",cat:"Career"},
  {id:"CR173",text:"I ask clients what winning looks like before I start running.",cat:"Career"},
  {id:"CR174",text:"The meeting where I said the uncomfortable number changed my year.",cat:"Career"},
  {id:"CR175",text:"Sharp tools, named files, tidy handoffs — my professionalism lives in the details.",cat:"Career"},
  {id:"CR176",text:"I estimate honestly, even when honesty loses the bid. The right clients hear competence.",cat:"Career"},
  {id:"CR177",text:"My work has seasons — launch, learn, lie fallow — and I stopped fighting the rotation.",cat:"Career"},
  {id:"CR178",text:"I interview them right back. Fit is a two-way door.",cat:"Career"},
  {id:"CR179",text:"I am building a career that lets me look my family in the eye at dinner — funded, honest, and home when it matters.",cat:"Career"},
  {id:"CR180",text:"My inbox is a queue, not a leash.",cat:"Career"},
  {id:"CR181",text:"I name the project's risks out loud on day one. Optimism with open eyes is my brand.",cat:"Career"},
  {id:"CR182",text:"Twenty years in, I still read the manual and still ask the newest hire what they see.",cat:"Career"},
  {id:"CR183",text:"I left the title behind and kept the capabilities. The exchange favored me.",cat:"Career"},
  {id:"CR184",text:"Awards gather dust. Skills gather momentum. I know which shelf I am stocking.",cat:"Career"},
  {id:"CR185",text:"Difficult clients are a masterclass in boundaries, and I keep graduating.",cat:"Career"},
  {id:"CR186",text:"My cover letter says what I want. Clarity gets shortlisted.",cat:"Career"},
  {id:"CR187",text:"I give my best hours to my hardest problems and let email have the leftovers.",cat:"Career"},
  {id:"CR188",text:"I get the agreement in writing, kindly. Paper protects friendships.",cat:"Career"},
  {id:"CR189",text:"I do the work once, well, and it recommends me for years.",cat:"Career"},
  {id:"CR190",text:"I keep a running list of problems I would love to be paid to solve, and I keep solving my way toward them.",cat:"Career"},
  {id:"CR191",text:"I plan a career with an off-ramp I will enjoy taking.",cat:"Career"},
  {id:"CR192",text:"Early to the meeting, early to the trend, early to the apology — earliness compounds.",cat:"Career"},
  {id:"CR193",text:"My handshake-deal days are behind me, and my handshake still means everything.",cat:"Career"},
  {id:"CR194",text:"I return from every conference with one idea implemented, not ten bookmarked.",cat:"Career"},
  {id:"CR195",text:"Tools change every season. My habit of learning them is the actual skill.",cat:"Career"},
  {id:"CR196",text:"I am the calm one during launches, and everyone remembers it later.",cat:"Career"},
  {id:"CR197",text:"I want work that uses me fully and returns me home intact.",cat:"Career"},
  {id:"CR198",text:"My career survived my worst year. We are both stronger and better acquainted now.",cat:"Career"},
  {id:"CR199",text:"The title I am proudest of is reliable. Everything else got built on top of it.",cat:"Career"},
  // HEALING — expansion (HL149–HL198)
  {id:"HL149",text:"I paint, I garden, I bake — my hands heal things my words cannot reach.",cat:"Healing"},
  {id:"HL150",text:"The forest does not ask what happened to me. That is half of why I go.",cat:"Healing"},
  {id:"HL151",text:"In a circle of people healing from the same thing, my story stopped feeling like an exhibit.",cat:"Healing"},
  {id:"HL152",text:"I sing along at full volume. Music reaches the places therapy is still mapping.",cat:"Healing"},
  {id:"HL153",text:"Illness introduced me to myself without my productivity, and we became friends.",cat:"Healing"},
  {id:"HL154",text:"I write the letter I will never send, and the sending stops mattering.",cat:"Healing"},
  {id:"HL155",text:"Estrangement was the saddest right decision I ever made, and peace arrived anyway.",cat:"Healing"},
  {id:"HL156",text:"I reclaimed the song, the restaurant, the month of June. Memories do not get the whole calendar.",cat:"Healing"},
  {id:"HL157",text:"Divorce ended a marriage, not my capacity for a beautiful life.",cat:"Healing"},
  {id:"HL158",text:"Somebody's healing began because I told mine out loud.",cat:"Healing"},
  {id:"HL159",text:"I have a short version of the story now, and I owe nobody the director's cut.",cat:"Healing"},
  {id:"HL160",text:"Grief and gratitude share a table in me most days, and I stopped asking either to leave.",cat:"Healing"},
  {id:"HL161",text:"I light a candle, say the name, and let missing them be a form of loving them.",cat:"Healing"},
  {id:"HL162",text:"I move grief through my body — long walks, cold water, loud crying, deep sleep.",cat:"Healing"},
  {id:"HL163",text:"Old money fear is leaving my body slowly, one calmly opened envelope at a time.",cat:"Healing"},
  {id:"HL164",text:"The medication, the therapist, the support group — I use every rope offered and climb.",cat:"Healing"},
  {id:"HL165",text:"I forgave myself for how long I stayed. Leaving takes what leaving takes.",cat:"Healing"},
  {id:"HL166",text:"My humor came through the fire with me, a little darker and completely mine.",cat:"Healing"},
  {id:"HL167",text:"Rest rebuilt me while I thought nothing was happening.",cat:"Healing"},
  {id:"HL168",text:"My shoulders came down an inch this year. Healing is measured in inches, and I am counting.",cat:"Healing"},
  {id:"HL169",text:"Some apologies arrived years late and still landed. I stayed soft enough to receive them.",cat:"Healing"},
  {id:"HL170",text:"I water what survived.",cat:"Healing"},
  {id:"HL171",text:"Tea, a window, ten quiet minutes — the small morning ritual stitches me back together daily.",cat:"Healing"},
  {id:"HL172",text:"I am healing out of order and it still counts.",cat:"Healing"},
  {id:"HL173",text:"My appetite came back. My colors came back. I notice each one coming home.",cat:"Healing"},
  {id:"HL174",text:"I softened on purpose in a world that advised against it, and I would choose soft again.",cat:"Healing"},
  {id:"HL175",text:"Healing after the diagnosis means living while treating, not waiting to live after.",cat:"Healing"},
  {id:"HL176",text:"I sat with my regret until it turned into instruction.",cat:"Healing"},
  {id:"HL177",text:"I sleep through the night more often than not now. Nobody sees this victory, and it is enormous.",cat:"Healing"},
  {id:"HL178",text:"I keep some healing private. Not everything needs a progress report.",cat:"Healing"},
  {id:"HL179",text:"My therapist said one sentence in March that is still reorganizing my October.",cat:"Healing"},
  {id:"HL180",text:"The first thing I release each morning is the script of how healing should look.",cat:"Healing"},
  {id:"HL181",text:"I got help before I hit bottom. Early is allowed.",cat:"Healing"},
  {id:"HL182",text:"I outgrew the argument I was waiting to win.",cat:"Healing"},
  {id:"HL183",text:"Anger did its job — it carried me out. I set it down at the door of the new life.",cat:"Healing"},
  {id:"HL184",text:"Six months ago this would have leveled me. I noticed today that it did not.",cat:"Healing"},
  {id:"HL185",text:"My parents gave what they had. I grieved the rest and stopped billing them for it.",cat:"Healing"},
  {id:"HL186",text:"I heal at the speed of honesty.",cat:"Healing"},
  {id:"HL187",text:"The support I accept today becomes the strength I lend someone next year.",cat:"Healing"},
  {id:"HL188",text:"I put flowers on the grave of who I had to be, and I walk back to who I am.",cat:"Healing"},
  {id:"HL189",text:"Bones knit in the dark without supervision. So does the rest of me.",cat:"Healing"},
  {id:"HL190",text:"I catch the spiral earlier each time. The catching is the healing.",cat:"Healing"},
  {id:"HL191",text:"The pause between feeling and reacting grows wider every season. I live in that pause now.",cat:"Healing"},
  {id:"HL192",text:"I gave my grief a garden instead of a cage.",cat:"Healing"},
  {id:"HL193",text:"People meeting me now would never guess, and I no longer need them to.",cat:"Healing"},
  {id:"HL194",text:"I kept the lesson and returned everything else.",cat:"Healing"},
  {id:"HL195",text:"Feeling safe took longer than getting safe. I gave it the time.",cat:"Healing"},
  {id:"HL196",text:"My healing stopped being a project and became a place I live.",cat:"Healing"},
  {id:"HL197",text:"I bless the version of me who could not do this yet.",cat:"Healing"},
  {id:"HL198",text:"I am the answer to a prayer I made years ago in the dark.",cat:"Healing"},
  // COURAGE — expansion (CG147–CG196)
  {id:"CG147",text:"Resting when the world says hustle takes its own nerve, and I have it.",cat:"Courage"},
  {id:"CG148",text:"Happiness takes courage in a world this uncertain. I am that brave.",cat:"Courage"},
  {id:"CG149",text:"I accept the help. Solo suffering was never a merit badge.",cat:"Courage"},
  {id:"CG150",text:"I speak up for the person who is not in the room.",cat:"Courage"},
  {id:"CG151",text:"I hang my art where guests can see it.",cat:"Courage"},
  {id:"CG152",text:"Loving again after loving wrongly is the bravest math there is. I keep doing it.",cat:"Courage"},
  {id:"CG153",text:"I admit out loud when the other side has a point.",cat:"Courage"},
  {id:"CG154",text:"I tell my family no with love and hold steady through what follows.",cat:"Courage"},
  {id:"CG155",text:"I asked the doctor every question on my list, including the scary one at the bottom.",cat:"Courage"},
  {id:"CG156",text:"An ordinary, honest, unfamous life takes courage to choose on purpose. I chose it.",cat:"Courage"},
  {id:"CG157",text:"I throw the party for the small victory. Waiting for the big one wastes perfectly good cake.",cat:"Courage"},
  {id:"CG158",text:"Forgiving took more nerve than the grudge ever did.",cat:"Courage"},
  {id:"CG159",text:"I try the new thing at an age when people expect me to be done trying new things.",cat:"Courage"},
  {id:"CG160",text:"I opened the statement, called the bank, made the plan. Financial courage is quiet and wears reading glasses.",cat:"Courage"},
  {id:"CG161",text:"I take the lead when leading is needed and follow well when it is not. Both take spine.",cat:"Courage"},
  {id:"CG162",text:"I say it first — the love, the apology, the big idea.",cat:"Courage"},
  {id:"CG163",text:"Second attempts are braver than first ones. The first time, I did not know what it would cost.",cat:"Courage"},
  {id:"CG164",text:"I go out with my real face and my real opinions, and both hold up fine.",cat:"Courage"},
  {id:"CG165",text:"Grieving in front of people took more courage than any stage I have stood on.",cat:"Courage"},
  {id:"CG166",text:"I read my work aloud to a room, and my heartbeat eventually joined the audience.",cat:"Courage"},
  {id:"CG167",text:"I ended it kindly, said the real reason, and left us both our dignity.",cat:"Courage"},
  {id:"CG168",text:"I returned to the place where I failed and ordered a coffee like a regular.",cat:"Courage"},
  {id:"CG169",text:"I told the truth in a small room where a lie would have been easier and cheaper.",cat:"Courage"},
  {id:"CG170",text:"I raise my standards in front of the people most likely to tease me about it.",cat:"Courage"},
  {id:"CG171",text:"I invite the person who intimidates me to lunch.",cat:"Courage"},
  {id:"CG172",text:"I wore the bright color. The world needs to see somebody comfortable.",cat:"Courage"},
  {id:"CG173",text:"Cold water, high dives, steep trails — I keep my body acquainted with brave.",cat:"Courage"},
  {id:"CG174",text:"These are my swinging years. I swing.",cat:"Courage"},
  {id:"CG175",text:"I walk into parties alone and leave with plans.",cat:"Courage"},
  {id:"CG176",text:"I defend my idea exactly as long as it deserves and drop it the moment truth wins. Both take courage.",cat:"Courage"},
  {id:"CG177",text:"I put my real goal in writing where I will see it daily. Ink is commitment.",cat:"Courage"},
  {id:"CG178",text:"I chose honesty over image in front of people who only knew the image.",cat:"Courage"},
  {id:"CG179",text:"I filed the complaint, flagged the problem, said the quiet part at the right volume.",cat:"Courage"},
  {id:"CG180",text:"I can hear hard feedback without collapsing or counterattacking. That took years, and it shows.",cat:"Courage"},
  {id:"CG181",text:"I negotiate with people I will see again tomorrow, respectfully and without folding.",cat:"Courage"},
  {id:"CG182",text:"The brave thing this year was staying. Last year it was leaving. I can tell the difference.",cat:"Courage"},
  {id:"CG183",text:"I stopped laughing along with jokes that cost me something.",cat:"Courage"},
  {id:"CG184",text:"I apply for the bigger life on a rolling basis.",cat:"Courage"},
  {id:"CG185",text:"I stand up at the wedding, the funeral, the retirement — when my people need a voice, mine works.",cat:"Courage"},
  {id:"CG186",text:"Courage now looks like honest budgets, early screenings, and refusing to retire the dream.",cat:"Courage"},
  {id:"CG187",text:"I return the extra change, name my mistakes, correct the record — small integrity is daily courage.",cat:"Courage"},
  {id:"CG188",text:"The mountain got smaller the moment my boots touched it.",cat:"Courage"},
  {id:"CG189",text:"Fear checked my references and found them excellent.",cat:"Courage"},
  {id:"CG190",text:"I disagree with the expert when my evidence is better.",cat:"Courage"},
  {id:"CG191",text:"I have been scared of the dark, the deep end, and the truth — and befriended all three.",cat:"Courage"},
  {id:"CG192",text:"I start the business, the band, the book club — every beginning needs one brave founding member.",cat:"Courage"},
  {id:"CG193",text:"My audience shrinks every year, and my courage grows into the space.",cat:"Courage"},
  {id:"CG194",text:"I go public with my actual life — the beliefs, the love, the plans.",cat:"Courage"},
  {id:"CG195",text:"The hardest door I ever open some mornings is my own front door. I keep opening it.",cat:"Courage"},
  {id:"CG196",text:"Every scary first has become a story I tell calmly. I am out collecting the next one.",cat:"Courage"},
  // NEW BEGINNINGS — expansion (NB146–NB195)
  {id:"NB146",text:"I make new friends as a grown adult. The roster never closed.",cat:"New Beginnings"},
  {id:"NB147",text:"The house is quieter now, and my own name is back on the calendar.",cat:"New Beginnings"},
  {id:"NB148",text:"Retirement is not an ending with a cake. It is a beginning with a pension.",cat:"New Beginnings"},
  {id:"NB149",text:"Every recovery in history started on an ordinary day one. Mine did too.",cat:"New Beginnings"},
  {id:"NB150",text:"I speak the new language badly and often, which is the only road to speaking it well.",cat:"New Beginnings"},
  {id:"NB151",text:"New country, new paperwork, new grocery store logic — I am rebuilding daily life from parts, and it is working.",cat:"New Beginnings"},
  {id:"NB152",text:"After the funeral, spring came anyway. I decided to come with it.",cat:"New Beginnings"},
  {id:"NB153",text:"Round-number birthdays are commencements. I graduate into each one.",cat:"New Beginnings"},
  {id:"NB154",text:"I begin mid-week, mid-month, mid-mess. Beginnings do not check the date.",cat:"New Beginnings"},
  {id:"NB155",text:"First morning in the new place, the light comes in differently — and so do I.",cat:"New Beginnings"},
  {id:"NB156",text:"I gave away half my things and none of my history.",cat:"New Beginnings"},
  {id:"NB157",text:"Becoming a parent restarted everything — my schedule, my heart, my definition of morning.",cat:"New Beginnings"},
  {id:"NB158",text:"The hobby I started badly last year is a skill this year. New keeps its promises.",cat:"New Beginnings"},
  {id:"NB159",text:"I updated the bio. The old description fit a person I finished being.",cat:"New Beginnings"},
  {id:"NB160",text:"I begin the book, the business, the braver haircut — visible newness trains the invisible kind.",cat:"New Beginnings"},
  {id:"NB161",text:"The comeback does not need an announcement. It needs bricks, and I am laying them.",cat:"New Beginnings"},
  {id:"NB162",text:"I planted a garden at the new place. Roots are a decision, and I have decided.",cat:"New Beginnings"},
  {id:"NB163",text:"First weeks are for learning names and finding the good coffee. Mastery can wait until month two.",cat:"New Beginnings"},
  {id:"NB164",text:"The ending had paperwork. The beginning has mornings. I prefer the new filing system.",cat:"New Beginnings"},
  {id:"NB165",text:"I keep the friendships that crossed into my new life and bless the ones that stayed behind.",cat:"New Beginnings"},
  {id:"NB166",text:"New habits still take root in a brain my age. Science and I are both pleased.",cat:"New Beginnings"},
  {id:"NB167",text:"I repainted the room where the old life happened. Paint is cheaper than exile.",cat:"New Beginnings"},
  {id:"NB168",text:"The alarm rings in a life I chose this time.",cat:"New Beginnings"},
  {id:"NB169",text:"I am four days into something I will still be doing in four years. I can feel the difference.",cat:"New Beginnings"},
  {id:"NB170",text:"The new city does not know my old nicknames. I introduce only the ones worth keeping.",cat:"New Beginnings"},
  {id:"NB171",text:"Grief and I built this new life together. It carries forward what mattered.",cat:"New Beginnings"},
  {id:"NB172",text:"The blank year ahead is not a test. It is a commission.",cat:"New Beginnings"},
  {id:"NB173",text:"I factory-reset my defaults: fewer apologies, more attempts.",cat:"New Beginnings"},
  {id:"NB174",text:"New glasses, new route to work, new bread recipe — I keep novelty stocked in small sizes.",cat:"New Beginnings"},
  {id:"NB175",text:"This beginning is the first one I have entered rested. It shows.",cat:"New Beginnings"},
  {id:"NB176",text:"I framed the old chapter instead of rereading it nightly.",cat:"New Beginnings"},
  {id:"NB177",text:"I begin again with my own blessing this time.",cat:"New Beginnings"},
  {id:"NB178",text:"After the setback, I gave myself a real winter — and then an honest spring.",cat:"New Beginnings"},
  {id:"NB179",text:"My restart has better instincts than my start ever did.",cat:"New Beginnings"},
  {id:"NB180",text:"This chapter is unscripted, and I have never been better cast.",cat:"New Beginnings"},
  {id:"NB181",text:"I replaced the ritual of dread with the ritual of coffee and a plan.",cat:"New Beginnings"},
  {id:"NB182",text:"I am the new person somewhere again, which means I am still moving.",cat:"New Beginnings"},
  {id:"NB183",text:"The seed catalog arrives in the coldest month, and I order anyway. That is what beginnings believe.",cat:"New Beginnings"},
  {id:"NB184",text:"I gave the new dream a drawer, then a desk, then a room. Beginnings expand when housed.",cat:"New Beginnings"},
  {id:"NB185",text:"First-pancake rules apply to first attempts: the second is always better, and the first is never wasted.",cat:"New Beginnings"},
  {id:"NB186",text:"I introduced myself by my new priorities, and nobody blinked.",cat:"New Beginnings"},
  {id:"NB187",text:"It turns out the deep end was four feet of fear over one foot of water.",cat:"New Beginnings"},
  {id:"NB188",text:"This time I begin with allies — the mentor, the group, the friend who checks in.",cat:"New Beginnings"},
  {id:"NB189",text:"The question that runs my mornings changed from how do I cope to what do I build.",cat:"New Beginnings"},
  {id:"NB190",text:"I honor the ending with a full stop, not an ellipsis.",cat:"New Beginnings"},
  {id:"NB191",text:"New keys, new numbers, new commute — the logistics of rebirth are pleasingly ordinary.",cat:"New Beginnings"},
  {id:"NB192",text:"I begin at the kitchen table with a notebook, and I mean it more than any podium speech.",cat:"New Beginnings"},
  {id:"NB193",text:"The only difference between me and the person already doing it is the year we started. Mine is now.",cat:"New Beginnings"},
  {id:"NB194",text:"I love a good prologue, and I am living one.",cat:"New Beginnings"},
  {id:"NB195",text:"New follows me around these days — new strength, new people, new mornings — because I finally left the door open for it.",cat:"New Beginnings"},
  // FAMILY — expansion (FM141–FM190)
  {id:"FM141",text:"My grown children come back by choice. That was the whole project.",cat:"Family"},
  {id:"FM142",text:"We keep the family close across time zones — calls, visits, and the good kind of showing up.",cat:"Family"},
  {id:"FM143",text:"Caring for my aging parent is slow, holy, repetitive work, and I bring my best patience to it.",cat:"Family"},
  {id:"FM144",text:"Blended is still built. Step by step, this family chose each other.",cat:"Family"},
  {id:"FM145",text:"The dog is family, and the evening walk is a ceremony.",cat:"Family"},
  {id:"FM146",text:"Our family has no children in it and every bit of the love. We count.",cat:"Family"},
  {id:"FM147",text:"My friendships hold family weight — holidays, hospital corridors, hard news at midnight.",cat:"Family"},
  {id:"FM148",text:"The cousins' table raised me as much as the adults' table did. I keep both traditions running.",cat:"Family"},
  {id:"FM149",text:"Grandma's recipe stays in the family because I make it badly, then better, then mine.",cat:"Family"},
  {id:"FM150",text:"I teach values at low volume — mostly by being watched when I think no one is watching.",cat:"Family"},
  {id:"FM151",text:"Illness moved in for a season, and this family closed ranks with soup and schedules.",cat:"Family"},
  {id:"FM152",text:"I forgave my sibling for the decade we lost, and we are spending the next one better.",cat:"Family"},
  {id:"FM153",text:"My in-laws and I built our own relationship, separate from anyone's old stories.",cat:"Family"},
  {id:"FM154",text:"We vote on the vacation. Small citizens, real ballots.",cat:"Family"},
  {id:"FM155",text:"I ask my grandmother to tell it again, and this time I write it down.",cat:"Family"},
  {id:"FM156",text:"We set a candle for the ones missing from the table. This family includes its history.",cat:"Family"},
  {id:"FM157",text:"Being the fun relative is a real position, and I hold it with honor.",cat:"Family"},
  {id:"FM158",text:"We fight fair in this family — no name-calling, no archives, no audience.",cat:"Family"},
  {id:"FM159",text:"I let my teenager's music play in the car and learn the words. Their world has a guest list, and I stay on it.",cat:"Family"},
  {id:"FM160",text:"Sunday calls with my mother are short, regular, and structural.",cat:"Family"},
  {id:"FM161",text:"I bring the folding chairs and the extra dessert. Belonging is something I help carry.",cat:"Family"},
  {id:"FM162",text:"Our family apologizes in full sentences.",cat:"Family"},
  {id:"FM163",text:"I show my children what a healthy argument sounds like, including the ending.",cat:"Family"},
  {id:"FM164",text:"I host the leftovers lunch the day after the holiday. The second gathering is where the real talking happens.",cat:"Family"},
  {id:"FM165",text:"I know my children's friends by name and feed them without notice.",cat:"Family"},
  {id:"FM166",text:"We garden, we board-game, we burn the occasional dinner together. The doing is the bonding.",cat:"Family"},
  {id:"FM167",text:"I tell my siblings I am proud of them, plainly, with no occasion attached.",cat:"Family"},
  {id:"FM168",text:"We arrive early to set up and stay late to wash dishes. That is the family signature.",cat:"Family"},
  {id:"FM169",text:"I protect the sibling bonds among my children — refereeing less, connecting more.",cat:"Family"},
  {id:"FM170",text:"I kept my parents' best recipes — the literal ones and the ones about love — and retired the rest.",cat:"Family"},
  {id:"FM171",text:"The one-more-chapter negotiation at bedtime is a negotiation I love to lose.",cat:"Family"},
  {id:"FM172",text:"We celebrate half-birthdays, first snows, and lost teeth. Any excuse for cake and each other.",cat:"Family"},
  {id:"FM173",text:"I keep a drawer of birthday cards bought in advance. Thoughtfulness can be a system.",cat:"Family"},
  {id:"FM174",text:"I ask the second question at dinner — the one that gets the real answer.",cat:"Family"},
  {id:"FM175",text:"The career I imagined for my child was my dream. I packed it away and showed up to theirs.",cat:"Family"},
  {id:"FM176",text:"We are rich in nicknames.",cat:"Family"},
  {id:"FM177",text:"I take the middle-of-the-night call from anyone in this family — always, no questions until morning.",cat:"Family"},
  {id:"FM178",text:"Holiday traditions bend for new in-laws, new babies, new diets. The point was always the people.",cat:"Family"},
  {id:"FM179",text:"Some of my family raised me sideways — the coach, the neighbor, the friend's mom. I carry them all.",cat:"Family"},
  {id:"FM180",text:"My marriage is the longest conversation of my life, and I keep it interesting.",cat:"Family"},
  {id:"FM181",text:"I stay well so my family has a well person to lean on. My health is a family asset.",cat:"Family"},
  {id:"FM182",text:"Around this table, the teasing stays gentle and everyone laughs hardest at themselves.",cat:"Family"},
  {id:"FM183",text:"Every child in this house knows what my undivided attention feels like.",cat:"Family"},
  {id:"FM184",text:"I learned my family's medical history and wrote it down. Practical love, filed properly.",cat:"Family"},
  {id:"FM185",text:"When one of us fails publicly, this family gets louder in their corner.",cat:"Family"},
  {id:"FM186",text:"We keep grandpa's jokes in circulation. Some inheritances are told, not willed.",cat:"Family"},
  {id:"FM187",text:"The teenagers still hug me in front of their friends. I must be doing something right.",cat:"Family"},
  {id:"FM188",text:"Some Saturdays we accomplish nothing but each other.",cat:"Family"},
  {id:"FM189",text:"I answer the question of who all this is for by walking into my own living room.",cat:"Family"},
  {id:"FM190",text:"Decades from now they will describe this home with soft eyes. I am writing that description today.",cat:"Family"},
  // GROWTH — expansion (GR156–GR205)
  {id:"GR156",text:"I learn from people half my age without flinching and mentor without preaching.",cat:"Growth"},
  {id:"GR157",text:"I read outside my lane, and my lane keeps widening.",cat:"Growth"},
  {id:"GR158",text:"Travel rearranged my certainties, and I let them settle into better positions.",cat:"Growth"},
  {id:"GR159",text:"I ask people I admire how they did it — and then, the growth part, I do the boring steps they describe.",cat:"Growth"},
  {id:"GR160",text:"My emotional vocabulary doubled, and half my conflicts settled out of court.",cat:"Growth"},
  {id:"GR161",text:"I apologize cleanly now — named harm, no fine print, changed behavior.",cat:"Growth"},
  {id:"GR162",text:"I listen all the way to the end of other people's sentences now. Growth, it turns out, is quiet.",cat:"Growth"},
  {id:"GR163",text:"Teaching the basics returned me to them. The beginner's questions were better than mine.",cat:"Growth"},
  {id:"GR164",text:"I learned to be wrong quickly and quietly, and my learning speed tripled.",cat:"Growth"},
  {id:"GR165",text:"My patience grew a full size this year. People noticed before I did.",cat:"Growth"},
  {id:"GR166",text:"I practice scales, drills, drafts — the plain grammar of every skill I now own.",cat:"Growth"},
  {id:"GR167",text:"Growth spurt, midlife edition: better boundaries, softer judgments, earlier bedtimes.",cat:"Growth"},
  {id:"GR168",text:"I let a book argue with me for three hundred pages and win.",cat:"Growth"},
  {id:"GR169",text:"I stopped outsourcing my report card to comment sections.",cat:"Growth"},
  {id:"GR170",text:"I journal the pattern until the pattern is embarrassed into changing.",cat:"Growth"},
  {id:"GR171",text:"My default response to hard things upgraded from panic to process.",cat:"Growth"},
  {id:"GR172",text:"I graduated from proving myself to improving myself.",cat:"Growth"},
  {id:"GR173",text:"My spiritual life grew roots when I stopped shopping for lightning.",cat:"Growth"},
  {id:"GR174",text:"I keep a failure résumé. It reads like the origin story it turned out to be.",cat:"Growth"},
  {id:"GR175",text:"I read the fine print of my own life now — contracts, habits, motives.",cat:"Growth"},
  {id:"GR176",text:"I outgrew the need to win small arguments, and my relationships got large.",cat:"Growth"},
  {id:"GR177",text:"I train my attention like an athlete trains legs — daily, progressively, without drama.",cat:"Growth"},
  {id:"GR178",text:"I gave my curiosity a budget, and it returned an education.",cat:"Growth"},
  {id:"GR179",text:"I let my friends grow past their old roles too. The permission travels both ways.",cat:"Growth"},
  {id:"GR180",text:"Comparison lost my subscription. The craft kept it.",cat:"Growth"},
  {id:"GR181",text:"I got better at receiving criticism by writing a few honest reviews of myself first.",cat:"Growth"},
  {id:"GR182",text:"Mastery stopped being a place and became a pace.",cat:"Growth"},
  {id:"GR183",text:"I turned my envy into a to-do list.",cat:"Growth"},
  {id:"GR184",text:"The wilderness parts of my life grew the deepest roots. I stopped resenting the terrain.",cat:"Growth"},
  {id:"GR185",text:"Growth looks like fewer opinions, held better.",cat:"Growth"},
  {id:"GR186",text:"I sunset old goals without shame. Some dreams were scaffolding for better ones.",cat:"Growth"},
  {id:"GR187",text:"Hard seasons interview me, and I keep showing up with better answers.",cat:"Growth"},
  {id:"GR188",text:"My range grew — at ease in silence, in crowds, in beginnings, in endings.",cat:"Growth"},
  {id:"GR189",text:"My mistakes became mulch. The garden is thriving.",cat:"Growth"},
  {id:"GR190",text:"The apology I owed myself took the longest and grew me the most.",cat:"Growth"},
  {id:"GR191",text:"Growth has a standing appointment in my week, and I stopped rescheduling it.",cat:"Growth"},
  {id:"GR192",text:"I now do on autopilot what once took my whole nervous system.",cat:"Growth"},
  {id:"GR193",text:"I forgive faster since learning what carrying costs.",cat:"Growth"},
  {id:"GR194",text:"The gap between my taste and my skill is my homework, and I do it daily.",cat:"Growth"},
  {id:"GR195",text:"I updated beliefs I had held since I was seventeen. They were due.",cat:"Growth"},
  {id:"GR196",text:"Growth gave me softer eyes for other people's slow seasons.",cat:"Growth"},
  {id:"GR197",text:"I stopped chasing flawless and started stockpiling better.",cat:"Growth"},
  {id:"GR198",text:"My inner monologue got a new writer this year. The reviews are strong.",cat:"Growth"},
  {id:"GR199",text:"Version after version, I remain recognizably me — only roomier.",cat:"Growth"},
  {id:"GR200",text:"The person who annoys me most is usually carrying my next lesson. I sign for the delivery now.",cat:"Growth"},
  {id:"GR201",text:"I keep learning to say it sooner — the boundary, the request, the dream.",cat:"Growth"},
  {id:"GR202",text:"I water my roots more than I polish my leaves.",cat:"Growth"},
  {id:"GR203",text:"One fear smaller, one skill larger, one friendship deeper — my years have a shape now.",cat:"Growth"},
  {id:"GR204",text:"I let the mountain change me on the way up. Summits are optional; the changing is not.",cat:"Growth"},
  {id:"GR205",text:"Looking back, every hard chapter promoted me. Looking forward, I trust the publisher.",cat:"Growth"},
];
